-- Poems batch 380
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1ecc9e90-2eeb-4ff1-b112-f9c121c9a870','又絕句二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','自折梅花插鬢端，韭黄蘭茁簇春盤。',32,'全唐诗/poet.song.91000.json','["自折梅花插鬢端，韭黄蘭茁簇春盤。", "潑醅酒軟渾無力，作惡東風特地寒。"]'),
('7a8b4b66-9a34-4f51-9439-b01b5848813b','又絕句二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','喜勝春幡嫋鳳釵，新春不換舊情懷。',32,'全唐诗/poet.song.91000.json','["喜勝春幡嫋鳳釵，新春不換舊情懷。", "草根隱綠冰痕滿，柳眼藏嬌雪影埋。"]'),
('fe8e30de-b079-4e2f-8440-835d49cf241d','春霽','朱淑真','宋','宋诗','song-poetry','','[]','淡薄輕寒雨後天，柳絲無力带朝煙。',64,'全唐诗/poet.song.91000.json','["淡薄輕寒雨後天，柳絲無力带朝煙。", "弄晴鶯舌於中巧，著雨花枝分外妍。", "消破舊愁馮酒盞，去除新恨賴詩篇。", "年年來到梨花月，瘦不勝衣怯杜鵑。"]'),
('ff07faec-94b4-4163-b2e4-668ee7155796','新春','朱淑真','宋','宋诗','song-poetry','','[]','樓臺影裏蕩春風，協氣融怡物物同。',64,'全唐诗/poet.song.91000.json','["樓臺影裏蕩春風，協氣融怡物物同。", "草色乍翻新樣綠，花容不減舊時紅。", "鶯唇小巧輕煙裏，蝶翅輕便細雨中。", "聊把新詩記風景，休嗟萬事轉頭空。"]'),
('aaff90c0-af05-45f0-8d90-aee9804e20d9','晴和','朱淑真','宋','宋诗','song-poetry','','[]','海棠深院雨初收，苔徑無風蝶自由。',64,'全唐诗/poet.song.91000.json','["海棠深院雨初收，苔徑無風蝶自由。", "百結丁香誇美麗，三眠楊柳弄輕柔。", "小桃酒膩紅尤淺，芳草寒餘綠漸稠。", "寂寂珠廉歸燕未，子規啼處一春愁。"]'),
('c36c6457-c262-42be-b3d0-24670fe1635a','春陰古律二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','薄雲籠日弄輕陰，試與詩工略話春。',64,'全唐诗/poet.song.91000.json','["薄雲籠日弄輕陰，試與詩工略話春。", "春蠢綠楊初學線，茸茸碧草漸成茵。", "園林深寂撩私恨，山水昏明惱暗顰。", "芳意被他寒約住，天應知有惜花人。"]'),
('3cadfff0-6165-4299-9273-adf4cc13f583','春陰古律二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','陡覺湘裙剩带圍，情懷常是被春欺。',64,'全唐诗/poet.song.91000.json','["陡覺湘裙剩带圍，情懷常是被春欺。", "半簷落日飛花後，一陣輕寒微雨時。", "幽谷想應鶯出晚，舊巢應怪燕歸遲。", "間關幾許傷懷處，悒悒柔情不自持。"]'),
('07f519c1-3750-4f1a-bced-d3bda0ec2e4c','又絕句少年心','朱淑真','宋','宋诗','song-poetry','','[]','楊花擾亂少年心，怕雨愁風用意深。',32,'全唐诗/poet.song.91000.json','["楊花擾亂少年心，怕雨愁風用意深。", "付與酒杯渾不管，從教天氣作春陰。"]'),
('c7ae3912-ba8c-496b-9b93-29aeda3f9434','問春古律','朱淑真','宋','宋诗','song-poetry','','[]','春到休論舊日情，風光還是一番新。',64,'全唐诗/poet.song.91000.json','["春到休論舊日情，風光還是一番新。", "鶯花有恨偏供我，桃李無言祇惱人。", "粉淚洗幹清瘦面，带圍寬盡小腰身。", "東君負我春三月，我負東君三月春。"]'),
('4baff705-f690-487e-a9cf-23cc563bb84c','訴春','朱淑真','宋','宋诗','song-poetry','','[]','十二欄杆鎖畫樓，春風吹損上簾鈎。',64,'全唐诗/poet.song.91000.json','["十二欄杆鎖畫樓，春風吹損上簾鈎。", "花心柳眼從教放，蝶意蜂情一任休。", "殘滯酒懷消舊恨，禁持詩句遣新愁。", "東君若也憐孤獨，莫使韶光便似秋。"]'),
('cad7ed18-9bca-4e2f-abef-1b870bbc5bba','傷春','朱淑真','宋','宋诗','song-poetry','','[]','閣淚拋詩卷，無聊酒獨親。',48,'全唐诗/poet.song.91000.json','["閣淚拋詩卷，無聊酒獨親。", "客情方惜別，心事已傷春。", "柳暗輕籠日，花飛半掩塵。", "鶯聲驚蝶夢，喚起舊愁新。"]'),
('c2043257-7669-446c-b4c1-7ac95c69e64d','春日感懷','朱淑真','宋','宋诗','song-poetry','','[]','寂寂多愁客，傷春二月中。',48,'全唐诗/poet.song.91000.json','["寂寂多愁客，傷春二月中。", "惜花嫌夜雨，多病怯東風。", "不奈鶯聲碎，那堪蝶夢空。", "海堂方睡足，簾影日融融。"]'),
('4f4f8ae7-3681-4b51-a7f2-38eb9b1bd0eb','中春書事','朱淑真','宋','宋诗','song-poetry','','[]','乍暖還寒二月天，釀紅醖綠鬬新鮮。',64,'全唐诗/poet.song.91000.json','["乍暖還寒二月天，釀紅醖綠鬬新鮮。", "日烘春色成和氣，風弄花香作瑞煙。", "鶯舌似簧初學語，柳條如線未飛綿。", "金杯滿酌黄封酒，欲勸東君莫放權。"]'),
('a468e3e0-a167-49f6-b305-4398a989b08a','又絕句','朱淑真','宋','宋诗','song-poetry','','[]','乳燕調雛出畫簷，遊蜂喧翅入珠簾。',32,'全唐诗/poet.song.91000.json','["乳燕調雛出畫簷，遊蜂喧翅入珠簾。", "日長無事人慵困，金鴨香銷懶更添。"]'),
('3bce17de-b7e6-4caf-be0b-de436a1bb538','春半','朱淑真','宋','宋诗','song-poetry','','[]','拭目憑闌久，柔風拂面吹。',48,'全唐诗/poet.song.91000.json','["拭目憑闌久，柔風拂面吹。", "鶯花爭嫵媚，詩酒鬬清奇。", "已近清明節，初過上巳時。", "莫縈尋俗事，隨意樂春熙。"]'),
('68765852-1ad3-4eb5-afde-1e826e236e18','春日即事','朱淑真','宋','宋诗','song-poetry','','[]','輕寒噤㾕花期晚，皺綠差鱗接遠波。',64,'全唐诗/poet.song.91000.json','["輕寒噤㾕花期晚，皺綠差鱗接遠波。", "躍藻白魚翻玉尺，穿林黄鳥度金梭。", "閑將詩草臨軒讀，靜聽漁船隔岸歌。", "盡日倚窗情脈脈，眼前無事奈春何。"]'),
('192062b7-03ee-4842-88f3-9ca47a160f2c','春詞二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','屋嗔柳葉噪春鴉，簾幕風輕燕翅斜。',64,'全唐诗/poet.song.91000.json','["屋嗔柳葉噪春鴉，簾幕風輕燕翅斜。", "芳草池塘初夢斷，海棠庭院正愁加。", "幾聲嬌巧黄鸝舌，數朵柔纖小杏花。", "獨倚莊窗梳洗倦，只慚辜負好年華。"]'),
('7b6592a8-9393-4e4f-ba1c-f6bce23a51a9','春詞二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','屈指清明數日期，紛紛紅紫競芳菲。',64,'全唐诗/poet.song.91000.json','["屈指清明數日期，紛紛紅紫競芳菲。", "池塘水暖鶼鶼並，巷陌風輕燕燕飛。", "柳带萬條籠淑景，遊絲千尺網晴暉。", "人間何處無春色，祇是西樓人未歸。"]'),
('f9fea9a8-0cb0-4a73-9c14-48cfc5450b3c','春色有懷','朱淑真','宋','宋诗','song-poetry','','[]','客裏逢春想恨濃，故園花木夢魂同。',32,'全唐诗/poet.song.91000.json','["客裏逢春想恨濃，故園花木夢魂同。", "連堤綠陰晴煙裏，映水紅搖薄霧中。"]'),
('b8ab5987-eae5-4498-b2ef-277df68f04e5','約遊春不去二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','鄰姬約我踏青遊，強拂愁眉下小樓。',32,'全唐诗/poet.song.91000.json','["鄰姬約我踏青遊，強拂愁眉下小樓。", "去戶欲行還自省，也知憔悴見人羞。"]'),
('1b27e6af-4a51-4df6-9045-62fede38e629','約遊春不去二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','少年意思懶能酬，愛好心情一向休。',32,'全唐诗/poet.song.91000.json','["少年意思懶能酬，愛好心情一向休。", "若到舊家遊冶處，只應滿眼是春愁。"]'),
('8aa72f7d-abeb-4ed6-a9c1-97208b414c2e','喜晴','朱淑真','宋','宋诗','song-poetry','','[]','鵓鳩聲歇已閑晴，柳眼窺春淺放青。',32,'全唐诗/poet.song.91000.json','["鵓鳩聲歇已閑晴，柳眼窺春淺放青。", "樓上捲簾凝目處，遠山如畫盡幃幈。"]'),
('0eaa2fd6-98b3-496a-9059-12f3a6623cb0','春日雜書十首  其一','朱淑真','宋','宋诗','song-poetry','','[]','春來春去幾經過，不似今年恨最多。',32,'全唐诗/poet.song.91000.json','["春來春去幾經過，不似今年恨最多。", "寂寂海棠枝上月，照人清夜欲如何。"]'),
('896be53e-f07f-4a74-b549-07acf662b1a3','春日雜書十首  其二','朱淑真','宋','宋诗','song-poetry','','[]','柳絲拂拂弄東風，日色春容一樣同。',32,'全唐诗/poet.song.91000.json','["柳絲拂拂弄東風，日色春容一樣同。", "嫩草破煙開秀綠，小桃和露拆香紅。"]'),
('2c07ef62-c141-45c2-afd4-5efe5037a469','春日雜書十首  其三','朱淑真','宋','宋诗','song-poetry','','[]','鬆鬆麗日約餘寒，春向梅邊柳上添。',32,'全唐诗/poet.song.91000.json','["鬆鬆麗日約餘寒，春向梅邊柳上添。", "蜂蝶自知新得意，展鬚忙翅入層簾。"]'),
('fdf983dc-9c4c-4917-a872-d45832295c85','春日雜書十首  其四','朱淑真','宋','宋诗','song-poetry','','[]','柳垂新綠膩煙光，紫燕惺鬆語畫梁。',32,'全唐诗/poet.song.91000.json','["柳垂新綠膩煙光，紫燕惺鬆語畫梁。", "午睡忽驚雞唱罷，日移花影上窗香。"]'),
('d5f307a0-1211-43b6-96a3-82944b95f604','春日雜書十首  其五','朱淑真','宋','宋诗','song-poetry','','[]','捲簾月掛一鈎斜，愁到黄昏轉更加。',32,'全唐诗/poet.song.91000.json','["捲簾月掛一鈎斜，愁到黄昏轉更加。", "獨坐小窗無伴侶，凝情羞對海棠花。"]'),
('c3fbaf97-8331-4b85-b9ff-ecb88763be9b','春日雜書十首  其六','朱淑真','宋','宋诗','song-poetry','','[]','鬬草尋花正及時，不爲容易見芳菲。',32,'全唐诗/poet.song.91000.json','["鬬草尋花正及時，不爲容易見芳菲。", "誰能更覷閑針線，且殢春光伴酒巵。"]'),
('f94ae76d-8947-46a4-be72-93ed683bfe3d','春日雜書十首  其七','朱淑真','宋','宋诗','song-poetry','','[]','月篩窗幌好風生，病眼傷春淚欲傾。',32,'全唐诗/poet.song.91000.json','["月篩窗幌好風生，病眼傷春淚欲傾。", "寫字彈琴無意緒，踏青挑菜沒心情。"]'),
('e2f8871f-4c41-47f3-9537-2626e9446651','春日雜書十首  其八','朱淑真','宋','宋诗','song-poetry','','[]','一年好處清明近，已覺春光大半休。',32,'全唐诗/poet.song.91000.json','["一年好處清明近，已覺春光大半休。", "點檢芳菲多少在，翠深紅淺已關愁。"]'),
('96cd4714-2cd9-4d2f-bcaf-23b10a9262e0','春日雜書十首  其九','朱淑真','宋','宋诗','song-poetry','','[]','濛濛細雨濕香塵，似欲藏鴉柳色新。',32,'全唐诗/poet.song.91000.json','["濛濛細雨濕香塵，似欲藏鴉柳色新。", "鬬草工夫渾忘卻，祇憑詩酒破除春。"]'),
('bb3cf817-0eab-456d-b00a-2f55490edd08','春日雜書十首  其一○','朱淑真','宋','宋诗','song-poetry','','[]','自入春來日日愁，惜花翻作爲花羞。',32,'全唐诗/poet.song.91000.json','["自入春來日日愁，惜花翻作爲花羞。", "呢喃飛過雙雙燕，嗔我簾垂不上鉤。"]'),
('fd8b8889-c7f2-44ff-b99b-dab47b55826a','晚春會東園','朱淑真','宋','宋诗','song-poetry','','[]','紅疊苔痕綠滿枝，舉杯和淚送春歸。',64,'全唐诗/poet.song.91000.json','["紅疊苔痕綠滿枝，舉杯和淚送春歸。", "鶬鶊有意留殘景，杜字無情戀晚暉。", "蝶趁落花盤地舞，燕隨狂絮入簾飛。", "醉中曾記題詩處，臨水人家半敞扉。"]'),
('72b4ad21-d792-4c5f-bbf6-08aee2d42479','晚春有感','朱淑真','宋','宋诗','song-poetry','','[]','卻扇羞花春已空，掃紅吹白任顛風。',32,'全唐诗/poet.song.91000.json','["卻扇羞花春已空，掃紅吹白任顛風。", "斷腸芳草連天碧，春不歸來夢不通。"]'),
('b1d0581e-b753-4158-a764-7fdc6724cc8e','暮春三首  其一','朱淑真','宋','宋诗','song-poetry','','[]','才過清明春意殘，落花飛恕便相關。',64,'全唐诗/poet.song.91000.json','["才過清明春意殘，落花飛恕便相關。", "銜泥燕子時來去，釀蜜蜂兒自往還。", "風靜窗前榆葉鬧，雨餘牆角蘚苔斑。", "綠槐高柳濃陰合，深院人眠白晝閑。"]'),
('990c7682-b05a-4a5a-b950-495824b072a5','暮春三首  其二','朱淑真','宋','宋诗','song-poetry','','[]','碧沼荷錢小葉圓，眼前芍藥恣連顛。',64,'全唐诗/poet.song.91000.json','["碧沼荷錢小葉圓，眼前芍藥恣連顛。", "清明已過三春候，穀雨初晴四月天。", "乍著薄羅偏覺瘦，懶勻鉛粉祇宜眠。", "情知廢事因詩句，氣習難除筆硯緣。"]'),
('e4b51ff1-2179-487a-82b8-9c4829de3dce','暮春三首  其三','朱淑真','宋','宋诗','song-poetry','','[]','舉杯無語送春歸，分付東風欲去時。',64,'全唐诗/poet.song.91000.json','["舉杯無語送春歸，分付東風欲去時。", "燕子樓臺人寂寂，楊花庭院日熙熙。", "枝頭添翠鶯先覺，葉底銷紅蝶未知。", "詩卷酒杯新廢卻，閑愁消遣殢他誰。"]'),
('d824b2ac-1195-4794-a85f-c43d1f1a0c5d','恨春五首  其一','朱淑真','宋','宋诗','song-poetry','','[]','櫻桃初薦杏梅酸，槐嫩風高麥秀寒。',32,'全唐诗/poet.song.91000.json','["櫻桃初薦杏梅酸，槐嫩風高麥秀寒。", "惆悵東君太情薄，挽留時暫也應難。"]'),
('5a8b2575-e9f5-4b17-8607-dc7b948ca95e','恨春五首  其二','朱淑真','宋','宋诗','song-poetry','','[]','一瞬芬菲爾許時，苦無佳句紀相思。',64,'全唐诗/poet.song.91000.json','["一瞬芬菲爾許時，苦無佳句紀相思。", "春光正好須風雨，恩愛方深奈別離。", "淚眼謝他花繳抱，愁懷惟賴酒扶持。", "鶯鶯燕燕休相笑，試與單棲各自知。"]'),
('8babb34c-360d-455f-a82b-572e2cd7319f','恨春五首  其三','朱淑真','宋','宋诗','song-poetry','','[]','病酒厭厭日正高，一聲啼鳥在花梢。',64,'全唐诗/poet.song.91000.json','["病酒厭厭日正高，一聲啼鳥在花梢。", "驚回好夢方萌蕊，喚起新愁卻破苞。", "暗把後期隨處記，閑將清恨倩詩嘲。", "從今始信恩成怨，且與鶯花作淡交。"]'),
('7bfad1d9-7a11-4ddd-8e60-fa493007293e','恨春五首  其四','朱淑真','宋','宋诗','song-poetry','','[]','遲遲花日上簾鉤，盡日無人獨倚樓。',64,'全唐诗/poet.song.91000.json','["遲遲花日上簾鉤，盡日無人獨倚樓。", "蝶使蜂媒傳客恨，鶯梭柳線織春愁。", "碧雲信斷惟勞夢，紅葉成詩想到秋。", "幾許別離多少淚，不堪重省不堪流。"]'),
('07bb6000-b65a-4298-b11e-a092cb3caf76','恨春五首  其五','朱淑真','宋','宋诗','song-poetry','','[]','一篆煙消繫臂香，閑看書冊就牙牀。',64,'全唐诗/poet.song.91000.json','["一篆煙消繫臂香，閑看書冊就牙牀。", "鶯聲冉冉來深院，柳色陰陰暗畫牆。", "眼底落紅千萬點，臉邊新淚兩三行。", "梨花細雨黄昏後，不是愁人也斷腸。"]'),
('2e1952d2-aa05-42b4-8daa-612f17d4c791','春歸五首  其一','朱淑真','宋','宋诗','song-poetry','','[]','片片飛花弄晚暉，杜鵑啼血訴春歸。',32,'全唐诗/poet.song.91000.json','["片片飛花弄晚暉，杜鵑啼血訴春歸。", "憑誰礙斷春歸路，更且留連伴翠微。"]'),
('23261c98-b884-4f28-ba15-afaf6ed91cb4','春歸五首  其二','朱淑真','宋','宋诗','song-poetry','','[]','滿地落花初過雨，一聲啼鳥已春歸。',32,'全唐诗/poet.song.91000.json','["滿地落花初過雨，一聲啼鳥已春歸。", "午窗夢覺情懷惡，風絮欺人故著衣。"]'),
('3c2fe0c0-8431-496f-a0eb-943c2f1277de','春歸五首  其三','朱淑真','宋','宋诗','song-poetry','','[]','狼藉花因昨夜風，春歸了不見行蹤。',32,'全唐诗/poet.song.91000.json','["狼藉花因昨夜風，春歸了不見行蹤。", "孤吟惸坐清如水，憶得輕離十二峰。"]'),
('662849b5-6467-49f2-8623-46c1fe1aee34','春歸五首  其四','朱淑真','宋','宋诗','song-poetry','','[]','一點芳心冷若灰，寂無夢想惹塵埃。',32,'全唐诗/poet.song.91000.json','["一點芳心冷若灰，寂無夢想惹塵埃。", "東君總領鶯花處，浪蝶狂蜂不自來。"]'),
('a2b450f6-b2bb-4e91-8c42-438a43180361','春歸五首  其五','朱淑真','宋','宋诗','song-poetry','','[]','平疇交綠藹成陰，梅豆初肥酒味新。',32,'全唐诗/poet.song.91000.json','["平疇交綠藹成陰，梅豆初肥酒味新。", "門外好禽情分熟，不知春去尚啼春。"]'),
('04b9bb55-71fd-4d14-a379-640669f0101b','惜春','朱淑真','宋','宋诗','song-poetry','','["\u5bd3\u4eba", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u7231\u60c5", "\u82b1", "\u5199\u82b1", "\u5b8b\u8bd7"]','連理枝頭花正開，妒花風雨苦相催。',32,'全唐诗/poet.song.91000.json','["連理枝頭花正開，妒花風雨苦相催。", "願教青帝長爲主，莫遣紛紛落翠苔。"]'),
('81d6b46b-29b2-4c42-ad2b-7fc1405039c3','春睡','朱淑真','宋','宋诗','song-poetry','','[]','午窗春睡足，推枕起來時。',48,'全唐诗/poet.song.91000.json','["午窗春睡足，推枕起來時。", "瘦怯羅衣褪，慵妝鬢影垂。", "舊愁消不盡，新恨忽相隨。", "有蝶傳魂夢，無鴻寄別離。"]'),
('9ac83df5-4aa1-41e8-834d-41e93c0907df','春日閑坐','朱淑真','宋','宋诗','song-poetry','','[]','社燕歸來春正濃，摧花雨倩一番風。',32,'全唐诗/poet.song.91000.json','["社燕歸來春正濃，摧花雨倩一番風。", "倚樓閑省經由處，月館雲藏望眼中。"]'),
('20d4e513-eb0b-4348-8bd4-fdc11673e88f','春夜','朱淑真','宋','宋诗','song-poetry','','[]','半簷斜月人歸後，一枕清風夢破時。',32,'全唐诗/poet.song.91000.json','["半簷斜月人歸後，一枕清風夢破時。", "無奈梨花春寂寂，杜鵑聲裏祇顰眉。"]'),
('fd8949c2-d0c8-4dd9-86e1-20803aa3859b','春宵','朱淑真','宋','宋诗','song-poetry','','[]','夢回酒醒春愁怯，寶鴨煙銷香未歇。',32,'全唐诗/poet.song.91000.json','["夢回酒醒春愁怯，寶鴨煙銷香未歇。", "薄衾無奈五更寒，杜鵑叫落西樓月。"]'),
('e0bfecb6-e307-4187-a5a3-dec10956fd96','元夜三首  其一','朱淑真','宋','宋诗','song-poetry','','[]','闌月籠春霽色澄，深沉簾幙管絃清。',64,'全唐诗/poet.song.91000.json','["闌月籠春霽色澄，深沉簾幙管絃清。", "爭豪競侈連仙館，墜翠遺珠滿帝城。", "一片笑聲連鼓吹，六街燈火麗升平。", "歸來禁漏踰三四，窗上梅花瘦影橫。"]'),
('1cfbedf0-a542-4884-ab56-6ac65083acfd','元夜三首  其二','朱淑真','宋','宋诗','song-poetry','','[]','厭塵小雨潤生寒，雲影澄鮮月正圓。',64,'全唐诗/poet.song.91000.json','["厭塵小雨潤生寒，雲影澄鮮月正圓。", "十里綺羅春富貴，千門燈火夜嬋娟。", "香街寶馬嘶瓊轡，輦路輕輿鄉翠軿。", "高掛危簾凝望處，分明星斗下晴天。"]'),
('a0cb74dc-09c4-4688-aa41-57f1c6ed0f89','元夜三首  其三','朱淑真','宋','宋诗','song-poetry','','[]','火獨銀花觸目紅，揭天鼓吹鬧春風。',64,'全唐诗/poet.song.91000.json','["火獨銀花觸目紅，揭天鼓吹鬧春風。", "欣歡入手愁忙裏，舊事驚心憶夢中。", "但願暫成人繾綣，不妨常任月朦朧。", "賞燈那得工夫醉，未必明年此會同。"]'),
('791388f1-6aa0-47d4-975e-6bb4b1564421','元夜遇雨','朱淑真','宋','宋诗','song-poetry','','[]','煙火笙歌是處休，沉沉春雨暗皇州。',32,'全唐诗/poet.song.91000.json','["煙火笙歌是處休，沉沉春雨暗皇州。", "危樓十二闌干曲，一曲闌干一曲愁。"]'),
('d2a23539-8cf4-4fd0-901b-d3136ccb8015','雨中寫懷','朱淑真','宋','宋诗','song-poetry','','[]','東風吹雨苦生寒，慳澀春光不放寬。',32,'全唐诗/poet.song.91000.json','["東風吹雨苦生寒，慳澀春光不放寬。", "萬紫千紅渾未見，閑愁先占許多般。"]'),
('37491148-46a0-48dc-a0fd-ffdacda987d3','夜雨二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','抱影無眠坐夜闌，窗風戰雨下琅玕。',32,'全唐诗/poet.song.91000.json','["抱影無眠坐夜闌，窗風戰雨下琅玕。", "我將好況供陪夢，只恐燈花不耐寒。"]'),
('3df70a6b-a5a6-43b5-a4ec-ef4f03ec2fb8','夜雨二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','明朝春在雨中看，心碎簷聲點滴間。',32,'全唐诗/poet.song.91000.json','["明朝春在雨中看，心碎簷聲點滴間。", "蹤有酒能消熟恨，寧無花解怨生寒。"]'),
('7d0e3fc5-f240-4b57-a065-1fc404488c4b','膏雨','朱淑真','宋','宋诗','song-poetry','','[]','添得垂楊色更濃，飛煙捲霧弄輕風。',64,'全唐诗/poet.song.91000.json','["添得垂楊色更濃，飛煙捲霧弄輕風。", "展勻芳草茸茸綠，濕透妖桃薄薄紅。", "潤物有情如著意，催花無語自施工。", "一犂膏脈分春壟，只慰農桑望眼中。"]'),
('8b79841d-c17d-4454-bd15-0b5c10d10d00','阻雨','朱淑真','宋','宋诗','song-poetry','','[]','幾度尋芳已不成，又還寂寞過清明。',32,'全唐诗/poet.song.91000.json','["幾度尋芳已不成，又還寂寞過清明。", "慳風澀雨顛迷甚，十日春無一日晴。"]'),
('ddabd380-0c06-4152-ab06-2afadfd6a0e0','清晝','朱淑真','宋','宋诗','song-poetry','','["\u590f\u5929"]','竹搖清影罩幽窗，兩兩時禽噪夕陽。',32,'全唐诗/poet.song.91000.json','["竹搖清影罩幽窗，兩兩時禽噪夕陽。", "謝卻海棠飛盡絮，困人天氣日初長。"]'),
('3adebc7e-4b35-4763-8c33-9c5310c2cea5','惜花','朱淑真','宋','宋诗','song-poetry','','[]','生情賦得春心性，剩選名花繞砌栽。',64,'全唐诗/poet.song.91000.json','["生情賦得春心性，剩選名花繞砌栽。", "客到且堪供客眼，詩慳聊可助詩才。", "低叢高架隨宜有，淺紫深紅次第開。", "便做即今風雨限，要看香豔繡蒼苔。"]'),
('d401b5f0-4873-4c79-97f2-dc8736c5ba6d','看花','朱淑真','宋','宋诗','song-poetry','','[]','欲向花邊遣舊愁，對花無語祇成羞。',32,'全唐诗/poet.song.91000.json','["欲向花邊遣舊愁，對花無語祇成羞。", "春光蹤好須歸去，誰伴幽人著意留。"]'),
('f0b3adb3-f805-45e9-bb67-88322b46ae5e','移花','朱淑真','宋','宋诗','song-poetry','','[]','自移紅藥繞闌栽，粉膩香嬌逐旋開。',32,'全唐诗/poet.song.91000.json','["自移紅藥繞闌栽，粉膩香嬌逐旋開。", "且與幽人充近侍，莫教風雨苦相催。"]'),
('484ebbdb-5086-46a6-b1a3-eb3fcfae4bdc','小桃葉去偶生數花','朱淑真','宋','宋诗','song-poetry','','[]','庭外緗桃一萼紅，多情特地振春風。',32,'全唐诗/poet.song.91000.json','["庭外緗桃一萼紅，多情特地振春風。", "仙源已露真消息，迥作新花發舊叢。"]'),
('fe27c040-81b5-4db4-9c77-2ee9b0a5c85a','窗西桃花盛開','朱淑真','宋','宋诗','song-poetry','','[]','盡是劉郎手自栽，劉郎去後幾番開。',32,'全唐诗/poet.song.91000.json','["盡是劉郎手自栽，劉郎去後幾番開。", "東君有意能相顧，蛺蝶無情更不來。"]'),
('d2712989-18f3-4f78-bdcb-36535c01433a','杏花','朱淑真','宋','宋诗','song-poetry','','[]','淺注胭脂剪絳綃，獨將妖豔冠花曹。',32,'全唐诗/poet.song.91000.json','["淺注胭脂剪絳綃，獨將妖豔冠花曹。", "春心自得東君意，遠勝玄都觀裏桃。"]'),
('5d0ec773-c72a-4afd-8ad4-3698fd365c54','梨花','朱淑真','宋','宋诗','song-poetry','','[]','朝來带雨一枝春，薄薄香羅蹙蕊勻。',64,'全唐诗/poet.song.91000.json','["朝來带雨一枝春，薄薄香羅蹙蕊勻。", "冷豔未饒梅共色，靚粧長與月爲鄰。", "許同蝶夢還如蝶，似替人愁卻笑人。", "須到年年寒食夜，情懷爲你倍傷神。"]'),
('c16d5d76-8396-470f-9e13-af3ffd56b371','海棠','朱淑真','宋','宋诗','song-poetry','','[]','胭脂爲臉玉爲肌，未赴春風二月期。',64,'全唐诗/poet.song.91000.json','["胭脂爲臉玉爲肌，未赴春風二月期。", "曾比溫泉妃子睡，不吟西蜀杜陵詩。", "桃羞豔冶愁回首，柳妬妖嬈祇皺眉。", "燕子欲歸寒食近，黄昏庭院雨絲絲。"]'),
('50864ba9-6a72-4e28-9ee7-fbac69a36cdc','茶䕷','朱淑真','宋','宋诗','song-poetry','','[]','花神未怯春歸去，故遣仙姿殿後芳。',64,'全唐诗/poet.song.91000.json','["花神未怯春歸去，故遣仙姿殿後芳。", "白玉體輕蟾魄瑩，素紗囊薄麝臍香。", "夢思洛浦嬋娟態，愁記瑤臺淡淨粧。", "勾引詩情清絕處，一枝和雨在東牆。"]'),
('d0957b57-d70e-4f84-ab0a-2612f226b717','偶得牡丹數本移植窗外將有著花意二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','王種元從上苑分，擁培圍護怕因循。',32,'全唐诗/poet.song.91000.json','["王種元從上苑分，擁培圍護怕因循。", "快晴快雨隨人意，正爲牆陰作好春。"]'),
('a2a977ae-39b4-485c-b0a9-c6ab34d91006','偶得牡丹數本移植窗外將有著花意二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','香玉對春未啄花，露根烘曉見紅霞。',32,'全唐诗/poet.song.91000.json','["香玉對春未啄花，露根烘曉見紅霞。", "自非水月觀音樣，不稱維摩居士家。"]'),
('9a484055-7c0e-4cb7-9cbb-fda9e42daeb1','瑞香','朱淑真','宋','宋诗','song-poetry','','[]','玲瓏巧蹙紫羅囊，今得東君著意粧。',64,'全唐诗/poet.song.91000.json','["玲瓏巧蹙紫羅囊，今得東君著意粧。", "带露欲開宜曉日，臨風微困怯春霜。", "發揮名字來雕輦，彈厭芳菲入醉鄉。", "最是午窗初睡省，重重贏得夢魂香。"]'),
('4927b550-22cd-4d35-8d9d-814a49236e14','柳','朱淑真','宋','宋诗','song-poetry','','[]','萬縷千絲織暖風，絆煙留霧市橋東。',32,'全唐诗/poet.song.91000.json','["萬縷千絲織暖風，絆煙留霧市橋東。", "砌成幽恨斜陰裏，供斷閑愁細雨中。"]'),
('b681186b-7622-47d9-9451-ab5925c073c7','柳絮','朱淑真','宋','宋诗','song-poetry','','[]','繚繞晴空似雪飛，悠揚不肯著塵泥。',64,'全唐诗/poet.song.91000.json','["繚繞晴空似雪飛，悠揚不肯著塵泥。", "花邊嬌軟黏蜂翅，陌上輕狂趁馬蹄。", "貼水化萍隨浪遠，弄風無影度牆低。", "成團作陣愁春去，故把東君歸路迷。"]'),
('088b491f-68b5-47d9-a83c-9a5bf6676102','聞子規有感','朱淑真','宋','宋诗','song-poetry','','[]','花落花開事可悲，等閑一醉失芳菲。',64,'全唐诗/poet.song.91000.json','["花落花開事可悲，等閑一醉失芳菲。", "園林初聽鶯聲澀，庭徑俄看蝶粉稀。", "欹枕夜深無夢到，倚樓天外便魂飛。", "我無雲翼飛歸去，杜宇能飛卻不歸。"]'),
('631426c7-8244-4bab-a448-1d90d1268c4d','初夏二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','枝上渾無一點春，半隨流水半隨塵。',64,'全唐诗/poet.song.91000.json','["枝上渾無一點春，半隨流水半隨塵。", "柔桑欲椹吳蠶老，稚筍成竿綵鳳馴。", "荷嫩愛風欹蓋翠，榴花宜日皺裙殷。", "待封一𥯃傷心淚，寄與南樓薄倖人。"]'),
('656c8e7e-879f-42f7-81b4-f3da1f6bf358','初夏二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','冰蠶欲繭二桑陰，粉籜彫風曲徑深。',32,'全唐诗/poet.song.91000.json','["冰蠶欲繭二桑陰，粉籜彫風曲徑深。", "長日漸成微暑意，喜看樓影浸波心。"]'),
('bb68df05-6989-4fb0-bcfc-e766e7071464','日永','朱淑真','宋','宋诗','song-poetry','','[]','雨過橫塘蛙吹鬧，日融芳圃蜜脾香。',32,'全唐诗/poet.song.91000.json','["雨過橫塘蛙吹鬧，日融芳圃蜜脾香。", "一痕心事難消遣，雙鵲飛鳴過短牆。"]'),
('bea177fd-87e7-42a2-bf08-0666e365bc19','端午','朱淑真','宋','宋诗','song-poetry','','[]','縱有靈符共綵絲，心情不似舊家時。',32,'全唐诗/poet.song.91000.json','["縱有靈符共綵絲，心情不似舊家時。", "榴花照眼能牽恨，強切菖蒲泛酒巵。"]'),
('af53a824-19fe-41a4-926c-79a9ca015720','苦熱聞田夫語有感','朱淑真','宋','宋诗','song-poetry','','[]','日輪推火燒長空，正是六月三伏中。',128,'全唐诗/poet.song.91000.json','["日輪推火燒長空，正是六月三伏中。", "旱雲萬疊赤不雨，地裂河枯塵起風。", "農憂田畝死禾黍，車水救田無暫處。", "日長饑渴喉嚨焦，汗血勤勞誰與語。", "播插耕耘功已足，尚愁秋晚無成熟。", "雲霓不至空自忙，恨不擡頭向天哭。", "寄語豪家輕薄兒，綸巾羽扇將何爲。", "田中青稻半黄槁，安坐高堂知不知。"]'),
('a8e90414-52c1-4bbe-a62d-5d24febca0c9','納涼桂堂二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','微涼待月畫樓西，風遞荷香拂面吹。',32,'全唐诗/poet.song.91000.json','["微涼待月畫樓西，風遞荷香拂面吹。", "先自桂堂無暑氣，那堪人唱雪堂詞。"]'),
('b731de41-728b-4f77-a252-8d212f0fe9ed','納涼桂堂二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','清香滿座瓜分玉，明月澄空酒漾金。',32,'全唐诗/poet.song.91000.json','["清香滿座瓜分玉，明月澄空酒漾金。", "不是夜涼難就醉，一簾秋色竹森森。"]'),
('f4c9a4f6-337f-4d4f-8b20-54b5feef736b','梅蒸滋甚因懷湖上二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','東風作雨淺寒生，梅子傳黄未肯晴。',32,'全唐诗/poet.song.91000.json','["東風作雨淺寒生，梅子傳黄未肯晴。", "戢戢籜龍頭角就，溫雲繚繞變江城。"]'),
('8f9e76d2-2905-4f7b-97f4-cabcba063dff','梅蒸滋甚因懷湖上二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','雲暗湖光雨四垂，珠璣萬斛撒琉璃。',32,'全唐诗/poet.song.91000.json','["雲暗湖光雨四垂，珠璣萬斛撒琉璃。", "紫苔階面寒聲急，有甚心情更賦詩。"]'),
('58c6f79e-6046-4f05-b075-da122bb83809','納涼即事','朱淑真','宋','宋诗','song-poetry','','[]','旋折蓮蓬破綠瓜，酒杯收起點新茶。',32,'全唐诗/poet.song.91000.json','["旋折蓮蓬破綠瓜，酒杯收起點新茶。", "飛蠅不到冰壺淨，時有涼風入齒牙。"]'),
('8789c61c-d676-48c8-9b6c-66ffd1a827dc','夏雨生涼三首  其一','朱淑真','宋','宋诗','song-poetry','','[]','烈日如焚正藴隆，黑雲載雨瀉長空。',32,'全唐诗/poet.song.91000.json','["烈日如焚正藴隆，黑雲載雨瀉長空。", "搜龍霹靂一聲歇，庭竹瀟瀟來好風。"]'),
('b10e0756-1f88-47c8-9289-ce2c39133392','夏雨生涼三首  其二','朱淑真','宋','宋诗','song-poetry','','[]','崒嵂金蛇殷殷雷，過雷斑駁漸晴開。',32,'全唐诗/poet.song.91000.json','["崒嵂金蛇殷殷雷，過雷斑駁漸晴開。", "雨催涼意詩催雨，當盡新篘玉友醅。"]'),
('2a7cdef5-34eb-4929-ba0b-8290fadd980a','夏雨生涼三首  其三','朱淑真','宋','宋诗','song-poetry','','[]','眼界清無俗事來，要涼更著好詩催。',32,'全唐诗/poet.song.91000.json','["眼界清無俗事來，要涼更著好詩催。", "涼生還又撩幽恨，留取孤樽對月開。"]'),
('245eb650-3a17-4bef-a4ab-54b30f421571','雨過','朱淑真','宋','宋诗','song-poetry','','[]','幽篁脫籜綠參差，雨過微風拂面宜。',32,'全唐诗/poet.song.91000.json','["幽篁脫籜綠參差，雨過微風拂面宜。", "浴罷晚粧慵不御，卻親筆硯賦新詩。"]'),
('aa446b06-66d4-4b6d-a34c-c8fbf19cb659','喜雨','朱淑真','宋','宋诗','song-poetry','','[]','赤日炎炎燒八荒，田中無雨苗半黄。',192,'全唐诗/poet.song.91000.json','["赤日炎炎燒八荒，田中無雨苗半黄。", "天工不放老龍懶，赤電驅雷雲四方。", "瓊瑰萬斛寫碧落，陂塘池沼皆泱泱。", "高田低田盡沾澤，農喜禾無可槁傷。", "我皇聖德布寰宇，六月青天降甘雨。", "四海咸蒙滂沛恩，九州盡解焦熬苦。", "傾盆勢歇塵點無，衣袂生涼罷揮羽。", "江上數峰天外青，眼界增明快心腑。", "炎熱一洗無留跡，頓覺好風生雨腋。", "紗廚湘簟爽氣新，沉李削瓜浮玉液。", "傍池占得秋意多，尚餘珠點綴圓荷。", "樓頭月上雲散盡，遠水連天天接波。"]'),
('0739837e-f2c5-419e-9451-6d2649413993','夏夜','朱淑真','宋','宋诗','song-poetry','','[]','花底杯傾演漾金，月邊風細竹陰陰。',32,'全唐诗/poet.song.91000.json','["花底杯傾演漾金，月邊風細竹陰陰。", "故人清遠更真絕，消盡煩襟爽氣深。"]'),
('09c9b6fa-376d-4120-a83a-0e1ced1ada64','新荷','朱淑真','宋','宋诗','song-poetry','','[]','平波浮動洛妃鈿，翠色嬌圓小更鮮。',32,'全唐诗/poet.song.91000.json','["平波浮動洛妃鈿，翠色嬌圓小更鮮。", "蕩漾湖光三十頃，未知葉底是誰蓮。"]'),
('13ff21ef-3e84-4a80-b317-507d7b2d28d3','青蓮花','朱淑真','宋','宋诗','song-poetry','','[]','淨土移根體性殊，笑他紅白費工夫。',64,'全唐诗/poet.song.91000.json','["淨土移根體性殊，笑他紅白費工夫。", "幽姿羞損嬋娟女，異色孤芳瀲灩湖。", "顧影有情欺水荇，向人無語鄙風蒲。", "一枝搖動清香遠，幾許詩牋與畫圖。"]'),
('fb271b12-b7a9-4a8a-ac28-6201d02196a8','水梔子','朱淑真','宋','宋诗','song-poetry','','[]','一痕春寄小峰蠻，薝蔔香清水影寒。',32,'全唐诗/poet.song.91000.json','["一痕春寄小峰蠻，薝蔔香清水影寒。", "玉質自然無暑意，更宜移就月中看。"]'),
('d4ae32a0-60a3-47bc-80e7-09fdf9532004','羞燕','朱淑真','宋','宋诗','song-poetry','','[]','停針無語淚盈眸，不但傷春夏亦愁。',32,'全唐诗/poet.song.91000.json','["停針無語淚盈眸，不但傷春夏亦愁。", "花外飛來雙燕子，一番飛過一番羞。"]'),
('24cb31a0-32ff-45ea-b00b-5dcfa58cb7f8','早秋','朱淑真','宋','宋诗','song-poetry','','[]','一痕雨過濕秋光，紈扇初拋自有涼。',32,'全唐诗/poet.song.91000.json','["一痕雨過濕秋光，紈扇初拋自有涼。", "霧影乍隨山影薄，蛩聲偏接漏聲長。"]'),
('e1fd577d-8173-452e-b15f-0380b8deef54','秋日登樓','朱淑真','宋','宋诗','song-poetry','','[]','梧影蕭疏弄晚晴，殘蟬凄楚不堪聽。',32,'全唐诗/poet.song.91000.json','["梧影蕭疏弄晚晴，殘蟬凄楚不堪聽。", "樓高望極秋山去，溢眼重重疊疊青。"]'),
('5c21a868-1755-49fb-9914-dbfab8f84326','秋夜雜書二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','雨過涼生枕簟秋，樓頭新月掛銀鉤。',32,'全唐诗/poet.song.91000.json','["雨過涼生枕簟秋，樓頭新月掛銀鉤。", "且無揮扇勞纖手，只好燒香伴酒甌。"]'),
('f2bbe06f-6003-47ba-a93b-d05d94571e6e','秋夜雜書二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','窗外蛩吟解說秋，迢迢清夜惜前遊。',32,'全唐诗/poet.song.91000.json','["窗外蛩吟解說秋，迢迢清夜惜前遊。", "月華飛過西樓上，添起離人一段愁。"]'),
('38cefb32-6767-436a-816c-ab06c0efd9ce','秋夜二首  其一','朱淑真','宋','宋诗','song-poetry','','["\u95fa\u6028", "\u6292\u60c5", "\u5b64\u5bc2", "\u79cb\u5929", "\u591c\u665a", "\u60c6\u6005"]','夜久無眠秋氣清，燭花頻剪欲三更。',32,'全唐诗/poet.song.91000.json','["夜久無眠秋氣清，燭花頻剪欲三更。", "鋪牀涼滿梧桐月，月在梧桐缺處明。"]'),
('bfad699f-17e3-4df6-b4cc-5322550f93df','秋夜二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','涼天如水夜澄鮮，桂子風清嫩去眠。',32,'全唐诗/poet.song.91000.json','["涼天如水夜澄鮮，桂子風清嫩去眠。", "多謝嫦娥知我意，中秋未到月先圓。"]'),
('dbe23bd4-9254-430d-a286-71166cf4c79a','秋夜聞雨三首  其一','朱淑真','宋','宋诗','song-poetry','','[]','似箭撩風穿帳幕，如傾涼雨咽更籌。',32,'全唐诗/poet.song.91000.json','["似箭撩風穿帳幕，如傾涼雨咽更籌。", "冷懷欹枕人無寐，鐵石肝腸也淚流。"]'),
('6c2654d3-4024-42e8-b6bb-1820b135ec9c','秋夜聞雨三首  其二','朱淑真','宋','宋诗','song-poetry','','[]','竹窗蕭索鎮如秋，雨滴簷花夜不休。',32,'全唐诗/poet.song.91000.json','["竹窗蕭索鎮如秋，雨滴簷花夜不休。", "獨宿廣寒多少恨，一時分付我心頭。"]'),
('fa9a537e-fc7e-4cb8-9e1f-9ac7267777c5','秋夜聞雨三首  其三','朱淑真','宋','宋诗','song-poetry','','[]','似篾身材無事瘦，如絲腸肚怎禁愁。',32,'全唐诗/poet.song.91000.json','["似篾身材無事瘦，如絲腸肚怎禁愁。", "鳴窗更聽芭蕉雨，一葉中藏萬斛愁。"]'),
('7a13e8d2-3d80-4ca0-87e4-49fd4a123a2c','秋夜有感','朱淑真','宋','宋诗','song-poetry','','[]','哭損雙眸斷盡腸，怕黄昏後到昏黄。',32,'全唐诗/poet.song.91000.json','["哭損雙眸斷盡腸，怕黄昏後到昏黄。", "更堪細雨新秋夜，一點殘燈伴夜長。"]'),
('ffca74b4-37fb-453a-84cc-22bac89328a3','中夜','朱淑真','宋','宋诗','song-poetry','','[]','馮夷捧出一輪月，河伯吹開萬里雲。',32,'全唐诗/poet.song.91000.json','["馮夷捧出一輪月，河伯吹開萬里雲。", "寥廓無塵河漢遠，水光天影接清芬。"]'),
('4ad49447-3dfe-40d9-a764-25e8cd707543','月夜','朱淑真','宋','宋诗','song-poetry','','[]','燈花鵲喜兩無憑，那更清宵夢不成。',32,'全唐诗/poet.song.91000.json','["燈花鵲喜兩無憑，那更清宵夢不成。", "月上樓頭天似洗，愁人別是一般情。"]'),
('eac3287f-969c-4f6d-bfe1-b1db2cf9980a','長宵','朱淑真','宋','宋诗','song-poetry','','[]','月轉西窗斗帳深，燈昏香燼擁寒衾。',32,'全唐诗/poet.song.91000.json','["月轉西窗斗帳深，燈昏香燼擁寒衾。", "魂飛何處臨風笛，腸斷誰家搗夜砧。"]'),
('3a67fef9-f25f-4e5f-a844-917e440050f4','對景漫成','朱淑真','宋','宋诗','song-poetry','','[]','半窗殘照一簾風，小小池亭竹徑通。',32,'全唐诗/poet.song.91000.json','["半窗殘照一簾風，小小池亭竹徑通。", "楓葉醉紅秋色裏，兩三行雁夕陽中。"]'),
('737536af-faca-4cac-8623-a00646643a30','七夕','朱淑真','宋','宋诗','song-poetry','','[]','拜月亭前梧葉稀，穿針樓上覺秋遲。',32,'全唐诗/poet.song.91000.json','["拜月亭前梧葉稀，穿針樓上覺秋遲。", "天孫正好貪歡笑，那得工夫賜巧絲。"]'),
('91052f5d-e493-45ed-a102-52f52a5fc19d','中秋','朱淑真','宋','宋诗','song-poetry','','[]','秋來長是病，不易到中秋。',48,'全唐诗/poet.song.91000.json','["秋來長是病，不易到中秋。", "欲賞今宵月，須登昨夜樓。", "露濃梧影淡，風細桂香浮。", "莫做尋常看，嫦娥亦解愁。"]'),
('7465e60f-b24c-4c19-a99f-4cfc0bc980c4','中秋值雨','朱淑真','宋','宋诗','song-poetry','','[]','積葉冷翻階，癡雲暗海涯。',48,'全唐诗/poet.song.91000.json','["積葉冷翻階，癡雲暗海涯。", "樓高勞望眼，天暝隔吟懷。", "宛轉愁難遣，團圓事未諧。", "四簷飛急雨，寂寂坐空齊。"]'),
('8b0f46d8-ba3c-4f2f-91ec-a40364238d3c','獨坐','朱淑真','宋','宋诗','song-poetry','','[]','捲簾待明月，拂檻對西風。',48,'全唐诗/poet.song.91000.json','["捲簾待明月，拂檻對西風。", "夜氣涵秋色，瑤河浸碧空。", "草根鳴蟋蟀，天外叫冥鴻。", "幾許舊時事，今宵誰與同。"]'),
('47173a94-2e38-4077-aad7-69c2458b6d34','悶懷二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','黄昏院落雨瀟瀟，獨對孤燈恨氣高。',32,'全唐诗/poet.song.91000.json','["黄昏院落雨瀟瀟，獨對孤燈恨氣高。", "針錢懶拈腸自斷，梧桐葉葉剪風刀。"]'),
('76b615e3-6627-4c06-8813-c754232c950a','悶懷二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','秋雨沉沉滴夜長，夢難成處轉淒涼。',32,'全唐诗/poet.song.91000.json','["秋雨沉沉滴夜長，夢難成處轉淒涼。", "芭蕉葉上梧桐裏，點點聲聲有斷腸。"]'),
('153e1424-a613-4999-85b5-3d555e232b15','湖上閑望二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','照水芙蓉入眼明，敗荷枯草鬧秋聲。',32,'全唐诗/poet.song.91000.json','["照水芙蓉入眼明，敗荷枯草鬧秋聲。", "疏雲不雨陰長定，喚起詩懷酒興清。"]'),
('973c2c60-f7bc-498f-8824-6ea4c28cb59a','湖上閑望二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','薄雲疏日弄陰晴，山秀湖平眼界清。',32,'全唐诗/poet.song.91000.json','["薄雲疏日弄陰晴，山秀湖平眼界清。", "不必西風吹葉下，愁人滿耳是秋聲。"]'),
('456f196a-b819-4a86-99f8-d532ea770cb4','中秋聞笛','朱淑真','宋','宋诗','song-poetry','','[]','誰家橫笛弄輕清，喚起離人枕上情。',32,'全唐诗/poet.song.91000.json','["誰家橫笛弄輕清，喚起離人枕上情。", "自是斷腸聽不得，非干吹出斷腸聲。"]'),
('294461d1-25db-4b78-bc1e-f84b1b15ce08','九日','朱淑真','宋','宋诗','song-poetry','','[]','去年年月愁何限，重上心來益斷腸。',64,'全唐诗/poet.song.91000.json','["去年年月愁何限，重上心來益斷腸。", "秋色夕陽俱淡薄，淚痕離思共淒涼。", "征鴻有陣全無信，黄菊無情卻有香。", "自覺近來清瘦了，懶將鸞鏡照容光。"]'),
('1d9163e7-617a-4c10-84c4-801dd11120ce','寫懷二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','淡月疏雲九月天，醉霜危葉墜江寒。',32,'全唐诗/poet.song.91000.json','["淡月疏雲九月天，醉霜危葉墜江寒。", "孤窗鎮日無聊賴，編輯詩詞改抹看。"]'),
('aa34d852-80fd-40c1-899e-b409fb98344b','寫懷二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','菊有黄花離檻邊，怨鴻聲重下寒天。',32,'全唐诗/poet.song.91000.json','["菊有黄花離檻邊，怨鴻聲重下寒天。", "偏宜小閣幽窗下，獨自燒香獨自眠。"]'),
('b4df00b7-4835-4dae-9e70-06e346b73c39','秋日述懷','朱淑真','宋','宋诗','song-poetry','','[]','婦人雖軟眼，淚不等閑流。',24,'全唐诗/poet.song.91000.json','["婦人雖軟眼，淚不等閑流。", "我因無好況，揮斷五湖秋。"]'),
('97656ea5-751e-431b-a781-8b7d20b062fe','秋日偶成','朱淑真','宋','宋诗','song-poetry','','[]','初合雙鬟學畫眉，未知心事屬他誰。',32,'全唐诗/poet.song.91000.json','["初合雙鬟學畫眉，未知心事屬他誰。", "待將滿抱中秋月，分付蕭郎萬首詩。"]'),
('84969029-1a2c-45e8-a0a9-f6455216bc1c','秋日晚望','朱淑真','宋','宋诗','song-poetry','','[]','煙濃難認別州山，彷彿鷗群浴遠灘。',32,'全唐诗/poet.song.91000.json','["煙濃難認別州山，彷彿鷗群浴遠灘。", "一點客帆搖動處，排雲給日弄先寒。"]'),
('9b9a42cd-b73b-45f9-a364-13c86e47798a','秋夜牽情三首  其一','朱淑真','宋','宋诗','song-poetry','','[]','纖纖新月掛黄昏，人在幽閨欲斷魂。',64,'全唐诗/poet.song.91000.json','["纖纖新月掛黄昏，人在幽閨欲斷魂。", "牋素拆封還又改，酒杯慵舉卻重溫。", "燈花占斷燒心事，羅袖長供挹淚痕。", "益悔風流多不足，須知恩愛是愁恨。"]'),
('8bda34ae-ea9f-46d0-b2c9-776f94d153ac','秋夜牽情三首  其二','朱淑真','宋','宋诗','song-poetry','','[]','簷外秋清繡綺窗，菊煙月露冷浮香。',32,'全唐诗/poet.song.91000.json','["簷外秋清繡綺窗，菊煙月露冷浮香。", "寒更二十五聲點，相應愁情爾許長。"]'),
('97171c6c-0652-42f3-b70c-7bc371a47ce3','秋夜牽情三首  其三','朱淑真','宋','宋诗','song-poetry','','[]','閑悶閑愁百病生，有情終不似無情。',32,'全唐诗/poet.song.91000.json','["閑悶閑愁百病生，有情終不似無情。", "風流意思鐫磨盡，離別肝腸鑄寫成。"]'),
('0acc8fbd-fa6a-437e-8fc2-b305b96bbe43','詠桂四首  其一','朱淑真','宋','宋诗','song-poetry','','[]','彈壓西風擅衆芳，十分秋色爲君忙。',32,'全唐诗/poet.song.91000.json','["彈壓西風擅衆芳，十分秋色爲君忙。", "一枝淡貯書窗下，人與花心各自香。"]'),
('0a4f1688-62c3-4092-b500-874a82aed957','詠桂四首  其二','朱淑真','宋','宋诗','song-poetry','','[]','移根蟾窟不尋常，枝葉猶垂月露香。',32,'全唐诗/poet.song.91000.json','["移根蟾窟不尋常，枝葉猶垂月露香。", "可笑當年陶靖節，東籬猶带菊花黄。"]'),
('4e420e27-0669-414f-9274-7ff982e2fb8f','詠桂四首  其三','朱淑真','宋','宋诗','song-poetry','','[]','酷愛清香折一枝，故簪香髻驀思維。',32,'全唐诗/poet.song.91000.json','["酷愛清香折一枝，故簪香髻驀思維。", "若教水月浮清淺，消得林逋兩句詩。"]'),
('ce6e147d-7527-4726-8878-4e97ad839c72','詠桂四首  其四','朱淑真','宋','宋诗','song-poetry','','[]','月待圓時花正好，花將殘後月還虧。',32,'全唐诗/poet.song.91000.json','["月待圓時花正好，花將殘後月還虧。", "須知天上人間物，同稟秋清在一時。"]'),
('9dd71ae1-8cd1-44fb-b383-c0a314dfdce0','堂下巖桂秋晚未開作詩促之','朱淑真','宋','宋诗','song-poetry','','[]','著意裁詩特地催，花須著意聽新詩。',64,'全唐诗/poet.song.91000.json','["著意裁詩特地催，花須著意聽新詩。", "清香未吐黄金粟，嫩蕊猶藏碧玉枝。", "不是地寒偏放晚，定知花好故開遲。", "也宜急趁無風雨，莫待霜高露結時。"]'),
('438e4e8f-c718-4daf-8b82-5120adddf68b','白菊','朱淑真','宋','宋诗','song-poetry','','[]','回旋秋色漙清露，淩厲西風紫嫩霜。',32,'全唐诗/poet.song.91000.json','["回旋秋色漙清露，淩厲西風紫嫩霜。", "莫作東籬等閑看，下清曾借廣寒香。"]'),
('f7fff300-bc8f-40bc-b3cf-e38a0142de49','冬日梅窗書事四首  其一','朱淑真','宋','宋诗','song-poetry','','[]','明窗瑩几淨無塵，月映幽窗夜色新。',32,'全唐诗/poet.song.91000.json','["明窗瑩几淨無塵，月映幽窗夜色新。", "惟有梅花無限意，射人又放一枝春。"]'),
('4441a4aa-cace-4ace-a916-781aa07a3f6d','冬日梅窗書事四首  其二','朱淑真','宋','宋诗','song-poetry','','[]','愛日烘簷暖似春，梅花描摸雪精神。',32,'全唐诗/poet.song.91000.json','["愛日烘簷暖似春，梅花描摸雪精神。", "清香未寄江南夢，偏惱幽閑獨睡人。"]'),
('681a5529-9e58-4d14-a619-5577fefcdd8e','冬日梅窗書事四首  其三','朱淑真','宋','宋诗','song-poetry','','[]','病起眼前俱不喜，可人唯有一枝梅。',32,'全唐诗/poet.song.91000.json','["病起眼前俱不喜，可人唯有一枝梅。", "未容明月橫疏影，且得清香寄酒杯。"]'),
('81231f79-c701-4b28-8cc4-cee1e79a6b06','冬日梅窗書事四首  其四','朱淑真','宋','宋诗','song-poetry','','[]','的皪江梅淺淺春，小窗相對自清新。',32,'全唐诗/poet.song.91000.json','["的皪江梅淺淺春，小窗相對自清新。", "幽香特地成牽役，不似梨花入夢頻。"]'),
('dc837a3c-b4d4-402d-8761-fd035ffff03c','二色梅','朱淑真','宋','宋诗','song-poetry','','[]','綴雪融酥各自芳，兩般顔色一般香。',32,'全唐诗/poet.song.91000.json','["綴雪融酥各自芳，兩般顔色一般香。", "瑤池會罷朝元客，縞素仙裳問道裝。"]'),
('5552aa6f-4693-437a-af46-a2ff90ba62ad','山腳有梅一株地差背陰冬深初結蕊作絕句寄之','朱淑真','宋','宋诗','song-poetry','','[]','溪橋野店梅都綻，此地冬深尚未寒。',32,'全唐诗/poet.song.91000.json','["溪橋野店梅都綻，此地冬深尚未寒。", "寄語梅花且寧奈，枝頭無雪不堪看。"]'),
('b12bfeb3-83e5-48e7-8e5c-8e595a2fbb79','雪夜對月賦詩','朱淑真','宋','宋诗','song-poetry','','[]','一樹梅花雪月間，梅清月皎雪光寒。',32,'全唐诗/poet.song.91000.json','["一樹梅花雪月間，梅清月皎雪光寒。", "看來表裏俱清徹，酌酒吟詩興儘寬。"]'),
('f34ea126-dd59-462e-83c1-d8754fafe868','欲雪','朱淑真','宋','宋诗','song-poetry','','[]','寒雀無聲滿竹籬，凍雲四羃雪將垂。',32,'全唐诗/poet.song.91000.json','["寒雀無聲滿竹籬，凍雲四羃雪將垂。", "北風不看人情面，控勒梅花不放枝。"]'),
('86b91b3f-0721-4c8a-842d-1a5898903c96','雪二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','一夜青山換玉尖，了無塵翳半痕兼。',64,'全唐诗/poet.song.91000.json','["一夜青山換玉尖，了無塵翳半痕兼。", "寒鴉打食圍沙渚，凍雀藏身宿畫簷。", "野外易尋東郭履，月中難認塞翁髯。", "梅花恣逞春情性，不管風姨號令嚴。"]'),
('8abc0331-2bf0-451b-9c8d-0bfbf2d95d63','雪二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','誰剪飛花六出尖，索娥肌肉瑩相兼。',64,'全唐诗/poet.song.91000.json','["誰剪飛花六出尖，索娥肌肉瑩相兼。", "分明幻玉迷青嶂，輕薄隨風入畫簷。", "凍筆想停詩客手，寒蓑宜擁釣翁髯。", "長安陋巷多貧士，可見鶉衣透膽嚴。"]'),
('fafbcb23-4642-4280-bc10-2f443bcb2a7b','雪晴','朱淑真','宋','宋诗','song-poetry','','[]','饑禽高噪日三竿，積雪回風墮指寒。',64,'全唐诗/poet.song.91000.json','["饑禽高噪日三竿，積雪回風墮指寒。", "秀色暗添梅富裕，綠梢明報竹平安。", "冷侵翠袖詩肩聳，春入紅爐酒量寬。", "簾外有山千萬疊，醉眸渾作怒濤看。"]'),
('7e0f726a-af0b-4d44-b0db-a18323a82d16','圍爐','朱淑真','宋','宋诗','song-poetry','','[]','圜坐紅爐唱小詞，旋篘新酒賞新詩。',32,'全唐诗/poet.song.91000.json','["圜坐紅爐唱小詞，旋篘新酒賞新詩。", "大家莫惜今宵醉，一別參差又幾時。"]'),
('1141a4de-fdb6-4039-950e-f4fb0fa95cf7','除日','朱淑真','宋','宋诗','song-poetry','','[]','爆竹聲中臘已殘，酴酥酒暖燭花寒。',32,'全唐诗/poet.song.91000.json','["爆竹聲中臘已殘，酴酥酒暖燭花寒。", "朦朧曉色籠春色，便覺春光不一般。"]'),
('ac85cda2-99ef-43bd-b5dc-18353020fdd6','除夜','朱淑真','宋','宋诗','song-poetry','','[]','窮冬欲去尚徘徊，獨坐頻斟守歲杯。',64,'全唐诗/poet.song.91000.json','["窮冬欲去尚徘徊，獨坐頻斟守歲杯。", "一夜臘寒隨漏盡，十分春色破朝來。", "桃符自寫新翻句，玉律誰吹定等灰。", "且是作詩人未老，換年添歲莫相催。"]'),
('8a045671-b5df-4601-9c09-da1bd52e18a7','湖上小集','朱淑真','宋','宋诗','song-poetry','','[]','門前春水碧於天，坐上詩人逸似仙。',32,'全唐诗/poet.song.91000.json','["門前春水碧於天，坐上詩人逸似仙。", "白璧一雙無玷缺，吹簫歸去又無緣。"]'),
('d405a195-fd31-420b-a99f-cba5b8fa0746','下湖即事','朱淑真','宋','宋诗','song-poetry','','[]','晴波碧漾浸春空，邃館清寒柳曳風。',32,'全唐诗/poet.song.91000.json','["晴波碧漾浸春空，邃館清寒柳曳風。", "隔岸誰家修竹外，杏花斜裊一枝紅。"]'),
('9a27ce66-8c19-45e2-8a5d-7d89db3e3315','西樓寄情','朱淑真','宋','宋诗','song-poetry','','[]','靜看飛蠅觸曉窗，宿酲未醒卷梳粧。',32,'全唐诗/poet.song.91000.json','["靜看飛蠅觸曉窗，宿酲未醒卷梳粧。", "強調朱粉西樓上，愁裏春山畫不長。"]'),
('4790a3f6-c4c0-4e54-ad4a-4efc9ab2a93a','書窗即事二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','花落春無語，春歸鳥自啼。',24,'全唐诗/poet.song.91000.json','["花落春無語，春歸鳥自啼。", "多情是蜂蝶，飛過粉牆西。"]'),
('b8dcc013-c2c7-4491-8a3f-20f30938778d','書窗即事二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','一陣催花雨，高低飛落紅。',24,'全唐诗/poet.song.91000.json','["一陣催花雨，高低飛落紅。", "榆錢空萬疊，買不住春風。"]'),
('06cb982e-be12-469d-9b0a-2c5c32f44413','夜留依綠亭  其一','朱淑真','宋','宋诗','song-poetry','','[]','水鳥棲煙夜不喧，風傳宮漏到湖邊。',32,'全唐诗/poet.song.91000.json','["水鳥棲煙夜不喧，風傳宮漏到湖邊。", "三更好月十分魄，萬里無雲一樣天。"]'),
('4be49296-aee4-44fd-a2d1-a4b5e3664ac6','夜留依綠亭  其二','朱淑真','宋','宋诗','song-poetry','','[]','雨換新涼秋興濃，流螢明滅綠楊中。',32,'全唐诗/poet.song.91000.json','["雨換新涼秋興濃，流螢明滅綠楊中。", "庭虛池印一方月，樓靜簷披四面風。"]'),
('68172152-cad5-493f-ab5b-b2ce19a8a04f','閑步','朱淑真','宋','宋诗','song-poetry','','[]','天街平貼淨無塵，燈火春搖不夜城。',32,'全唐诗/poet.song.91000.json','["天街平貼淨無塵，燈火春搖不夜城。", "乍得好涼宜散步，朦朧新月弄疏明。"]'),
('1f0af5bc-10e8-458c-a000-035bac735559','聞鵲','朱淑真','宋','宋诗','song-poetry','','[]','牆頭花外說新情，拔去閑愁著耳聽。',32,'全唐诗/poet.song.91000.json','["牆頭花外說新情，拔去閑愁著耳聽。", "青鳥已承雲信息，預先來報兩三聲。"]'),
('4498dd54-2829-476f-a0d8-2f1addaa4052','試墨','朱淑真','宋','宋诗','song-poetry','','[]','翠樓高壓浙山頭，海角湖光豁醉眸。',32,'全唐诗/poet.song.91000.json','["翠樓高壓浙山頭，海角湖光豁醉眸。", "萬景入簾吹不捲，一般心做百般愁。"]'),
('24ca7e54-5a41-424e-9448-c05079f353af','燈花','朱淑真','宋','宋诗','song-poetry','','[]','蘭釭和氣散氤氳，忽作元珠吐穗新。',64,'全唐诗/poet.song.91000.json','["蘭釭和氣散氤氳，忽作元珠吐穗新。", "膏脈破芽非藉手，敷芳成豔不關春。", "疑猜海角天涯事，攪亂衾寒枕冷人。", "我欲生憐心燄上，何妨好客致清貧。"]'),
('cfd1ea02-2c15-4802-9962-bde3245ff79a','書王庵道姑壁','朱淑真','宋','宋诗','song-poetry','','[]','短短牆圍小小亭，半簷疏玉響泠泠。',32,'全唐诗/poet.song.91000.json','["短短牆圍小小亭，半簷疏玉響泠泠。", "塵飛不到人長靜，一篆爐煙兩卷經。"]'),
('c209e1f8-a615-4e0a-9365-af97b5f24266','東馬塍','朱淑真','宋','宋诗','song-poetry','','[]','一塍芳草碧芋芋，活水穿花暗護田。',32,'全唐诗/poet.song.91000.json','["一塍芳草碧芋芋，活水穿花暗護田。", "蠶事正忙農事急，不知春色爲誰妍。"]'),
('9b0e894e-99ba-40bc-a042-0373f119b9fc','墨梅','朱淑真','宋','宋诗','song-poetry','','[]','若箇龍眠手，能傳處士詩。',48,'全唐诗/poet.song.91000.json','["若箇龍眠手，能傳處士詩。", "借他窗上影，寫作雪中枝。", "頃刻回春色，輕盈動玉巵。", "不能殷七七，橫笛月中吹。"]'),
('7d4ab74b-5dfd-444e-bbfc-edd70ed85c78','月臺','朱淑真','宋','宋诗','song-poetry','','[]','下視紅塵意眇然，翠欄十二出雲顛。',32,'全唐诗/poet.song.91000.json','["下視紅塵意眇然，翠欄十二出雲顛。", "縱眸愈覺心寬大，碧落無垠繞地圓。"]'),
('febee654-ce55-43d0-a1c0-f9c8cb1b6d74','雲掩半月','朱淑真','宋','宋诗','song-poetry','','[]','霜月迎寒著意圓，橫天雲浪礙嬋娟。',32,'全唐诗/poet.song.91000.json','["霜月迎寒著意圓，橫天雲浪礙嬋娟。", "嫦娥未肯全梳掠，玉鑒先教露半邊。"]'),
('987b59eb-a28b-460b-8675-de37f927f469','傷別二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','覽鏡驚容卻自嫌，逢春長盡病懨懨。',64,'全唐诗/poet.song.91000.json','["覽鏡驚容卻自嫌，逢春長盡病懨懨。", "吹花弄粉新來懶，惹恨供愁舊日添。", "生怕子規聲到耳，苦羞雙燕影穿簾。", "眉頭眼底無他事，須信離情一味嚴。"]'),
('231890a7-26ef-4cd5-aa44-f10b90b3648c','傷別二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','雙燕呢喃語畫梁，勸人休恁苦思量。',64,'全唐诗/poet.song.91000.json','["雙燕呢喃語畫梁，勸人休恁苦思量。", "逢春觸處須縈恨，對景無時不斷腸。", "寒食梨花新月夜，黄昏楊柳舊風光。", "繁華種種成愁恨，最是西樓近夕陽。"]'),
('02a26a77-f929-4c45-ad77-8f7ec63308f8','訴愁','朱淑真','宋','宋诗','song-poetry','','[]','苦沒心情只愛眠，夢魂還又到愁邊。',64,'全唐诗/poet.song.91000.json','["苦沒心情只愛眠，夢魂還又到愁邊。", "舊家庭院春長鎖，今夜樓臺月正圓。", "錦夜樓臺雙鳳带，獸爐閑爇水沉煙。", "良辰美景俱成恨，莫問新年與舊年。"]'),
('f71661c4-f3e1-47a6-b66c-4cdb67ae1796','愁懷二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','鷗鷺鴛鴦作一池，須知羽翼不相宜。',32,'全唐诗/poet.song.91000.json','["鷗鷺鴛鴦作一池，須知羽翼不相宜。", "東君不與花爲主，何似休生連理枝。"]'),
('6eb9ba53-d80d-449f-8da9-33f107453ec6','愁懷二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','滿眼春光色色新，花紅柳綠總關情。',32,'全唐诗/poet.song.91000.json','["滿眼春光色色新，花紅柳綠總關情。", "欲將鬰結心頭事，付與黄鸝叫幾聲。"]'),
('4cf0e60d-6026-4df7-8388-04a3cb32bf20','舊愁二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','銀屏屈曲障春風，獨抱寒衾睡正濃。',32,'全唐诗/poet.song.91000.json','["銀屏屈曲障春風，獨抱寒衾睡正濃。", "啼鳥一聲驚夢破，亂愁依舊鎖眉峰。"]'),
('6848512b-a725-478b-8cb0-0ceeb4f03d05','舊愁二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','花影重重疊綺窗，篆煙飛上枕屏香。',32,'全唐诗/poet.song.91000.json','["花影重重疊綺窗，篆煙飛上枕屏香。", "無情鶯舌驚春夢，喚起愁人對夕陽。"]'),
('1650ddf9-c96c-49cf-9906-8f1ea83c5233','供愁','朱淑真','宋','宋诗','song-poetry','','[]','寂寂疏簾掛玉樓，樓頭新月曲如鈎。',32,'全唐诗/poet.song.91000.json','["寂寂疏簾掛玉樓，樓頭新月曲如鈎。", "不須問我情深淺，鈎動長天遠水愁。"]'),
('1233f2a7-6ef5-4a0a-a154-55f66bb89368','恨別','朱淑真','宋','宋诗','song-poetry','','[]','調朱弄粉總無心，瘦覺寬餘纏臂金。',32,'全唐诗/poet.song.91000.json','["調朱弄粉總無心，瘦覺寬餘纏臂金。", "別後大拚憔悴損，思情未抵此情深。"]'),
('37bb370e-631c-4719-927e-68ad9ca314b5','寄恨','朱淑真','宋','宋诗','song-poetry','','[]','如毛細雨藹遙空，偏與花枝著意紅。',64,'全唐诗/poet.song.91000.json','["如毛細雨藹遙空，偏與花枝著意紅。", "人自多愁春自好，天應不語悶應同。", "吟牋謾有千篇苦，心事全無一點通。", "窗外數聲新百舌，喚回楊柳正眠中。"]'),
('8f9bb1c0-9b51-42f5-a093-62ba67901efb','寄情','朱淑真','宋','宋诗','song-poetry','','[]','欲寄相思滿紙愁，魚沉雁杳又還休。',32,'全唐诗/poet.song.91000.json','["欲寄相思滿紙愁，魚沉雁杳又還休。", "分明此去無多地，如在天涯無盡頭。"]'),
('60d9763e-5ce8-40fa-a3ff-e984dabdbc5b','無寐二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','吹徹雲簫夜未賒，梨花带月映窗紗。',32,'全唐诗/poet.song.91000.json','["吹徹雲簫夜未賒，梨花带月映窗紗。", "休將往事思量遍，瀲灧新愁亂似麻。"]'),
('65510b03-efbb-4732-8a16-027a7489c4b3','無寐二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','背彈珠淚暗傷神，挑盡寒燈睡不成。',32,'全唐诗/poet.song.91000.json','["背彈珠淚暗傷神，挑盡寒燈睡不成。", "卸卻鳳釵尋睡去，上牀開眼到天明。"]'),
('ff493d0c-6305-4a08-810f-ae5e672bfd7f','酒醒','朱淑真','宋','宋诗','song-poetry','','[]','夢回酒醒嚼盂冰，侍女貪眠喚不應。',32,'全唐诗/poet.song.91000.json','["夢回酒醒嚼盂冰，侍女貪眠喚不應。", "瘦㾪江梅知我意，隔窗和月謾騰騰。"]'),
('b900fb56-f806-4d32-8b1f-d7a9be693c7a','睡起二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','起來不喜勻紅粉，強把菱花照病容。',32,'全唐诗/poet.song.91000.json','["起來不喜勻紅粉，強把菱花照病容。", "腰瘦故知閑事惱，淚多隻爲別情濃。"]'),
('0ec7d28d-ca38-4fe7-b6a1-e92c17ad5f0b','睡起二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','懶對粧臺指黛眉，任他雙鬢向煙垂。',32,'全唐诗/poet.song.91000.json','["懶對粧臺指黛眉，任他雙鬢向煙垂。", "侍兒全不知人意，猶把梅花插一枝。"]'),
('eb8fe3f9-b8ab-4794-8025-d2ad8b929c53','清瘦','朱淑真','宋','宋诗','song-poetry','','[]','春花秋月若浮漚，怎得心如不繫舟。',32,'全唐诗/poet.song.91000.json','["春花秋月若浮漚，怎得心如不繫舟。", "肌骨大都無一把，可憐禁駕許多愁。"]'),
('901f5e31-1665-41ed-88b3-0ab58ba69aa5','悶書','朱淑真','宋','宋诗','song-poetry','','[]','淚粉勻開滿鏡愁，麝煤拂斷遠山秋。',32,'全唐诗/poet.song.91000.json','["淚粉勻開滿鏡愁，麝煤拂斷遠山秋。", "一痕心寄銀屏上，不見人來竹葉舟。"]'),
('78da9070-c239-4036-b4e4-48f99fd255c9','掬水月在手','朱淑真','宋','宋诗','song-poetry','','[]','無事江頭弄碧波，分明掌上見嫦娥。',32,'全唐诗/poet.song.91000.json','["無事江頭弄碧波，分明掌上見嫦娥。", "不知李謫仙人在，曾向江頭捉得麽。"]'),
('dc5eb226-1be3-4a3f-9939-2aa7188d51da','弄花香滿衣','朱淑真','宋','宋诗','song-poetry','','[]','豔紅影裏擷芳回，沾惹春風兩袖歸。',32,'全唐诗/poet.song.91000.json','["豔紅影裏擷芳回，沾惹春風兩袖歸。", "夾路露桃渾欲笑，不禁蜂蝶繞人飛。"]'),
('9630a8b8-a120-4752-8986-65645a3423c6','會魏夫人席上命小鬟妙舞曲終求詩于予以飛雪滿群山爲韻作五絕  其一','朱淑真','宋','宋诗','song-poetry','','[]','管弦催上錦裀時，體段輕盈祇欲飛。',32,'全唐诗/poet.song.91000.json','["管弦催上錦裀時，體段輕盈祇欲飛。", "若使明皇當日見，阿蠻無計況楊妃。"]'),
('cc5d7efe-c48f-4f9b-b15f-30e38ec322a0','會魏夫人席上命小鬟妙舞曲終求詩于予以飛雪滿群山爲韻作五絕  其二','朱淑真','宋','宋诗','song-poetry','','[]','香茵穩襯半鈎月，來往淩波雲影滅。',32,'全唐诗/poet.song.91000.json','["香茵穩襯半鈎月，來往淩波雲影滅。", "弦催緊拍捉將遍，兩袖翻然做迴雪。"]'),
('2444adc8-c7c3-44cf-9b23-8ad26c75ccb3','會魏夫人席上命小鬟妙舞曲終求詩于予以飛雪滿群山爲韻作五絕  其三','朱淑真','宋','宋诗','song-poetry','','[]','柳腰不被春拘管，鳳轉鸞回霞袖緩。',32,'全唐诗/poet.song.91000.json','["柳腰不被春拘管，鳳轉鸞回霞袖緩。", "舞徹伊州力不禁，筵前撲簌花飛滿。"]'),
('d2c865a4-7085-4b6a-876c-f3ebe3e88d88','會魏夫人席上命小鬟妙舞曲終求詩于予以飛雪滿群山爲韻作五絕  其四','朱淑真','宋','宋诗','song-poetry','','[]','占斷京華第一春，清歌妙舞實超群。',32,'全唐诗/poet.song.91000.json','["占斷京華第一春，清歌妙舞實超群。", "只愁到曉人星散，化作巫山一段雲。"]'),
('7be7482a-62d2-4b62-a372-cac230f56894','會魏夫人席上命小鬟妙舞曲終求詩于予以飛雪滿群山爲韻作五絕  其五','朱淑真','宋','宋诗','song-poetry','','[]','燭花影裏粉姿閑，一點愁侵兩點山。',32,'全唐诗/poet.song.91000.json','["燭花影裏粉姿閑，一點愁侵兩點山。", "不怕带他飛燕妬，無言相逐省弓彎。"]'),
('f012cfc0-1d8b-4550-a648-8c95c70ffc1d','讀史','朱淑真','宋','宋诗','song-poetry','','[]','筆頭去取萬千端，後世遭它恣意瞞。',32,'全唐诗/poet.song.91000.json','["筆頭去取萬千端，後世遭它恣意瞞。", "王霸謾分心與迹，到成功處一般難。"]'),
('8102e79f-a117-4715-9334-cb80419731d9','圓子','朱淑真','宋','宋诗','song-poetry','','[]','輕圓絕勝雞頭肉，滑膩偏宜蟹眼湯。',32,'全唐诗/poet.song.91000.json','["輕圓絕勝雞頭肉，滑膩偏宜蟹眼湯。", "縱有風流無處說，已輸湯餅試何郎。"]'),
('68894ba0-149e-447d-bec6-7cd6205381e8','即事','朱淑真','宋','宋诗','song-poetry','','[]','旋粧冷火試龍涎，香繞屏山不動煙。',32,'全唐诗/poet.song.91000.json','["旋粧冷火試龍涎，香繞屏山不動煙。", "簾幕半垂燈燭暗，酒闌時節未忺眠。"]'),
('95d17ef6-21b7-48da-8b9d-92d0bcf3b913','自責二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','女子弄文誠可罪，那堪詠月更吟風。',32,'全唐诗/poet.song.91000.json','["女子弄文誠可罪，那堪詠月更吟風。", "磨穿鐵硯成何事，繡折金鍼卻有功。"]'),
('69c396ba-6f3b-4b6d-b6ae-8358c6995481','自責二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','悶無消遣只看詩，又見詩中話別離。',32,'全唐诗/poet.song.91000.json','["悶無消遣只看詩，又見詩中話別離。", "添得情懷轉蕭索，如知伶俐不如癡。"]'),
('06645b62-fd1b-4475-8863-cce79fd5e8f5','浴罷','朱淑真','宋','宋诗','song-poetry','','[]','浴罷雲鬟亂不梳，清癯無力氣方蘇。',32,'全唐诗/poet.song.91000.json','["浴罷雲鬟亂不梳，清癯無力氣方蘇。", "坐來始覺神魂定，尚怯涼風到坐隅。"]'),
('54d168da-2299-42fb-95fe-f3cd578fa029','宴謝夫人堂','朱淑真','宋','宋诗','song-poetry','','[]','竹引清風入酒巵，森森涼氣暗侵肌。',32,'全唐诗/poet.song.91000.json','["竹引清風入酒巵，森森涼氣暗侵肌。", "冰巒四疊渾無暑，不似人間六月時。"]'),
('43fb4aef-5a49-411e-a3ea-01b987b5e51a','吊林和靖二者  其一','朱淑真','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不見孤山處士星，西湖風月爲誰清。',32,'全唐诗/poet.song.91000.json','["不見孤山處士星，西湖風月爲誰清。", "當時寂寞冰霜下，兩句詩成萬古名。"]'),
('8a753e35-e049-4236-aa9f-e9c68a92bc8c','吊林和靖二者  其二','朱淑真','宋','宋诗','song-poetry','','[]','短篷載影夜歸時，月白風清易得詩。',32,'全唐诗/poet.song.91000.json','["短篷載影夜歸時，月白風清易得詩。", "不識酌泉拈菊意，一庭寒翠藹空祠。"]'),
('50447cbe-b92c-48e6-934e-41d4aab747c2','答求譜','朱淑真','宋','宋诗','song-poetry','','[]','雨好解開花百結，風恬扶起柳三眠。',32,'全唐诗/poet.song.91000.json','["雨好解開花百結，風恬扶起柳三眠。", "春醲釅處多傷感，那得心情事管弦。"]'),
('573f4361-c418-4009-aee6-78a27fa1606b','得家嫂書','朱淑真','宋','宋诗','song-poetry','','[]','聲聲喜報鵲溫柔，忽接芳緘自便郵。',64,'全唐诗/poet.song.91000.json','["聲聲喜報鵲溫柔，忽接芳緘自便郵。", "一尺溪藤摛錦带，數行香墨健銀鉤。", "傾心吐盡重重恨，入眼翻成字字愁。", "添得情懷無是處，非干病酒與悲秋。"]'),
('03fdc5db-f461-47eb-9ebe-93e2c5cdce30','新春二絕  其一','朱淑真','宋','宋诗','song-poetry','','[]','雪從庾嶺梅中盡，春向隋提柳上來。',32,'全唐诗/poet.song.91000.json','["雪從庾嶺梅中盡，春向隋提柳上來。", "多少園林正蕭索，紛紛爭逐趁時開。"]'),
('4f1a32c8-fc40-4b21-94ed-3cd1e396127a','新春二絕  其二','朱淑真','宋','宋诗','song-poetry','','[]','黄宮陽氣幾潛伸，玉管吹灰適報春。',32,'全唐诗/poet.song.91000.json','["黄宮陽氣幾潛伸，玉管吹灰適報春。", "天子只知農事重，躬耕端的爲吾民。"]'),
('043fbe0f-9223-42e5-9983-f7092769a5a0','春日有作','朱淑真','宋','宋诗','song-poetry','','[]','景近清明節，垂楊翠縷長。',48,'全唐诗/poet.song.91000.json','["景近清明節，垂楊翠縷長。", "塞鴻歸朔漠，海燕度瀟湘。", "花麗繁爭錦，鶯嬌巧轉簧。", "西園正明媚，收拾入吟鄉。"]'),
('944b0566-744f-40db-b306-55edba97a0e0','早春喜晴即事','朱淑真','宋','宋诗','song-poetry','','[]','山明雪盡翠嵐深，天闊雲開斷翳陰。',64,'全唐诗/poet.song.91000.json','["山明雪盡翠嵐深，天闊雲開斷翳陰。", "漠漠暖煙生草木，薰薰和氣動園林。", "詩書遣興消長日，景物牽情入苦吟。", "金鴨火殘香閣靜，更調商羽弄瑤琴。"]'),
('96a88b60-1d49-4ee6-8e60-2da589400c60','春晴','朱淑真','宋','宋诗','song-poetry','','[]','日暖風和明媚天，最宜吟詠入詩篇。',64,'全唐诗/poet.song.91000.json','["日暖風和明媚天，最宜吟詠入詩篇。", "庭花吐蕊紅如錦，岸柳飛絲白似錦。", "深院雕梁巢燕返，高林喬木谷鶯遷。", "韶光正近清明節，花塢樓臺酒旆懸。"]'),
('1c408f43-7e1a-4b72-9c68-79ec9a7183a2','春日行','朱淑真','宋','宋诗','song-poetry','','[]','春雲漠漠連春空，映階草色綠茸茸。',160,'全唐诗/poet.song.91000.json','["春雲漠漠連春空，映階草色綠茸茸。", "不寒不暖雨新霽，滿城佳氣浮葱葱。", "岸柳依依微煙籠，園林淡蕩催花風。", "東君造化一何工，施青繪紫複勻紅。", "多少閑花與凡卉，不論妍醜爭夭穠。", "燕舞鶯歌晝晷永，簾幕無人門宇靜。", "何處飛來雙蛺蝶，翻翻飛入尋香徑。", "可憐春色都九旬，朝歡暮宴歸王孫。", "禿毫寫紙屬詩人，長歌短什勞精神。", "長歌短什聊自適，豈有佳句生陽春。"]'),
('55f8d25f-a283-4d5d-863b-cbbd3ae238b4','春遊西園','朱淑真','宋','宋诗','song-poetry','','[]','閑步西園裏，春風明媚天。',48,'全唐诗/poet.song.91000.json','["閑步西園裏，春風明媚天。", "蝶疑莊叟夢，絮憶謝娘聯。", "踏草青茵軟，看花紅錦鮮。", "徘徊月影下，欲去又依然。"]'),
('34184800-579f-4e57-8701-988bb246a15c','春園小宴','朱淑真','宋','宋诗','song-poetry','','[]','春園得對賞芳菲，步草黏鞋絮點衣。',64,'全唐诗/poet.song.91000.json','["春園得對賞芳菲，步草黏鞋絮點衣。", "萬木初陰鶯百轉，千花乍拆蝶雙飛。", "牽情自覺詩毫健，痛飲惟優酒力微。", "窮日追歡歡不足，恨無爲計鎖斜暉。"]'),
('ee46c6f6-ec2e-4f91-b480-e7e19f95ce0d','春日書懷','朱淑真','宋','宋诗','song-poetry','','[]','從宦東西不自由，親幃千里淚長流。',64,'全唐诗/poet.song.91000.json','["從宦東西不自由，親幃千里淚長流。", "已無鴻雁傳家信，更被杜鵑追客愁。", "日暖鳥歌空美景，花光柳影謾盈眸。", "高樓惆悵憑闌久，心逐白雲南向浮。"]'),
('8d924e96-21de-4543-aa7b-f3d6e1e4d11d','春日亭上觀魚','朱淑真','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春暖長江水正清，洋洋得意漾波生。',32,'全唐诗/poet.song.91000.json','["春暖長江水正清，洋洋得意漾波生。", "非無欲透龍門志，只待新雷震一聲。"]'),
('8723f9e7-822d-4c19-9319-2c0dfe83f2da','春晝偶成','朱淑真','宋','宋诗','song-poetry','','[]','默默深閨掩晝關，簡編盈案小窗寒。',32,'全唐诗/poet.song.91000.json','["默默深閨掩晝關，簡編盈案小窗寒。", "卻嗟流水琴中意，難向人前取次彈。"]'),
('6033571c-3e6d-4d61-9ae6-ffd92b22aec1','春日雜興','朱淑真','宋','宋诗','song-poetry','','[]','窈窕風光艷艷春，無言桃李一番新。',64,'全唐诗/poet.song.91000.json','["窈窕風光艷艷春，無言桃李一番新。", "青回野燒草初染，光泛幽香蘭可紉。", "官柳欲眠多態度，海棠貪睡足精神。", "舊遊似夢渾情懶，對景無聊愁殺人。"]'),
('fcf52009-7297-4dec-98ac-9004f6a116a9','立春日粧成宜春花','朱淑真','宋','宋诗','song-poetry','','[]','青旛碧勝縷金文，柳色梅花逐指新。',32,'全唐诗/poet.song.91000.json','["青旛碧勝縷金文，柳色梅花逐指新。", "卻笑尚爲兒女態，寶刀剪綵強爲春。"]'),
('65155a77-0770-4288-9847-f3f469ca0335','春曉雜興','朱淑真','宋','宋诗','song-poetry','','[]','挑盡殘燈夢欲迷，子規催月小樓西。',32,'全唐诗/poet.song.91000.json','["挑盡殘燈夢欲迷，子規催月小樓西。", "紗窗偷眼天將曉，無數宿禽花下啼。"]'),
('3d2f49ec-ec9f-42f4-81a9-696bc287e30c','寒食詠懷','朱淑真','宋','宋诗','song-poetry','','[]','淮南寒食更風流，絲管紛紛逐勝遊。',32,'全唐诗/poet.song.91000.json','["淮南寒食更風流，絲管紛紛逐勝遊。", "春色眼前無限好，思親懷土自多愁。"]'),
('6a7f74f0-fa10-4d0d-8264-2ee11f624eef','春燕','朱淑真','宋','宋诗','song-poetry','','[]','簾前日暖翩翩過，簾外風輕對對斜。',32,'全唐诗/poet.song.91000.json','["簾前日暖翩翩過，簾外風輕對對斜。", "偏是社來還社去，年年不見蠟梅花。"]'),
('0b7ad411-cbd7-45e9-ab38-b03380e52aad','春夜感懷','朱淑真','宋','宋诗','song-poetry','','[]','清江碧草兩悠悠，各自風流一種愁。',32,'全唐诗/poet.song.91000.json','["清江碧草兩悠悠，各自風流一種愁。", "正是落花寒食夜，夜深無伴倚空樓。"]'),
('9a29651a-6447-4804-8a1f-1c5a2b31c6a8','獨坐感春','朱淑真','宋','宋诗','song-poetry','','[]','翠密藏鴉綠柳提，傷春懶矣步桃溪。',32,'全唐诗/poet.song.91000.json','["翠密藏鴉綠柳提，傷春懶矣步桃溪。", "夢回窗下日當午，鶗鴂一聲林外啼。"]'),
('9a3276de-2f8d-4e60-ad44-6be1cde97e14','暮春有感','朱淑真','宋','宋诗','song-poetry','','[]','倦對飄零滿徑花，靜聞春水鬧鳴蛙。',32,'全唐诗/poet.song.91000.json','["倦對飄零滿徑花，靜聞春水鬧鳴蛙。", "故人何處草空碧，撩亂寸心天一涯。"]'),
('29bda1b8-edcf-467f-b57c-5297f2271ad5','夏日作','朱淑真','宋','宋诗','song-poetry','','[]','東風迤邐轉南風，萬物全歸長養功。',32,'全唐诗/poet.song.91000.json','["東風迤邐轉南風，萬物全歸長養功。", "舜豈無心阜民俗，薰薰歌入五絃中。"]'),
('fc3f2fe6-cad1-4d87-b326-f5c0718d224f','暑月獨眠','朱淑真','宋','宋诗','song-poetry','','[]','紗幮困臥日初長，解卻紅裙小罩涼。',32,'全唐诗/poet.song.91000.json','["紗幮困臥日初長，解卻紅裙小罩涼。", "一篆爐煙籠午枕，冰肌生汗白蓮香。"]'),
('ed81a598-bc94-4511-85d0-6663fb6cf750','暑夜','朱淑真','宋','宋诗','song-poetry','','[]','水亭相對已黄昏，靜數飛螢過小園。',32,'全唐诗/poet.song.91000.json','["水亭相對已黄昏，靜數飛螢過小園。", "窗下孤燈自明滅，無陶獨自懶扃門。"]'),
('2b14b847-0fdf-400a-becf-0e9edf3b1277','夏夜有作','朱淑真','宋','宋诗','song-poetry','','[]','暑夕炎蒸著摸人，移牀借月臥中庭。',32,'全唐诗/poet.song.91000.json','["暑夕炎蒸著摸人，移牀借月臥中庭。", "更深露下衣襟冷，夢到陽臺不奈醒。"]'),
('b53b649a-16aa-4a67-bfed-586b608fd0ee','夏夜乘涼','朱淑真','宋','宋诗','song-poetry','','[]','滿意好風生水面，趁人明月到天心。',32,'全唐诗/poet.song.91000.json','["滿意好風生水面，趁人明月到天心。", "此時情緒誰能會，獨坐中庭夜已深。"]'),
('a080192f-72be-43d4-924a-7b0d4384373f','夏枕自詠','朱淑真','宋','宋诗','song-poetry','','[]','夏日初長候，風櫺暑夕眠。',48,'全唐诗/poet.song.91000.json','["夏日初長候，風櫺暑夕眠。", "衣輕香汗透，睡重翠鬟偏。", "顰綠攢眉小，啼紅上臉鮮。", "起來無箇事，纖手弄清泉。"]'),
('5980d9dd-c74d-49e3-b8fc-3c6727710803','遊湖歸晚','朱淑真','宋','宋诗','song-poetry','','["\u897f\u6e56"]','戀戀西湖景，山頭带夕陽。',48,'全唐诗/poet.song.91000.json','["戀戀西湖景，山頭带夕陽。", "歸禽翻竹露，落果響芹塘。", "葉倚風中靜，魚遊水底涼。", "半亭明月色，荷氣惱人香。"]'),
('38bb309f-2429-4265-9400-5278b953831f','西樓納涼','朱淑真','宋','宋诗','song-poetry','','[]','小閣對芙蕖，囂塵一點無。',24,'全唐诗/poet.song.91000.json','["小閣對芙蕖，囂塵一點無。", "水風涼枕罩，雪葛爽肌膚。"]'),
('d119676f-1d16-430a-a582-bd358df843ec','夏日游水閣','朱淑真','宋','宋诗','song-poetry','','[]','淡紅衫子透肌膚，夏日初長水閣虛。',32,'全唐诗/poet.song.91000.json','["淡紅衫子透肌膚，夏日初長水閣虛。", "獨自憑闌無箇事，水風涼處讀文書。"]'),
('811e5cae-e5e7-4230-9540-7784fcf8d476','秋日晚望','朱淑真','宋','宋诗','song-poetry','','[]','極目寒郊外，晚來微雨收。',48,'全唐诗/poet.song.91000.json','["極目寒郊外，晚來微雨收。", "隴頭霞散綺，天際月懸鈎。", "一字新鴻度，千聲落葉秋。", "倚樓堪聽處，玉笛在漁舟。"]'),
('b6cd7194-0de4-4c63-a639-0d2d5ce6b078','秋日行','朱淑真','宋','宋诗','song-poetry','','[]','蕭瑟西風起何處，庭前葉葉驚梧樹。',128,'全唐诗/poet.song.91000.json','["蕭瑟西風起何處，庭前葉葉驚梧樹。", "萬物收成天地肅，田家芋栗初登圃。", "杳杳高穹片水清，一點秋鵰翥雲路。", "淒淒空曠雨初晴，涼飇動地收殘暑。", "高樓玉笛應清商，天外數聲新雁度。", "園林草木半含黄，籬菊黄金花正吐。", "池上枯楊噪晚蟬，愁蓮蔌蔌啼殘露。", "可憐秋色與春風，幾度榮枯新復故。"]'),
('ac01977f-ca51-43f6-b2ef-d7ed0dbc0d61','秋日偶題','朱淑真','宋','宋诗','song-poetry','','[]','芙蓉斜倚胭脂臉，巖桂輕搖金粟花。',32,'全唐诗/poet.song.91000.json','["芙蓉斜倚胭脂臉，巖桂輕搖金粟花。", "愁思不知秋浩蕩，一鞭逸興繞天涯。"]'),
('24d3adfe-f252-449d-b0b2-221f412aa13e','早秋偶筆','朱淑真','宋','宋诗','song-poetry','','[]','肅肅涼風至，淒然景驟清。',48,'全唐诗/poet.song.91000.json','["肅肅涼風至，淒然景驟清。", "雨餘殘暑退，日落晚涼生。", "鷹隼雙睛轉，梧桐一葉驚。", "試聽松竹裏，萬籟起秋聲。"]'),
('8d993102-98cd-4981-8c02-19ccb8f816a9','七夕口占','朱淑真','宋','宋诗','song-poetry','','[]','三秋靈匹此宵期，萬古傳聞果是非。',32,'全唐诗/poet.song.91000.json','["三秋靈匹此宵期，萬古傳聞果是非。", "免俗未能還自笑，金鍼乞得巧絲歸。"]'),
('32d8fa6e-f893-42e0-8014-c33d3ea09de8','新秋','朱淑真','宋','宋诗','song-poetry','','[]','一夜涼風動扇愁，背時容易入新秋。',32,'全唐诗/poet.song.91000.json','["一夜涼風動扇愁，背時容易入新秋。", "桃花臉上汪汪淚，忍到更深枕上流。"]'),
('728550cd-4dc7-4451-9aab-43dada827c1b','初秋雨晴','朱淑真','宋','宋诗','song-poetry','','[]','雨後風涼暑氣收，庭梧葉葉報初秋。',32,'全唐诗/poet.song.91000.json','["雨後風涼暑氣收，庭梧葉葉報初秋。", "浮雲盡逐黄昏去，樓角新蟾掛玉鈎。"]'),
('c33ab30b-5b8f-42bc-8f2c-5fb862a78603','早秋有感','朱淑真','宋','宋诗','song-poetry','','[]','西風淅淅收殘暑，庭竹蕭疏報早秋。',32,'全唐诗/poet.song.91000.json','["西風淅淅收殘暑，庭竹蕭疏報早秋。", "砌下黄昏微雨後，幽蛩唧唧使人愁。"]'),
('71993ebd-087c-4674-8b3a-f5ee321c6d1a','秋樓晚望','朱淑真','宋','宋诗','song-poetry','','[]','涼吹晚颼颼，蘆花兩岸秋。',24,'全唐诗/poet.song.91000.json','["涼吹晚颼颼，蘆花兩岸秋。", "夕陽樓上望，獨倚淚偷流。"]'),
('6c10c054-ea66-4c92-a5df-24c5946f33e3','對秋有感','朱淑真','宋','宋诗','song-poetry','','[]','風倍淒涼月倍明，人間占得十分清。',32,'全唐诗/poet.song.91000.json','["風倍淒涼月倍明，人間占得十分清。", "可憐宋玉多才子，只爲多情苦愴情。"]'),
('229ba027-dc84-4257-87b2-2756a092fd94','秋夜舟行宿前江','朱淑真','宋','宋诗','song-poetry','','[]','扁舟夜泊月明秋，水面魚遊趁閘流。',32,'全唐诗/poet.song.91000.json','["扁舟夜泊月明秋，水面魚遊趁閘流。", "更作嬌癡兒女態，笑將竿竹擲絲鈎。"]'),
('1ef6c575-78a0-4fef-af96-dc5ac1c41ff7','中秋夜家宴詠月','朱淑真','宋','宋诗','song-poetry','','[]','九秋三五夕，此夕正秋中。',48,'全唐诗/poet.song.91000.json','["九秋三五夕，此夕正秋中。", "天意一夜別，人心千古同。", "清光消霧靄，皓色遍高空。", "願把團圓盞，年年對兔宮。"]'),
('ba44c03f-c4fc-45d1-bb25-30f6965af7c4','中秋夜不見月','朱淑真','宋','宋诗','song-poetry','','[]','不許蟾蜍此夜明，始知天意是無情。',32,'全唐诗/poet.song.91000.json','["不許蟾蜍此夜明，始知天意是無情。", "何當拔去閑雲霧，放出光輝萬里清。"]'),
('9b90f62c-2919-4568-93f7-bf36e262fb7d','中秋月','朱淑真','宋','宋诗','song-poetry','','[]','杳杳長空斂霧煙，冰輸都勝別時圓。',32,'全唐诗/poet.song.91000.json','["杳杳長空斂霧煙，冰輸都勝別時圓。", "風傳漏報天將曉，惆悵嬋娟又隔年。"]'),
('89f58d4f-4f0e-4307-889c-bf70ae8933ca','中秋玩月','朱淑真','宋','宋诗','song-poetry','','[]','獨占秋光盛，天工信有偏。',48,'全唐诗/poet.song.91000.json','["獨占秋光盛，天工信有偏。", "清暉千里共，皓魄十分圓。", "兔影寒猶弄，蟾蜍老更堅。", "只愁看未足，一去又輕年。"]'),
('9f5d3b6c-0788-49f3-8342-039f9d9264bd','湖上詠月','朱淑真','宋','宋诗','song-poetry','','[]','清宵三五涼風發，湖上閑吟步明月。',48,'全唐诗/poet.song.91000.json','["清宵三五涼風發，湖上閑吟步明月。", "涓涓流水淺又清，皎潔長空纖靄滅。", "水光月色環相連，可憐清景兩奇絕。"]'),
('55ec2ade-a3bf-4d8a-b44e-afb77d24c514','秋夜感懷','朱淑真','宋','宋诗','song-poetry','','[]','滿院含秋思，蟾輝映一方。',48,'全唐诗/poet.song.91000.json','["滿院含秋思，蟾輝映一方。", "蛩吟喧曲砌，鳥宿傍回塘。", "木落桐應瘦，宵寒漏正長。", "安仁閑感慨，徒爾鬢蒼蒼。"]'),
('ecbe89a9-5398-4284-b091-adfb087b082d','小閣秋日詠雨','朱淑真','宋','宋诗','song-poetry','','[]','疏雨洗高穹，瀟瀟滴井桐。',48,'全唐诗/poet.song.91000.json','["疏雨洗高穹，瀟瀟滴井桐。", "潤煙生硯底，涼氣入堂中。", "翠鎖交竿竹，紅翻落葉楓。", "撫琴閑弄曲，靜坐理商宮。"]'),
('ede0ee61-9cbf-4e19-930f-3007ba175f5a','秋日得書','朱淑真','宋','宋诗','song-poetry','','[]','秋風本無意，愁思自難禁。',48,'全唐诗/poet.song.91000.json','["秋風本無意，愁思自難禁。", "共月傷千里，來書勝萬金。", "代騮驚北吹，越鳥戀南林。", "已有歸寧約，何須惜歲陰。"]'),
('b8d25efd-5f81-42d4-bc11-4bb93ba3d69f','秋深偶作','朱淑真','宋','宋诗','song-poetry','','[]','生殺循環本自然，可堪肅肅出乎天。',32,'全唐诗/poet.song.91000.json','["生殺循環本自然，可堪肅肅出乎天。", "休嗟物理易彫瘁，好看西成報有年。"]'),
('11d6149d-1a3a-49bd-9631-1e0a7b24c411','暮秋','朱淑真','宋','宋诗','song-poetry','','[]','瀟瀟風雨暗殘秋，忍見黄生滿徑幽。',32,'全唐诗/poet.song.91000.json','["瀟瀟風雨暗殘秋，忍見黄生滿徑幽。", "恰似楚人情太苦，年年對景倍添愁。"]'),
('7984886d-9d6c-4839-9f03-3a3b755d8b14','新冬','朱淑真','宋','宋诗','song-poetry','','[]','日一北而萬物生，始知天意在收成。',32,'全唐诗/poet.song.91000.json','["日一北而萬物生，始知天意在收成。", "愚民未論祁寒理，往往相爲嗟怨聲。"]'),
('0122f404-421a-40dd-9933-1c35bd9470a1','初冬書懷','朱淑真','宋','宋诗','song-poetry','','[]','觸目園池景，荷枯菊已荒。',48,'全唐诗/poet.song.91000.json','["觸目園池景，荷枯菊已荒。", "風寒侵夜枕，霜凍怯晨粧。", "江上楓翻赤，庭前橘带黄。", "題詩欲排悶，對景倍悲傷。"]'),
('7a7d6c51-2353-43f6-99ef-56559556ef3f','冬日離詠','朱淑真','宋','宋诗','song-poetry','','[]','愛日溫溫正滌場，老農擊壤慶時康。',64,'全唐诗/poet.song.91000.json','["愛日溫溫正滌場，老農擊壤慶時康。", "水催舂韻擣殘雨，風急耞聲带夕陽。", "霜瓦曉寒欺酒力，月欄夜冷動詩腸。", "厭厭對景無情緒，謾把梅花取次粧。"]'),
('f6febc53-93a5-461f-93cc-e41acb90276b','霜夜','朱淑真','宋','宋诗','song-poetry','','[]','彤雲黯黯暮天寒，半卷珠簾未欲眠。',32,'全唐诗/poet.song.91000.json','["彤雲黯黯暮天寒，半卷珠簾未欲眠。", "獨坐小窗無伴侶，可憐霜月向人圓。"]'),
('d3717566-9169-474e-a9d2-dd29cb4466a3','長宵','朱淑真','宋','宋诗','song-poetry','','[]','霜月照人悄，迢迢夜未闌。',24,'全唐诗/poet.song.91000.json','["霜月照人悄，迢迢夜未闌。", "鴛幃夢展轉，珠淚向誰彈。"]'),
('a02bf152-f13c-4893-b68b-7159d325c8a1','探梅','朱淑真','宋','宋诗','song-poetry','','[]','溫溫天氣似春和，試探寒梅已滿坡。',32,'全唐诗/poet.song.91000.json','["溫溫天氣似春和，試探寒梅已滿坡。", "笑折一枝插雲鬢，問人瀟灑似誰麼。"]'),
('c26b94de-3e74-428e-9440-0d6154f77317','冬至','朱淑真','宋','宋诗','song-poetry','','[]','黄鍾應律好風吹，陰伏陽升淑氣回。',64,'全唐诗/poet.song.91000.json','["黄鍾應律好風吹，陰伏陽升淑氣回。", "葵影便移日長至，梅花先趁小寒開。", "八神表日占和歲，六琯飛葭動細灰。", "已有岸旁迎臘柳，參差又欲領春來。"]'),
('c707ceb2-8393-4f6b-bbd1-200b9be0e9ed','觀雪偶成','朱淑真','宋','宋诗','song-poetry','','[]','憑闌觀雪獨徘徊，欲賦慚無詠絮才。',32,'全唐诗/poet.song.91000.json','["憑闌觀雪獨徘徊，欲賦慚無詠絮才。", "鹽撒空中如可用，收藏聊與贈羹梅。"]'),
('f35c16ae-5992-4b69-ad94-9a81731ab3b5','冬夜不寐','朱淑真','宋','宋诗','song-poetry','','[]','推枕鴛幃不奈寒，起來霜月轉闌干。',32,'全唐诗/poet.song.91000.json','["推枕鴛幃不奈寒，起來霜月轉闌干。", "悶懷脈脈與誰說，淚滴羅衣不忍看。"]'),
('83924c0c-33b9-4dac-a903-a514be477fe9','詠雪','朱淑真','宋','宋诗','song-poetry','','[]','六出飛花四面來，連山連水皓皚皚。',64,'全唐诗/poet.song.91000.json','["六出飛花四面來，連山連水皓皚皚。", "玲瓏天地蒼茫合，的皪園林爛漫開。", "庾嶺臘梅寒散亂，章臺風柳絮縈回。", "自言空有孤吟癖，覽景慚無謝氏才。"]'),
('4b97b8e1-0caa-4ca9-85a6-8deb9ed579eb','雪夜賡筆','朱淑真','宋','宋诗','song-poetry','','[]','夜雪飛花似月明，交連寒影透門庭。',32,'全唐诗/poet.song.91000.json','["夜雪飛花似月明，交連寒影透門庭。", "只宜挾策臨窗坐，免用辛勤更聚螢。"]'),
('555d392d-2a8f-4e3e-a3d2-1a5d8e6683fa','江上雪霽','朱淑真','宋','宋诗','song-poetry','','[]','江水冰消起綠鱗，川原蕩滌少煙塵。',32,'全唐诗/poet.song.91000.json','["江水冰消起綠鱗，川原蕩滌少煙塵。", "風吹南北溪橋畔，柳色參差欲漏春。"]'),
('43d45102-c7b9-47f3-ab0b-11ecf3fe7229','對雪一律','朱淑真','宋','宋诗','song-poetry','','[]','紛紛瑞雪壓山河，特出新奇和郢歌。',64,'全唐诗/poet.song.91000.json','["紛紛瑞雪壓山河，特出新奇和郢歌。", "樂道幽人方閉戶，高歌漁父正披蓑。", "自嗟老景光陰速，唯使佳時感愴多。", "更念鰥居憔悴客，映書無寐奈愁何。"]'),
('c1248667-abe4-434f-a130-3aa3eca9b58d','賞雪','朱淑真','宋','宋诗','song-poetry','','[]','朱簾暮卷綺筵開，風雪紛紛入酒杯。',32,'全唐诗/poet.song.91000.json','["朱簾暮卷綺筵開，風雪紛紛入酒杯。", "對景恨無飛絮句，從今羞見謝娘才。"]'),
('e663cb8b-ab49-43c4-870c-74c5aec1f939','圍爐','朱淑真','宋','宋诗','song-poetry','','[]','昨夜霜風透膽寒，圍爐漫意昔年歡。',32,'全唐诗/poet.song.91000.json','["昨夜霜風透膽寒，圍爐漫意昔年歡。", "如今獨坐無人說，撥悶惟憑酒力寬。"]'),
('d9c187d2-de86-40b3-a017-d83addb1ecf6','除夜','朱淑真','宋','宋诗','song-poetry','','[]','休嘆流光去，看看春欲回。',48,'全唐诗/poet.song.91000.json','["休嘆流光去，看看春欲回。", "椒盤卷紅燭，柏酒溢金杯。", "殘臘餘更盡，新年曉角催。", "爭先何物早，唯有後園梅。"]'),
('41e19b7f-c591-4c13-b574-28d9770bc429','海棠','朱淑真','宋','宋诗','song-poetry','','[]','天與嬌嬈綴作花，更於枝上散餘霞。',32,'全唐诗/poet.song.91000.json','["天與嬌嬈綴作花，更於枝上散餘霞。", "少陵漫道多詩興，不得當時一句誇。"]'),
('0997a3a6-e6cf-462d-973f-e1600b658156','芍藥','朱淑真','宋','宋诗','song-poetry','','[]','芬芳紅紫間成叢，獨占花王品第中。',32,'全唐诗/poet.song.91000.json','["芬芳紅紫間成叢，獨占花王品第中。", "到底只留爲謔贈，更勞國史刺民風。"]'),
('9e579f98-e2bd-4724-84be-23c746b014c5','牡丹','朱淑真','宋','宋诗','song-poetry','','[]','嬌嬈萬態逞殊芳，花品名中占得王。',32,'全唐诗/poet.song.91000.json','["嬌嬈萬態逞殊芳，花品名中占得王。", "莫把傾城比顔色，從來家國爲伊亡。"]'),
('5a088c40-d33c-46ac-9a32-b42ccc99808e','黄芙蓉','朱淑真','宋','宋诗','song-poetry','','[]','如何天賦與芬芳，徒作佳人淡竚粧。',32,'全唐诗/poet.song.91000.json','["如何天賦與芬芳，徒作佳人淡竚粧。", "試倩東風一爲主，輕黄應不讓姚黄。"]'),
('abddb44d-4e29-492d-a8ff-5fa15950e37c','長春花','朱淑真','宋','宋诗','song-poetry','','[]','一枝才謝一枝殷，自是春工不與閑。',32,'全唐诗/poet.song.91000.json','["一枝才謝一枝殷，自是春工不與閑。", "縱使牡丹稱絕豔，到頭榮瘁片時間。"]'),
('7ed31382-9ba0-450a-8367-cee14e808248','薔薇花  其一','朱淑真','宋','宋诗','song-poetry','','[]','飛葩散亂擁欄香，萬朵千枝不計行。',32,'全唐诗/poet.song.91000.json','["飛葩散亂擁欄香，萬朵千枝不計行。", "爛漫初開向清晝，會稽太守乍還鄉。"]'),
('705c920b-92bd-4b10-92ca-a6057182020e','薔薇花  其二','朱淑真','宋','宋诗','song-poetry','','[]','滿地紅影蘸秋光，始覺芙蓉植在旁。',32,'全唐诗/poet.song.91000.json','["滿地紅影蘸秋光，始覺芙蓉植在旁。", "賴有佳人頻醉賞，和將紅粉更施粧。"]'),
('c188dd39-68a7-4209-bcb2-a96fa7f23ee0','櫻桃','朱淑真','宋','宋诗','song-poetry','','[]','爲花結實自殊常，摘下盤中顆顆香。',32,'全唐诗/poet.song.91000.json','["爲花結實自殊常，摘下盤中顆顆香。", "味重不容輕衆口，獨於寢廟薦先嘗。"]'),
('d0c89ee5-893a-4e6f-8069-04efbd8b1856','梅花二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','園林蕭索未迎春，獨爾花開處處新。',32,'全唐诗/poet.song.91000.json','["園林蕭索未迎春，獨爾花開處處新。", "只有官娃無一事，每將施額鬬粧勻。"]'),
('909beb81-a423-4271-b30d-5ea1160ad8bf','梅花二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','消得騷人幾許時，疏籬淡月著橫枝。',32,'全唐诗/poet.song.91000.json','["消得騷人幾許時，疏籬淡月著橫枝。", "破荒的皪香隨馬，春信先教驛使知。"]'),
('73dc2b49-749b-411a-80f3-d6180988a57e','直竹','朱淑真','宋','宋诗','song-poetry','','[]','勁直忠臣節，孤高列女心。',24,'全唐诗/poet.song.91000.json','["勁直忠臣節，孤高列女心。", "四時同一色，霜雪不能侵。"]'),
('cf9a0e5d-1dd3-43e5-938f-9e367d7ca9d8','荷花','朱淑真','宋','宋诗','song-poetry','','[]','暑氣炎炎正若焚，荷花於此見天真。',64,'全唐诗/poet.song.91000.json','["暑氣炎炎正若焚，荷花於此見天真。", "香房馥郁隨風拆，笑臉妖嬈映水新。", "間葉淺深殷似點，滿池繁媚麗於春。", "年年占得餘芳在，幾見當時步步人。"]'),
('30d2e5dd-949b-4b63-bdd7-876ce3e30541','臘月躑躅一枝獨開','朱淑真','宋','宋诗','song-poetry','','[]','園林經臘正彫殘，獨爾花開爛漫鮮。',32,'全唐诗/poet.song.91000.json','["園林經臘正彫殘，獨爾花開爛漫鮮。", "借問隴梅知幸否，得陪春卉共時妍。"]'),
('cbcd1352-a952-4039-915f-5962246e740d','後庭花','朱淑真','宋','宋诗','song-poetry','','[]','豈意爲花屬後庭，荒迷亡國自茲生。',32,'全唐诗/poet.song.91000.json','["豈意爲花屬後庭，荒迷亡國自茲生。", "至今猶恨隔江唱，可惜當時枉用情。"]'),
('4722789e-01bf-4ebc-ad53-5b57948f297c','乞蘭','朱淑真','宋','宋诗','song-poetry','','[]','幽芳別得化工栽，紅紫紛紛莫與偕。',32,'全唐诗/poet.song.91000.json','["幽芳別得化工栽，紅紫紛紛莫與偕。", "珍重故人培養厚，真香獨許寄庭階。"]'),
('6d39df5d-fc46-459a-855e-4184e8acd323','項羽二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','自古興亡本自天，豈容人力預其間。',32,'全唐诗/poet.song.91000.json','["自古興亡本自天，豈容人力預其間。", "非憑天與憑騅逝，騅不前兮戰已閑。"]'),
('b31081f3-04b7-4b8e-8812-6d09a9e21c88','項羽二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','蓋世英雄力拔山，豈知天意在西關。',32,'全唐诗/poet.song.91000.json','["蓋世英雄力拔山，豈知天意在西關。", "范增可用非能用，徒嘆身亡頃刻間。"]'),
('2b50c7c3-0586-45b1-a8c0-979c829d4320','韓信','朱淑真','宋','宋诗','song-poetry','','[]','男兒忍辱志長存，出胯曾無怨一言。',32,'全唐诗/poet.song.91000.json','["男兒忍辱志長存，出胯曾無怨一言。", "漂母人亡石空在，不知還肯念王孫。"]'),
('1a896ce4-6154-49d6-885d-d1a10ce5c36d','張良','朱淑真','宋','宋诗','song-poetry','','[]','功成名遂便歸休，天道分明不與留。',32,'全唐诗/poet.song.91000.json','["功成名遂便歸休，天道分明不與留。", "果可人間戀駒隙，何心願學赤松遊。"]'),
('f9dab668-54b9-49a2-86b2-22593a88daf1','陸賈','朱淑真','宋','宋诗','song-poetry','','[]','漢方擾擾襲秦風，勇士相高馬上功。',32,'全唐诗/poet.song.91000.json','["漢方擾擾襲秦風，勇士相高馬上功。", "惟有君侯守奇節，能將新語悟宸衷。"]'),
('d072868c-551f-4d1a-86c8-b5ff5f9e3379','賈生','朱淑真','宋','宋诗','song-poetry','','[]','文帝爲君固有餘，豈容流涕復長吁。',32,'全唐诗/poet.song.91000.json','["文帝爲君固有餘，豈容流涕復長吁。", "單于可擊非無策，表餌陳來術已疏。"]'),
('0116dbd2-3652-4872-8282-c091ec824e11','董生','朱淑真','宋','宋诗','song-poetry','','[]','秦火經來道失真，下帷發憤每勞神。',32,'全唐诗/poet.song.91000.json','["秦火經來道失真，下帷發憤每勞神。", "誰知異日爲無得，只聽平津一老臣。"]'),
('b484e65c-3ef4-4e6b-8395-472de65fd21f','晁錯','朱淑真','宋','宋诗','song-poetry','','[]','七國綿延蔓草圖，一言請削獨干誅。',32,'全唐诗/poet.song.91000.json','["七國綿延蔓草圖，一言請削獨干誅。", "揚雄自負功名志，猶罪當時太失愚。"]'),
('65b38bc2-b25f-4343-a5ca-6fe25cb59c77','劉向二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','洽聞博識似君難，況復騰凌宗室間。',32,'全唐诗/poet.song.91000.json','["洽聞博識似君難，況復騰凌宗室間。", "屢諫不容甘畎畝，七侯同日亦何顔。"]'),
('9f3cfc6f-0c42-4de0-9539-a1efe957083a','劉向二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','王氏滔天擅國權，可堪恭顯廁其間。',32,'全唐诗/poet.song.91000.json','["王氏滔天擅國權，可堪恭顯廁其間。", "屢形天譴君非悟，徒使宗臣每犯顔。"]'),
('12c216c5-f9ec-4c70-a03b-c16c280aa62f','題王氏必興軒','朱淑真','宋','宋诗','song-poetry','','[]','福有根基善有源，必興緣此敞新軒。',64,'全唐诗/poet.song.91000.json','["福有根基善有源，必興緣此敞新軒。", "埋蛇入相真堪慕，屠狗封侯豈足論。", "未必芝蘭偏謝砌，好看車馬集于門。", "從來天報無先後，不在其身在子孫。"]'),
('25dd3935-2429-4b35-b7ce-22741e30bed2','題余氏攀鱗軒','朱淑真','宋','宋诗','song-poetry','','[]','瀟灑新軒傍翠岑，攀鱗勃勃此潛心。',64,'全唐诗/poet.song.91000.json','["瀟灑新軒傍翠岑，攀鱗勃勃此潛心。", "易驚誰羨葉公室，入夢當爲傅說霖。", "變化一身雷霹遠，騰凌千里海波深。", "臥廬曾比崇高志，肯憶當時梁父吟。"]'),
('ddb55f8d-e8e4-4e20-8129-ecd3741f7b8c','賀人移學東軒','朱淑真','宋','宋诗','song-poetry','','[]','一軒瀟灑正東偏，屏棄囂塵聚簡編。',64,'全唐诗/poet.song.91000.json','["一軒瀟灑正東偏，屏棄囂塵聚簡編。", "美璞莫辭彫作器，涓流終見積成淵。", "謝班難繼予慚甚，顔孟堪睎子勉旃。", "鴻鵠羽儀當養就，飛騰早晚看沖天。"]'),
('ea0c643c-c9a3-4abc-bc22-1ef8bf4ca47a','送人赴試禮部','朱淑真','宋','宋诗','song-poetry','','[]','春闈報罷已三年，又向西風促去鞭。',64,'全唐诗/poet.song.91000.json','["春闈報罷已三年，又向西風促去鞭。", "屢鼓莫嫌非作氣，一飛當自卜沖天。", "賈生少達終何遇，馬援才高老更堅。", "大抵功名無早晚，平津今見起菑川。"]'),
('e7ca9a56-7cf5-4d38-ade2-442c56f1625d','代送人赴召司農','朱淑真','宋','宋诗','song-poetry','','[]','當年持節使，寬厚出誠心。',48,'全唐诗/poet.song.91000.json','["當年持節使，寬厚出誠心。", "郡國承風遠，朝廷注意深。", "十行初下詔，四海望爲霖。", "幾夜台星轉，光侵九棘林。"]'),
('c101893d-f522-4770-9b24-7b7fb037f89e','次韻見贈兼簡吳夫人','朱淑真','宋','宋诗','song-poetry','','[]','南北常嗟見未因，停舟今喜笑談親。',64,'全唐诗/poet.song.91000.json','["南北常嗟見未因，停舟今喜笑談親。", "張姬淑德同冰玉，李白高吟泣鬼神。", "和管幸聽鳴鳳侶，濫竽還愧賞音人。", "佳篇獎拂還過實，班衛聲名豈易倫。"]'),
('3c903365-4fce-4139-b455-b98ea0820825','題四幷樓','朱淑真','宋','宋诗','song-poetry','','[]','華榜危樓豈浪名，人間四者此環幷。',64,'全唐诗/poet.song.91000.json','["華榜危樓豈浪名，人間四者此環幷。", "日知光景無虛度，時覺清風滿座生。", "庾亮據牀談興逸，仲宣倚檻客愁輕。", "眼前此樂難兼得，許我登臨載酒行。"]'),
('1ff4400c-330a-41a0-9850-501658a084f5','題斗野亭','朱淑真','宋','宋诗','song-poetry','','[]','高亭忽登覽，豁爾思無窮。',48,'全唐诗/poet.song.91000.json','["高亭忽登覽，豁爾思無窮。", "訪古多遣跡，留題有鉅公。", "地分吳楚界，人在斗牛中。", "不是乘槎客，那知此路通。"]'),
('b6f90e2f-8d64-485a-870b-cf3ddd730717','舟行即事七首  其一','朱淑真','宋','宋诗','song-poetry','','[]','帆高風順疾如飛，天闊波平遠又低。',32,'全唐诗/poet.song.91000.json','["帆高風順疾如飛，天闊波平遠又低。", "山色水光隨地改，共誰裁剪入新詩。"]'),
('cd72267e-f827-4380-9217-85efa2bb29e8','舟行即事七首  其二','朱淑真','宋','宋诗','song-poetry','','[]','扁舟欲發意何如，回望鄉關萬里餘。',32,'全唐诗/poet.song.91000.json','["扁舟欲發意何如，回望鄉關萬里餘。", "誰識此情腸斷處，白雲遙處有親廬。"]'),
('9b53bed7-2313-4953-84a4-27f279935ce2','舟行即事七首  其三','朱淑真','宋','宋诗','song-poetry','','[]','畫舸寒江江上亭，行舟來去泛縱橫。',32,'全唐诗/poet.song.91000.json','["畫舸寒江江上亭，行舟來去泛縱橫。", "無端添起思鄉意，一字天邊歸雁聲。"]'),
('43f5fcac-43b3-40bf-a656-02461664a0ad','舟行即事七首  其四','朱淑真','宋','宋诗','song-poetry','','[]','滿江流水萬重波，未似幽懷別恨多。',32,'全唐诗/poet.song.91000.json','["滿江流水萬重波，未似幽懷別恨多。", "目斷親闈瞻不到，臨風揮沔獨悲歌。"]'),
('607c392d-f863-461e-b9bd-c015a071ef51','舟行即事七首  其五','朱淑真','宋','宋诗','song-poetry','','[]','對景如何可遣懷，與誰江上共詩裁。',32,'全唐诗/poet.song.91000.json','["對景如何可遣懷，與誰江上共詩裁。", "江長景好是難盡，每自臨風愧乏才。"]'),
('032c5651-944a-40a8-b979-9e729aa9f7f6','舟行即事七首  其六','朱淑真','宋','宋诗','song-poetry','','[]','歲暮天涯客異鄉，扁舟今又度瀟湘。',32,'全唐诗/poet.song.91000.json','["歲暮天涯客異鄉，扁舟今又度瀟湘。", "顰眉獨坐水窗下，淚滴羅衣暗斷腸。"]'),
('f0724efb-f14b-44d0-83cf-60bfde49f1d1','舟行即事七首  其七','朱淑真','宋','宋诗','song-poetry','','[]','歲節將殘惱悶懷，庭闈獻壽阻傳杯。',32,'全唐诗/poet.song.91000.json','["歲節將殘惱悶懷，庭闈獻壽阻傳杯。", "此愁此恨人誰見，鎮日柔腸自九迴。"]'),
('429a5bf3-e5c3-48e3-8b5e-3f8263754c49','寄大人二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','去家千里外，飄泊若爲心。',48,'全唐诗/poet.song.91000.json','["去家千里外，飄泊若爲心。", "詩誦南陔句，琴歌陟岵音。", "承顔故國遠，舉目白雲深。", "欲識歸寧意，三年數歲陰。"]'),
('eed4f190-ebe7-4a38-8942-fbdfb99a946b','寄大人二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','極目思鄉國，千山更萬津。',48,'全唐诗/poet.song.91000.json','["極目思鄉國，千山更萬津。", "庭闈勞夢寐，道路厭埃塵。", "詩禮聞相遠，琴樽誰是親。", "愁看羅袖上，長揾淚痕新。"]'),
('02deaef4-329a-435e-bfd8-27b9ff20bbd1','和前韻見寄  其一','朱淑真','宋','宋诗','song-poetry','','[]','忽得南來信，殷勤慰我心。',48,'全唐诗/poet.song.91000.json','["忽得南來信，殷勤慰我心。", "新詩憐後逸，清論憶容音。", "目斷鄉程遠，樓高客恨深。", "三年重會合，依舊見荆陰。"]'),
('bdd63897-0a36-4866-89b1-d91bc9e34169','和前韻見寄  其二','朱淑真','宋','宋诗','song-poetry','','[]','憶昔江頭別，相看對古津。',48,'全唐诗/poet.song.91000.json','["憶昔江頭別，相看對古津。", "去來分櫓棹，南北隔音塵。", "把酒何時共，論文幾日親。", "歸寧知有約，綵服共爭新。"]'),
('fc9d8a3e-92cb-48b3-97c2-2d42b7ecefc4','臥龍','朱淑真','宋','宋诗','song-poetry','','[]','角瑩纖瓊鱗粲金，擁珠閑臥紫淵深。',32,'全唐诗/poet.song.91000.json','["角瑩纖瓊鱗粲金，擁珠閑臥紫淵深。", "時來天地雲雷舉，起作人間救旱霖。"]'),
('5644aae2-b59f-4336-aafa-c28e102cf6fe','代謝人見惠墨竹','朱淑真','宋','宋诗','song-poetry','','[]','紛紛桃李皆凡俗，四時之中惟有竹。',208,'全唐诗/poet.song.91000.json','["紛紛桃李皆凡俗，四時之中惟有竹。", "非惟蒼翠列風輕，對之自覺清人肉。", "羨君年少多才藝，筆墨潛偷造化力。", "掃出一枝爰惠我，清陰翠色驚滿幅。", "嗟我得之喜何以，貪夫忽獲珠盈斛。", "朝夕捧玩不知疲，如在太白樓上宿。", "遽令標軸掛壁間，勁節直日長目前。", "不必溪邊尋六逸，不必林間訪七賢。", "豈使閻本與王維，獨擅古念稱神師。", "又有屏間名浪得，誤墨成形何足奇。", "未若一筆掃一枝，渭川移來人莫疑。", "珍藏欲默默不得，命牋索筆成新詩。", "詩窮紙滿意不盡，閣筆無語愧才稀。"]'),
('329cbb31-c77f-4e32-9c10-df8116421713','惜花','朱淑真','宋','宋诗','song-poetry','','[]','病眼看花似夢中，一番次第又飛空。',32,'全唐诗/poet.song.91000.json','["病眼看花似夢中，一番次第又飛空。", "朝來不忍倚樹立，倚樹恐搖枝上紅。"]'),
('57ffc5fa-2803-478f-84b7-cb38cdc45810','竹  其一','朱淑真','宋','宋诗','song-poetry','','[]','一徑濃陰影覆牆，含煙敲雨暑天涼。',64,'全唐诗/poet.song.91000.json','["一徑濃陰影覆牆，含煙敲雨暑天涼。", "猗猗肯羨夭桃豔，凜凜終同勁柏剛。", "風籟入時添細韻，月華臨處送清光。", "凌冬不改青堅節，冒雪何傷色轉蒼。"]'),
('f75e560d-293b-456e-a414-f4512d598178','竹  其二','朱淑真','宋','宋诗','song-poetry','','[]','百竿直節拂雲霽，千畝誰人羨渭溪。',32,'全唐诗/poet.song.91000.json','["百竿直節拂雲霽，千畝誰人羨渭溪。", "燕雀謾教來唧噪，虛心終待鳳凰棲。"]'),
('b8dcfee6-7b37-40e2-980b-9a5a7f48c03f','江上阻風','朱淑真','宋','宋诗','song-poetry','','[]','正阻行程江岸間，江頭三日繫歸船。',64,'全唐诗/poet.song.91000.json','["正阻行程江岸間，江頭三日繫歸船。", "水光激浪高翻雪，風力推沙遠漲煙。", "拔悶喜陪尊有酒，供廚不慮食無錢。", "雕章見及唯虛辱，勉強賡酬愧斐然。"]'),
('de6b5b3d-a885-4bae-9d4a-dc9ed650eeec','雪晴二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','桃李無言蜂蝶忙，曉寒未肯放春光。',32,'全唐诗/poet.song.91000.json','["桃李無言蜂蝶忙，曉寒未肯放春光。", "花將計會千山日，風爲栽埋一夜霜。"]'),
('cf865cdc-a214-4311-b128-7de6f2121fac','雪晴二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','早上新鶯語尚蠻，花無氣力倚雕欄。',32,'全唐诗/poet.song.91000.json','["早上新鶯語尚蠻，花無氣力倚雕欄。", "幸蒙殘雪回頭早，又遣東風薄倖寒。"]'),
('475dadf9-ecbf-4c26-8ba6-666f1319f682','筆','朱淑真','宋','宋诗','song-poetry','','[]','雙毫五彩兔狸鋒，珍與歐陽象管同。',32,'全唐诗/poet.song.91000.json','["雙毫五彩兔狸鋒，珍與歐陽象管同。", "多謝寄來情意重，從今敢廢墨池工。"]'),
('86f4a26c-b082-43fb-a654-c6a475a43503','鶯','朱淑真','宋','宋诗','song-poetry','','[]','野花啼鳥喜新晴，湖上波光漾日明。',32,'全唐诗/poet.song.91000.json','["野花啼鳥喜新晴，湖上波光漾日明。", "底事傷春心緒懶，不堪愁裏聽鶯聲。"]'),
('854a72ce-4faa-46c1-861e-558d995d8218','三月三日','朱淑真','宋','宋诗','song-poetry','','[]','林花落盡草初齊，客裏蕭條思欲迷。',32,'全唐诗/poet.song.91000.json','["林花落盡草初齊，客裏蕭條思欲迷。", "又是春光去時節，滿城飛絮亂鶯啼。"]'),
('c383cbf7-7cda-4f54-8bc8-34500e84bc84','清明遊飲少湖莊','朱淑真','宋','宋诗','song-poetry','','[]','清明玩賞正繁華，今日林梢落盡花。',32,'全唐诗/poet.song.91000.json','["清明玩賞正繁華，今日林梢落盡花。", "人散酒闌春已去，一泓初漲滿池蛙。"]'),
('23ce3401-f358-402e-9fdf-65eb7a807b95','黄花','朱淑真','宋','宋诗','song-poetry','','[]','土花能白又能紅，晚節由能愛此工。',32,'全唐诗/poet.song.91000.json','["土花能白又能紅，晚節由能愛此工。", "寧可抱香枝上老，不隨黄葉舞秋風。"]'),
('fa3427f1-872e-4205-9c5b-7f7bc6915497','畫眉','朱淑真','宋','宋诗','song-poetry','','[]','曉來偶意畫愁眉，種種新粧試略施。',32,'全唐诗/poet.song.91000.json','["曉來偶意畫愁眉，種種新粧試略施。", "堪笑時人爭彷彿，滿城將謂是時宜。"]'),
('873785c3-d6e6-490e-b513-6009e0511b78','詠柳二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','長絲嫋娜拂溪垂，乳絮風吹漠漠飛。',32,'全唐诗/poet.song.91000.json','["長絲嫋娜拂溪垂，乳絮風吹漠漠飛。", "全惜東風與爲主，年年先占得韶暉。"]'),
('5fa0e109-0812-4e08-9487-a4e3e18710ad','詠柳二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','風牽裊裊搖無定，翠影侵階已午天。',32,'全唐诗/poet.song.91000.json','["風牽裊裊搖無定，翠影侵階已午天。", "花發鳥歌春景媚，好看柔軟吐香綿。"]'),
('9471b0d9-97d8-41fe-9997-cac469269a9a','桃花','朱淑真','宋','宋诗','song-poetry','','[]','每對春風競吐芳，胭脂顔色更濃粧。',32,'全唐诗/poet.song.91000.json','["每對春風競吐芳，胭脂顔色更濃粧。", "含羞自是不言者，從此成蹊入醉鄉。"]'),
('c5d6df4b-20a5-4371-9afe-6225ded8216f','李花二首  其一','朱淑真','宋','宋诗','song-poetry','','[]','滿園花發白于梅，又與紅桃幷候開。',32,'全唐诗/poet.song.91000.json','["滿園花發白于梅，又與紅桃幷候開。", "可口直須成實後，莫將苦種路旁栽。"]'),
('fa45df15-ac36-4afb-9f91-819e385a6587','李花二首  其二','朱淑真','宋','宋诗','song-poetry','','[]','小小瓊英舒嫩白，未饒深紫與輕紅。',32,'全唐诗/poet.song.91000.json','["小小瓊英舒嫩白，未饒深紫與輕紅。", "無言路側誰知味，惟有尋芳蝶與蜂。"]'),
('4e5e7bfa-bf9a-4404-afb8-47406793db23','梅','朱淑真','宋','宋诗','song-poetry','','[]','雪格冰姿蠟蒂紅，水邊山畔淡煙籠。',32,'全唐诗/poet.song.91000.json','["雪格冰姿蠟蒂紅，水邊山畔淡煙籠。", "江風也似知人意，密遞清香到室中。"]'),
('218a396c-7cc9-4f7c-86c0-934feacf2125','夏夜彈琴','朱淑真','宋','宋诗','song-poetry','','[]','夜久萬籟息，琴聲愈幽寂。',24,'全唐诗/poet.song.91000.json','["夜久萬籟息，琴聲愈幽寂。", "接引到清江，巖泉溜寒滴。"]'),
('ffb25d2d-f39d-4151-b263-f8ee8047012b','蠟梅','朱淑真','宋','宋诗','song-poetry','','[]','天然金蕊冠群英，誰信鵝黄染得成。',32,'全唐诗/poet.song.91000.json','["天然金蕊冠群英，誰信鵝黄染得成。", "昨夜南枝報春信，摘來香露月中清。"]'),
('d7824246-6f20-4a38-a45b-666367362399','夏螢','朱淑真','宋','宋诗','song-poetry','','[]','熠熠迎宵上，林間點點光。',48,'全唐诗/poet.song.91000.json','["熠熠迎宵上，林間點點光。", "初疑星錯落，渾訝火熒煌。", "著雨藏花塢，隨風入畫堂。", "兒童競追撲，照字集書囊。"]'),
('38ba50a2-ac8a-42b4-82d3-6334b7e13d9f','觀燕','朱淑真','宋','宋诗','song-poetry','','[]','深閨寂寞带斜暉，又是黄昏半掩扉。',32,'全唐诗/poet.song.91000.json','["深閨寂寞带斜暉，又是黄昏半掩扉。", "燕子不知人意思，檐前故作一雙飛。"]'),
('2ccdec57-9bd4-4242-b1fc-74a01a282d0c','送燕','朱淑真','宋','宋诗','song-poetry','','[]','見爾來齊去亦齊，空巢零落屋廬低。',32,'全唐诗/poet.song.91000.json','["見爾來齊去亦齊，空巢零落屋廬低。", "更無心記啣泥處，花絮春風小院西。"]'),
('a6895f8f-b42b-41c7-9b27-41397974bea8','遊曠寫亭有作','朱淑真','宋','宋诗','song-poetry','','[]','曠寫亭高四望中，樓臺城郭正春風。',64,'全唐诗/poet.song.91000.json','["曠寫亭高四望中，樓臺城郭正春風。", "笙歌富庶千門樂，市井喧嘩百貨通。", "疊疊民居還瓦屋，紛紛遊蝶亂花叢。", "憑欄忽念非吾土，目斷白雲心莫窮。"]'),
('f7779431-f485-402d-b21f-43888b16b2f6','打馬賦詩','李清照','宋','宋诗','song-poetry','','[]','佛貍定見卯年死，貴賤紛紛尚流徙。',48,'全唐诗/poet.song.91000.json','["佛貍定見卯年死，貴賤紛紛尚流徙。", "滿眼驊騮雜騄駬，時危安得真致此。", "老矣誰能致千里，但願相將過淮水。"]'),
('ff41468f-0600-4483-93d0-4b8413936b72','和張文潛浯溪中興頌二首  其一','李清照','宋','宋诗','song-poetry','','[]','五十年功如電掃，華清花柳咸陽草。',163,'全唐诗/poet.song.91000.json','["五十年功如電掃，華清花柳咸陽草。", "五坊供奉鬬雞兒，酒肉堆中不知老。", "胡兵忽自天上來，逆胡亦是姦雄才。", "勤政樓前走胡馬，珠翠踏盡香塵埃。", "何爲出戰輒披靡，傳置荔枝多馬死。", "堯功舜德本如天，安用區區紀文字。", "著碑銘德真陋哉，乃令神鬼磨山崖。", "子儀光弼不自猜，天心悔禍人心開。", "夏商有鑒當深戒，簡策汗青今具在。", "君不見當時張說最多機，雖生已被姚崇賣。"]'),
('85e4e3a1-bfb5-40e4-82e7-4f30c7da2353','和張文潛浯溪中興頌二首  其二','李清照','宋','宋诗','song-poetry','','[]','君不見驚人廢興傳天寶，中興碑上今生草。',174,'全唐诗/poet.song.91000.json','["君不見驚人廢興傳天寶，中興碑上今生草。", "不知負國有姦雄，但說成功尊國老。", "誰令妃子天上來，虢秦韓國皆天才。", "花桑羯鼓玉方響，春風不敢生塵埃。", "姓名誰復知安史，健兒猛將安眠死。", "去天尺五抱甕峰，峰頭鑿出開元字。", "時移勢去真可哀，姦人心醜深如崖。", "西蜀萬里尚能反，南內一閉何時開。", "可憐孝德如天大，反使將軍稱好在。", "嗚呼奴輩乃不能道輔國用事張后尊，乃能念春薺長安作斤賣。"]'),
('dc1d4078-4ac0-4045-9337-4fc036d095ec','上韓公樞密  其一','李清照','宋','宋诗','song-poetry','','[]','三年夏六月，天子視朝久。',292,'全唐诗/poet.song.91000.json','["三年夏六月，天子視朝久。", "凝旒望南雲，垂衣思北狩。", "如聞帝若曰，岳牧與群后。", "賢寧無半千，運已遇陽九。", "勿勒燕然銘，勿種金城柳。", "豈無純孝臣，識此霜露悲。", "何必羹捨肉，便可車載脂。", "土地非所惜，玉帛如塵泥。", "誰當可將命，幣厚詞益卑。", "四岳僉曰俞，臣下帝所知。", "中朝第一人，春官有昌黎。", "身爲百夫特，行足萬人師。", "嘉祐與建中，爲政有臯夔。", "匈奴畏王商，吐蕃尊子儀。", "夷狄已破膽，將命公所宜。", "公拜手稽首，受命白玉墀。", "曰臣敢辭難，此亦何等時。", "家人安足謀，妻子不必辭。", "願奉天地靈，願奉宗廟威。", "徑持紫泥詔，直入黄龍城。", "單于定稽顙，侍子當來迎。", "仁君方恃信，狂生休請纓。", "或取犬馬血，與結天日盟。", "胡公清德人所難，謀同德協心志安。"]'),
('de496db9-e840-451e-b4c8-1ecb9509f948','上韓公樞密  其二','李清照','宋','宋诗','song-poetry','','[]','想見皇華過二京，壺漿夾道萬人迎。',64,'全唐诗/poet.song.91000.json','["想見皇華過二京，壺漿夾道萬人迎。", "連昌宮裏桃應在，華萼樓頭鵲定驚。", "但說帝心憐赤子，須知天意念蒼生。", "聖君大信明如日，長亂何須在屢盟。"]'),
('b44d50a7-ba60-41d7-a288-5ab6486ae4a9','婺州八咏樓','李清照','宋','宋诗','song-poetry','','[]','千古風流八詠樓，江山留與後人愁。',32,'全唐诗/poet.song.91000.json','["千古風流八詠樓，江山留與後人愁。", "水通南國三千里，氣壓江城十四州。"]'),
('0964040f-49e5-4025-b84e-776775dfe1cc','端午帖子 皇帝閣','李清照','宋','宋诗','song-poetry','','[]','日月堯天大，璿璣舜歷長。',24,'全唐诗/poet.song.91000.json','["日月堯天大，璿璣舜歷長。", "側聞行殿帳，多集上書囊。"]'),
('73d8ca81-f90d-4955-b9a6-876d25d8f442','端午帖子 皇后閣','李清照','宋','宋诗','song-poetry','','[]','意帖初宜夏，金駒已過蠶。',24,'全唐诗/poet.song.91000.json','["意帖初宜夏，金駒已過蠶。", "至尊千萬壽，行見百斯男。"]'),
('c888edf8-feb4-4ca9-9a21-9e21be6f9b38','端午帖子 夫人閣','李清照','宋','宋诗','song-poetry','','[]','三宮催解糉，妝罷未天明。',24,'全唐诗/poet.song.91000.json','["三宮催解糉，妝罷未天明。", "便面天題字，歌頭御賜名。"]'),
('f2b17bdd-026c-4c2b-adef-cf0c82a09483','偶成','李清照','宋','宋诗','song-poetry','','["\u601d\u5ff5", "\u6292\u60c5", "\u8ffd\u5fc6"]','十五年前花月底，相從曾賦賞花詩。',32,'全唐诗/poet.song.91000.json','["十五年前花月底，相從曾賦賞花詩。", "今看花月渾相似，安得情懷似往時。"]'),
('a3040de0-4233-49b3-aeb0-98a048788a4c','春帖子 皇帝閣','李清照','宋','宋诗','song-poetry','','[]','莫進黄金簟，新除玉局牀。',24,'全唐诗/poet.song.91000.json','["莫進黄金簟，新除玉局牀。", "春風送庭燎，不復用沈香。"]'),
('f7bff790-cd8e-4009-9cbe-e540a8b0b582','春帖子 貴妃閣','李清照','宋','宋诗','song-poetry','','[]','金環半后禮，鉤弋比昭陽。',24,'全唐诗/poet.song.91000.json','["金環半后禮，鉤弋比昭陽。", "春生百子帳，喜入萬年觴。"]'),
('ba2fe8ca-41aa-466a-b268-fa3526daafb5','夏日絕句','李清照','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u52b1\u5fd7", "\u5178\u6545", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u548f\u53f2\u6000\u53e4"]','生當爲人傑，死亦作鬼雄。',24,'全唐诗/poet.song.91000.json','["生當爲人傑，死亦作鬼雄。", "至今思項羽，不肯過江東。"]'),
('4da9f457-0793-44c7-a86e-207fbf0a03ea','分得知字韻','李清照','宋','宋诗','song-poetry','','[]','學詩三十年，緘口不求知。',24,'全唐诗/poet.song.91000.json','["學詩三十年，緘口不求知。", "誰遣好奇士，相逢說項斯。"]'),
('8c530854-cb5c-4acb-a7a6-32f485fd4423','曉夢','李清照','宋','宋诗','song-poetry','','[]','曉夢隨疏鐘，飄然躡雲霞。',120,'全唐诗/poet.song.91000.json','["曉夢隨疏鐘，飄然躡雲霞。", "因緣安期生，邂逅萼綠華。", "秋風正無賴，吹盡玉井花。", "共看藕如船，同食棗如瓜。", "翩翩坐上客，意妙語亦佳。", "嘲辭鬬詭辨，活火分新茶。", "雖非助帝功，其樂莫可涯。", "人生能如此，何必歸故家。", "起來斂衣坐，掩耳厭喧嘩。", "心知不可見，念念猶咨嗟。"]'),
('c13055a4-5fd4-4049-9627-da0c59351de8','春殘','李清照','宋','宋诗','song-poetry','','[]','春殘何事苦思鄉，病裏梳頭恨最長。',32,'全唐诗/poet.song.91000.json','["春殘何事苦思鄉，病裏梳頭恨最長。", "梁燕語多終日在，薔薇風細一簾香。"]'),
('6b5192c1-6d91-4840-bcac-7a7526a1298e','感懷','李清照','宋','宋诗','song-poetry','','[]','寒窗敗几無書史，公路可憐竟至此。',64,'全唐诗/poet.song.91000.json','["寒窗敗几無書史，公路可憐竟至此。", "青州從事孔方君，終日紛紛喜生事。", "作詩謝絕聊閉門，燕寢凝香有佳思。", "靜中我乃得知交，烏有先生子虛子。"]'),
('b86a930d-17ca-48c2-a48d-fb6d72908157','釣台','李清照','宋','宋诗','song-poetry','','["\u540d\u5229", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143"]','巨艦只緣因利往，扁舟亦是爲名來。',32,'全唐诗/poet.song.91000.json','["巨艦只緣因利往，扁舟亦是爲名來。", "往來有愧先生德，特地通宵過釣台。"]'),
('7ad180ce-3da1-4535-8cca-3ca70574611c','句  其一','李清照','宋','宋诗','song-poetry','','[]','南渡衣冠欠王導，北來消息少劉琨。',16,'全唐诗/poet.song.91000.json','["南渡衣冠欠王導，北來消息少劉琨。"]'),
('fa1b7490-8178-4c44-a54d-8da68782c91e','句  其二','李清照','宋','宋诗','song-poetry','','[]','南游尚覺怯吳江冷，北狩應悲易水寒。',17,'全唐诗/poet.song.91000.json','["南游尚覺怯吳江冷，北狩應悲易水寒。"]'),
('0da6cab6-589c-4e5e-9197-f91e41636b02','句  其三','李清照','宋','宋诗','song-poetry','','[]','何況人間父子情。',8,'全唐诗/poet.song.91000.json','["何況人間父子情。"]'),
('d73eabff-b5dc-464f-bad1-987ce187e907','句  其四','李清照','宋','宋诗','song-poetry','','[]','炙手可熱心可寒。',8,'全唐诗/poet.song.91000.json','["炙手可熱心可寒。"]'),
('e6ec7ed0-b3dc-4ac5-a7ee-38eb12d3debf','句  其五','李清照','宋','宋诗','song-poetry','','[]','露花倒影柳三變，桂子飄香張九成。',16,'全唐诗/poet.song.91000.json','["露花倒影柳三變，桂子飄香張九成。"]'),
('9bbbf482-a6b6-4120-9ca4-5e0c8571010f','句  其六','李清照','宋','宋诗','song-poetry','','[]','兩漢本繼紹，新室如贅疣。',12,'全唐诗/poet.song.91000.json','["兩漢本繼紹，新室如贅疣。"]'),
('046616ed-ed73-4d02-8b0c-1d0c567e6d7d','句  其七','李清照','宋','宋诗','song-poetry','','[]','所以嵇中散，至死薄殷周。',12,'全唐诗/poet.song.91000.json','["所以嵇中散，至死薄殷周。"]'),
('15b3ae2a-f529-447b-9bf5-b888830fbf84','句  其八','李清照','宋','宋诗','song-poetry','','[]','詩情如夜鵲，三遶未能安。',12,'全唐诗/poet.song.91000.json','["詩情如夜鵲，三遶未能安。"]'),
('8884c54a-55a6-4f9b-97a1-b7d13177d2ce','句  其九','李清照','宋','宋诗','song-poetry','','[]','少陵也自可憐人，更待來年試春草。',16,'全唐诗/poet.song.91000.json','["少陵也自可憐人，更待來年試春草。"]'),
('d2d5842b-44e1-4500-bfaf-22f51097a3c4','句  其一○','李清照','宋','宋诗','song-poetry','','[]','猶將歌扇向人遮。',8,'全唐诗/poet.song.91000.json','["猶將歌扇向人遮。"]'),
('081c2740-d225-4bf6-930a-f43b6ed0d22e','句  其一一','李清照','宋','宋诗','song-poetry','','[]','水晶山枕象牙牀。',8,'全唐诗/poet.song.91000.json','["水晶山枕象牙牀。"]'),
('8858a449-3765-4cc7-aadc-77474eef0e81','句  其一二','李清照','宋','宋诗','song-poetry','','[]','彩雲易散月長虧。',8,'全唐诗/poet.song.91000.json','["彩雲易散月長虧。"]'),
('152e22ee-4757-4b5f-a417-84382fbcf8c8','句  其一三','李清照','宋','宋诗','song-poetry','','[]','幾多深恨斷人腸。',8,'全唐诗/poet.song.91000.json','["幾多深恨斷人腸。"]'),
('c4e3dc73-2e15-4da1-9157-fe99633c8862','句  其一四','李清照','宋','宋诗','song-poetry','','[]','羅衣消盡恁時香。',8,'全唐诗/poet.song.91000.json','["羅衣消盡恁時香。"]'),
('21168cb3-1b5c-43e3-aa27-67720e9a0e7b','句  其一五','李清照','宋','宋诗','song-poetry','','[]','閑愁也似月明多。',8,'全唐诗/poet.song.91000.json','["閑愁也似月明多。"]'),
('6b622e5d-b503-432f-ba57-f2d039b909a1','句  其一六','李清照','宋','宋诗','song-poetry','','[]','直送淒涼到畫屏。',8,'全唐诗/poet.song.91000.json','["直送淒涼到畫屏。"]'),
('25335352-1d8d-4002-9721-131a5aa07a45','余舊供觀音比得蔣穎叔所傳香山成道因緣歎仰靈異因爲贊於後','張守','宋','宋诗','song-poetry','','[]','大哉觀世音，願力不思議。',192,'全唐诗/poet.song.91000.json','["大哉觀世音，願力不思議。", "化身千百億，於一刹那頃。", "香山大因緣，愍念苦海衆。", "慈悲示修證，欲同到彼岸。", "受辱不退轉，是乃忍辱仙。", "抉眼斷兩手，不啻棄涕唾。", "欻然千手眼，照用無邊際。", "至人見與執，不在千手眼。", "向來棄去時，初無一毫欠。", "乃至以千記，我亦無贏餘。", "是故將示寂，還復本來相。", "猶如大虚空，雲電或風霾。", "須臾各霽止，太虚自寥廓。", "我今仰靈蹤，歡喜發洪願。", "今生未喪世，誓願永歸依。", "更與見聞者，同登無上法。"]'),
('1b55206e-7b03-428a-9c73-9202f969dcf1','方時敏倅濬歸浙江待次送行','張守','宋','宋诗','song-poetry','','[]','嶷嶷玄英孫，聞風自鄞川。',288,'全唐诗/poet.song.91000.json','["嶷嶷玄英孫，聞風自鄞川。", "朅來苕霅間，王事亦復聯。", "相遇一傾蓋，論交即忘年。", "開口見城府，落筆生雲烟。", "尋春五亭岸，釣月雙溪船。", "杯行各酣適，箕踞忘拘牽。", "放辭發奇偉，捜句窮鑱鐫。", "我時怯欲降，退壁常自堅。", "俯首試外臺，一矢雙鵰連。", "聯鑣仲與季，三秀來差肩。", "羣雋爲辟易，拱手不敢前。", "折箠破大敵，未足煩戈鋋。", "風低忽垂翅，信命付諸天。", "公飛東陽舄，我訪蘭亭賢。", "雙魚數流問，五馬方薦延。", "攝事古山陰，晤語復粲然。", "禪心扣空寂，蔬飯捐葷羶。", "一洗盡玷缺，皎皎尺璧圓。", "繼從甘陵遊，假道仍周旋。", "飄零我蓬轉，渠敢自意全。", "邂逅鳳凰闕，公亦仍迍邅。", "宦學舊軰行，金狨覆文韉。", "以及後來秀，青雲各聯翩。", "公方駕别車，去即三山巔。"]'),
('d5576f13-8862-4281-8490-c811bdedc716','貴溪道中寄信州夏蒙夫使君','張守','宋','宋诗','song-poetry','','[]','薄晚雪逾密，助寒風更顛。',72,'全唐诗/poet.song.91000.json','["薄晚雪逾密，助寒風更顛。", "長塗客衣薄，僕馬僵不前。", "綠林軫玉食，渠敢嘆獨賢。", "行喜見故人，羈懷得披宣。", "冰花散渺莽，玉樹争清妍。", "遥知坐歗餘，鈴齋聳吟肩。"]'),
('36aa22b2-c34e-4445-a79b-92f71d62363f','再和','張守','宋','宋诗','song-poetry','','[]','六花照老眼，令我喜欲顛。',72,'全唐诗/poet.song.91000.json','["六花照老眼，令我喜欲顛。", "頃刻萬株玉，巧趁春風前。", "佇立聽風謡，誦言使君賢。", "不事廚傳飾，皇化憂不宣。", "相見雖蒼顔，妙語加韶妍。", "小邦猶射鼠，安用彎黄肩。"]'),
('c6bf876c-95d7-45e2-8aaf-423fc1efe4e2','來詩過有稱譽再和','張守','宋','宋诗','song-poetry','','[]','任重非所勝，位高憂疾顛。',72,'全唐诗/poet.song.91000.json','["任重非所勝，位高憂疾顛。", "歸耕半頃秫，榮枯付樽前。", "來作江南牧，衰謝愧五賢。", "喜聞復故境，中興頌周宣。", "賢能不復遺，紆餘定爲妍。", "勿笑百僚尾，三署會須肩。"]'),
('b92c4dab-b103-4e1c-a306-badc4648fd4e','謝孫仲益察院借示詩卷','張守','宋','宋诗','song-poetry','','[]','客游跨兩春，胸次飽塵滓。',180,'全唐诗/poet.song.91000.json','["客游跨兩春，胸次飽塵滓。", "無人抉河漢，爲我一浣洗。", "故人富清製，放筆如翻水。", "此間渺無津，滂沛到筆底。", "長鬚遣大軸，光彩照窗几。", "我時食對案，驚喜失筯匕。", "風雅間何闊，稍復聞正始。", "滌除塵想滅，肝肺挹清泚。", "早年上金閨，氣劘諸彦壘。", "風斤運無旁，四座羞血指。", "駸駸跨驄馬，奔輪不容柅。", "負大難爲力，得坎聊復止。", "熙辰崇盛典，潤色待東里。", "風雲吐憤鬱，事業振奇偉。", "餘暇賦天台，金聲追祖禰。"]'),
('1d4c2538-affd-477a-8bb3-315110745781','洪慶善提刑罷官過建康惠詩和答','張守','宋','宋诗','song-poetry','','[]','若人儒林秀，俊聲自孩提。',192,'全唐诗/poet.song.91000.json','["若人儒林秀，俊聲自孩提。", "振鬛日千里，衆眼驚月題。", "盍登要路津，獻納蘇黔黎。", "聊乘使者車，枳棘非鸞棲。", "戢翼下吳會，客路秋風凄。", "弭帆江之濵，歸夢先苕谿。", "寄傲水南北，忘懷玉東西。", "况乃味禪悦，已知昔途迷。", "坐笑老婆禪，杖拂勞提撕。", "祗應浩然氣，中宵吐虹霓。", "功名儻來遇，未免雲衢躋。", "秖今寵辱際，淵澄看旋鯢。", "龍鍾秣陵守，短髪那勝箆。", "邂逅見亹亹，野鶴羞凡鷄。", "言句謝筌栰，未易窮端倪。", "歸來見詹尹，寧復問突梯。"]'),
('7a894c18-f662-4888-b494-cba84e285250','題王巖起樂齋','張守','宋','宋诗','song-poetry','','[]','靜者悦山林，夸者慕鐘鼎。',120,'全唐诗/poet.song.91000.json','["靜者悦山林，夸者慕鐘鼎。", "人生各有適，所樂滯一境。", "王郎超世姿，名教得深省。", "窮通付風雨，一笑萬累屏。", "閑居秖蔬水，開卷味自永。", "從事雖賢勞，游刃失綮肯。", "此心故休休，閲世徒耿耿。", "開軒理松菊，留客辦果茗。", "得趣地自偏，無塵句尤警。", "他年觀出處，廊廟即箕潁。"]'),
('ce4900da-3745-41c0-9a68-ce38247eb877','澄懷庵','張守','宋','宋诗','song-poetry','','[]','憶昨避寇亂，與君連一墻。',96,'全唐诗/poet.song.91000.json','["憶昨避寇亂，與君連一墻。", "别來幾寒暑，杳如參與商。", "君與喪亂際，徜徉水雲鄉。", "十年林下夢，不到聲利塲。", "結庵劣容膝，不爲大盜藏。", "此懷那須澄，已作冰雪涼。", "花竹供四時，飲水樂未央。", "何當謝塵鞅，解纓濯滄浪。"]'),
('ad58748b-0ef4-4526-adb5-1b9415c101d2','嵐光臺','張守','宋','宋诗','song-poetry','','[]','雲山屹長空，烟水湛深淥。',48,'全唐诗/poet.song.91000.json','["雲山屹長空，烟水湛深淥。", "築臺萬象表，領略在吾目。", "凝嵐翠欲流，煙光炯堪掬。", "盡洗纓上塵，長照杯中醁。"]'),
('2a25be10-49b6-450c-9817-1966d7089b99','四達亭','張守','宋','宋诗','song-poetry','','[]','胸中浩無旁，吞納九雲夢。',48,'全唐诗/poet.song.91000.json','["胸中浩無旁，吞納九雲夢。", "高懷有所寄，亭中亦空洞。", "涼月侵風櫺，寒烟逼曉棟。", "達人意有餘，未許俗子共。"]'),
('7cc738a0-dbc1-4d04-93fb-e94cd3ac81fd','題閭丘氏巢鳳亭以其子登科胡茂老名之','張守','宋','宋诗','song-poetry','','[]','令君命卿家，一經世遺子。',168,'全唐诗/poet.song.91000.json','["令君命卿家，一經世遺子。", "煌煌丹桂枝，寂寞踰五紀。", "朅來山水縣，闢館貯書史。", "竹梧森翠碧，鸞鵠自停峙。", "翩翩丹穴雛，一鳴驚衆耳。", "綷羽覽輝翔，百鳥各披靡。", "英姿凌雲氣，玉頰編貝齒。", "唾手取青氊，父老爲驚喜。", "寧無英妙年，亦或拾青紫。", "上堂拜重慶，此事世無比。", "勉哉尊所聞，烟霄千萬里。", "五斗暫折腰，百錬無繞指。", "矯翼儀舜韶，作瑞明光裏。", "來者玩兹亭，甘棠同勿毁。"]'),
('8feedf31-97f1-4a88-aa93-46c7aedcb9c3','和曾宏父告别兼簡幕屬','張守','宋','宋诗','song-poetry','','[]','奉詔辭北闕，把麾到南州。',168,'全唐诗/poet.song.91000.json','["奉詔辭北闕，把麾到南州。", "向來政已拙，老去語更偷。", "條教雖屢下，瘡痍何時瘳。", "猶喜豺虎息，稍解聖主憂。", "英英幕中彦，紅蕖汎清流。", "袖手聽婉畫，藥石兼珍羞。", "衰遲樗櫟姿，萬一桑榆收。", "吾人南豐秀，未應仄席求。", "飄泊乘别車，惠然肯來游。", "周旋見家規，會合非人謀。", "清詩日礱琢，不厭枯腸捜。", "束書赴嘉招，掉臂不我留。", "我無青玉案，何以報所投。", "從兹謝淚洳，龍門看吞舟。"]'),
('73f89afc-eb01-42ce-9625-bfc15ed9192a','秦楚材和六一先生秋懷因次韻送别','張守','宋','宋诗','song-poetry','','[]','抱釁久羸瘠，兀若槁木枝。',96,'全唐诗/poet.song.91000.json','["抱釁久羸瘠，兀若槁木枝。", "别離故作惡，未别意已悽。", "况此清商時，木落水潦歸。", "艤舟話心曲，未了舟欲移。", "借問何匆匆，直恐違官期。", "念此登臨意，何止騷人悲。", "子行不可留，子鬢殊未衰。", "痛飲置人事，江上鱸魚肥。"]'),
('0c0eba10-76db-4477-8f8a-d82c7c8f92be','客居聞雁有感','張守','宋','宋诗','song-poetry','','[]','涎涎社燕尾，嗈嗈霜雁聲。',72,'全唐诗/poet.song.91000.json','["涎涎社燕尾，嗈嗈霜雁聲。", "兩物巧相避，寸陰不得停。", "我來燕未歸，倐見雁南征。", "客遊何當還，節物凜可驚。", "哀歌撫長鋏，獨夜羞短檠。", "念營堂上巢，愧爾飛冥冥。"]'),
('bf54b3fa-9444-463e-b830-360c9c8e4c55','常山神祠','張守','宋','宋诗','song-poetry','','[]','籃輿破霜曉，駕言郡城南。',168,'全唐诗/poet.song.91000.json','["籃輿破霜曉，駕言郡城南。", "雲山爲好色，風日仍清酣。", "古祠據山腹，深堂静潭潭。", "我來何所禱，禍福久已諳。", "頑冥亦天資，乞靈漫懷慙。", "同來得我軰，勝處思窮探。", "爽氣排俗慮，濁醪侑清談。", "卧碑一拂拭，古鏡開塵函。", "斯人已仙去，寒泉獨清甘。", "扶藜山崷崒，放目窺渾涵。", "前瞻羣峰翔，九僊駐飛驂。", "後俯歸路迷，城郭埋烟嵐。", "平生丘壑姿，回首不我堪。", "歸來耿不寐，青燈對書龕。"]'),
('0824affa-e9a4-49c3-8f36-8f157a317af1','姚志道有書輒不借戲呈','張守','宋','宋诗','song-poetry','','[]','我來春未動，兀坐秋忽老。',144,'全唐诗/poet.song.91000.json','["我來春未動，兀坐秋忽老。", "客懷飽世味，塵土不容澡。", "尚餘筆硯癖，俯仰半華皓。", "中年得異書，夜諷或至卯。", "爾來口生棘，妙語時耳剽。", "故人吾臭味，囊帙富緗縹。", "什襲祕不傳，凜若璧在趙。", "念兹訪遺逸，從人掇殘藁。", "何當發其藏，囷廪一傾倒。", "窮途百態惡，歸思疾飛鳥。", "終當餽所有，共此絕代寶。", "歲晚同吟哦，乘風上蓬島。"]'),
('e671ea17-5dfa-43db-b497-425079311652','客居坐無茵褥賓至常苦之戲作','張守','宋','宋诗','song-poetry','','[]','廣文坐客寒無氊，少陵人來坐馬韉。',166,'全唐诗/poet.song.91000.json','["廣文坐客寒無氊，少陵人來坐馬韉。", "胸中富等千户侯，不使囊中餘一錢。", "嗟予久客貧到骨，兀坐長恐藜床穿。", "才名未踏兩公閾，窮愁何遽容爭先。", "畫餅端知不餬口，筆耕輒亦遭無年。", "媿無文茵薦佳客，促膝危坐如寒蟬。", "君不見漢朝博士能說經，五十餘席輸戴憑。", "又不見袁尚索席藉凍地，不意頭顱行萬里。", "空榻蕭然亦安穏，得失榮枯付天理。", "金狨覆鞍容墜傷，禍福由來相伏倚。"]'),
('0086f6da-f0ac-4005-ac31-c1502705c619','題舍弟舒嘯亭','張守','宋','宋诗','song-poetry','','[]','不羡高門聫甲乙，欲傍林泉老蓬蓽。',256,'全唐诗/poet.song.91000.json','["不羡高門聫甲乙，欲傍林泉老蓬蓽。", "田間築室路三杈，亭子蔭茅簷四出。", "春霖竹牖上蝸牛，夏夜藜床吟蟋蟀。", "茅亭雖小容舒嘯，丘壑胸中故超軼。", "晨窗晚逕足披風，細柳修篁長障日。", "閉關已作柴桑趣，况有腴田供種秫。", "客來共醉甕頭春，長嘯一聲百憂失。", "遥想妖氛纒象魏，忍見風塵侵警蹕。", "勿憂蘇門真避世，要似武侯時抱膝。", "我紆郡紱病且衰，欲報君恩老無術。", "簪裳未覺柴栅殊，鼓吹殆與池蛙一。", "簿領幾回迷老眼，况復伸眉縱狂率。", "已慙成瑨功曹諺，空憶劉琨胡騎逸。", "遐想東臯落成處，欲往從之足雙桎。", "夢君琢句俯清流，春草池塘到詩律。", "便應投紱賦歸來，肯待子平婚嫁畢。"]'),
('95484e69-856a-451f-bc6b-0bd68bf8912c','題畫','張守','宋','宋诗','song-poetry','','[]','二松偃蓋勢曲拳，二松疏幹凌風烟。',64,'全唐诗/poet.song.91000.json','["二松偃蓋勢曲拳，二松疏幹凌風烟。", "霜姿舒卷全于天，笑看草木爭春妍。", "杖藜誰子行蹁蹮，欲渡略彴迴溪船。", "令我清夢歸林泉，漳江流駛行可沿。"]'),
('2ecc7d5a-0dfe-4661-a7a0-23e9d2398de6','和族叔祖古風','張守','宋','宋诗','song-poetry','','[]','去年謝病辭黄屋，夜夜鄉心夢相續。',144,'全唐诗/poet.song.91000.json','["去年謝病辭黄屋，夜夜鄉心夢相續。", "今年罷郡理菟裘，喜在家庭厠蘭玉。", "阿翁年德冠吾宗，時親典刑聽約束。", "懷奇終待玉三獻，世路不堪珠九曲。", "愛酒惟憂北海空，居貧不作揚雄逐。", "如何蔬糲肯淹留，不爲盤餐爲宗族。", "忘懷一醉見天真，窮達寧煩詹尹卜。", "歸作長歌寫悲壯，千載騷人可奴僕。", "客星在天翁莫愁，赫赫太陽升若木。"]'),
('c53ecfa7-1a5d-4d53-8823-cb5120e38ca8','送提刑劉嶠解印還朝二首  其一','張守','宋','宋诗','song-poetry','','[]','贈君吉水麝煤之玄玉，毗陵兔穎之毛錐。',66,'全唐诗/poet.song.91000.json','["贈君吉水麝煤之玄玉，毗陵兔穎之毛錐。", "玄玉磨研勝點漆，毛錐揮洒如印泥。", "增光纒龍之大字，煥發吐鳳之英詞。", "玉旒光邉借前箸，便好再勒中興碑。"]'),
('6f7f6c2b-77bf-4b5e-88e0-d48eefc03781','送提刑劉嶠解印還朝二首  其二','張守','宋','宋诗','song-poetry','','[]','贈君西蜀衛生之藥，南臺送别之詩。',64,'全唐诗/poet.song.91000.json','["贈君西蜀衛生之藥，南臺送别之詩。", "藥驅陰邪保真氣，詩叙平昔同襟期。", "願言加餐錫難老，念兹分袂送將歸。", "時有平安寄來雁，慰我别後長相思。"]'),
('8712e002-69ae-4eeb-a325-31aa53d069fc','次韻范寥孟冬大閲之什','張守','宋','宋诗','song-poetry','','[]','承平不用衛與英，赤子頻弄潢池兵。',256,'全唐诗/poet.song.91000.json','["承平不用衛與英，赤子頻弄潢池兵。", "猰貐向恃七閩險，彗孛欲翳三辰明。", "吾皇南顧念凋瘵，舊臣雖老堪一行。", "奉詔褰帷問瘡痏，一意摩拊無他營。", "爾來松溪掃遺孽，卒歲不復枹鼓鳴。", "九農豐登四郊静，孟冬大閲張軍聲。", "摩天金鼓動霜曉，井鉞色正參旗横。", "羽箭犀利七札薄，鐵騎馳突一鳥輕。", "戰士人人逞驍儁，猛將一一懷忠精。", "吾軍如此粗可用，縱有綠林何足平。", "獨公之家雄洛京，人物接武多名卿。", "天涯邂逅見典刑，豈止一善宜盱衡。", "胸中韜鈐想餘事，筆下文采常知名。", "登塲縱觀重感慨，那得萬騎聽使令。", "通和強敵固下策，自古三王猶有征。", "得君耆艾將神武，定看却敵賢長城。"]'),
('e449bcd3-da8e-4dcb-98fe-16956127ded8','豐歲行','張守','宋','宋诗','song-poetry','','[]','早禾飽熟收山場，晚禾碩茂青吐芒。',144,'全唐诗/poet.song.91000.json','["早禾飽熟收山場，晚禾碩茂青吐芒。", "五風十雨作豐歲，一飽何以酬蒼蒼。", "牛遭癘疫大半死，挽犁豈誇人力強。", "妻兒翁媪共耕鑿，勤勞有此一稔償。", "人言穀賤三農傷，我喜不乏三軍糧。", "邉騎長驅自送死，卒致一怒煩君王。", "將軍輸忠士賈勇，獻俘獻捷來相望。", "忍令戰士有饑色，努力收斂輸太倉。", "勿言無以飽妻子，湏知餓死勝兵死。"]'),
('963b63bb-f27a-4ac3-8ee2-4b160fb41d14','晚霽獨坐戲呈周元舉劉希范許少伊同舍諸兄二首  其一','張守','宋','宋诗','song-poetry','','[]','吏散無人跡，風回掃積氛。',48,'全唐诗/poet.song.91000.json','["吏散無人跡，風回掃積氛。", "虛涼簷際得，遠響靜中聞。", "樹色深留暝，爐烟細裊雲。", "此間應有句，端合與君分。"]'),
('3a65fd37-7a58-4cd8-972e-43c05efa7a0d','晚霽獨坐戲呈周元舉劉希范許少伊同舍諸兄二首  其二','張守','宋','宋诗','song-poetry','','[]','疾風迴急雨，碧瓦散晴氛。',48,'全唐诗/poet.song.91000.json','["疾風迴急雨，碧瓦散晴氛。", "幽趣何人共，微吟得自聞。", "扶笻翻倦鳥，岸幘送歸雲。", "病惱新涼夕，孤斟負十分。"]'),
('4d88ce64-fbb5-436a-b076-729d8ae3cbf8','出郊奉祠','張守','宋','宋诗','song-poetry','','[]','薄霧林花潤，微風沙水清。',48,'全唐诗/poet.song.91000.json','["薄霧林花潤，微風沙水清。", "鴻歸心共遠，鷗泛眼偏明。", "寸祿秋毫累，分陰尺璧輕。", "滄浪端可濯，藿食了餘生。"]'),
('afd0959e-9b51-4841-ac90-385c148dd035','題潤公看經室','張守','宋','宋诗','song-poetry','','[]','潤公看經室，山氣翠霏霏。',48,'全唐诗/poet.song.91000.json','["潤公看經室，山氣翠霏霏。", "花雨當軒墮，松雲入座飛。", "鑿池泉繞霤，採木露沾衣。", "欲覓三山石，空慙心賞違。"]'),
('25e229de-cc20-457e-8a4a-844a998343e8','元舉希范見和佳篇皆有懷歸之意頗合鄙趣因次元韻','張守','宋','宋诗','song-poetry','','[]','湖海關幽夢，峰巒想翠氛。',48,'全唐诗/poet.song.91000.json','["湖海關幽夢，峰巒想翠氛。", "詩囊閑事業，禪衲舊知聞。", "白簡留任昉，玄文付子雲。", "飛潛俱有適，物理聽羣分。"]'),
('4c12e5b1-2bc2-43f8-9318-8a4ca08c6d7a','撫屬游君病起惠詩次韻','張守','宋','宋诗','song-poetry','','[]','蛇影沉杯裏，牛鳴震坐傍。',48,'全唐诗/poet.song.91000.json','["蛇影沉杯裏，牛鳴震坐傍。", "晦明生癘疫，神物護忠良。", "喜復神明舊，閑宜日月長。", "關心一枰上，黑白已分行。"]'),
('ccbe3e62-0dcc-481b-835d-09c0d8a4237e','王承可惠官字韻詩次韻二首  其一','張守','宋','宋诗','song-poetry','','[]','才疏空許國，老去漫爲官。',48,'全唐诗/poet.song.91000.json','["才疏空許國，老去漫爲官。", "長病同玄晏，多言愧懶殘。", "歸心隨贛水，愁眼望桑乾。", "自笑髪如鶴，羞看鏡裏鸞。"]'),
('c93b0eb3-358d-4b48-a0c6-16adb64eb00f','王承可惠官字韻詩次韻二首  其二','張守','宋','宋诗','song-poetry','','[]','昔年留建業，授館厠嘉賓。',48,'全唐诗/poet.song.91000.json','["昔年留建業，授館厠嘉賓。", "忝竊慙高位，淹留有故人。", "相逢青鬢在，誰信白頭新。", "晚歲良田熟，東阿豈漫云。"]'),
('a637d376-30b1-4356-934f-2b8676a9d250','獲從樞密徐公游者累月雖接名理不敢言詩念揮斤般郢之門古人所誚也日者惡語流傳不圖徹聽過蒙奬譽形之篇什輒復次韻叙謝','張守','宋','宋诗','song-poetry','','[]','詩壇推宿將，一諾重千金。',48,'全唐诗/poet.song.91000.json','["詩壇推宿將，一諾重千金。", "長怯雷門過，惟堪澤畔吟。", "數篇真漫興，三歎沗知音。", "佳句如傳法，慇懃慰夙心。"]'),
('acc54a75-a901-436a-92be-90f9ad5371c5','和王巖起惠二詩  其一','張守','宋','宋诗','song-poetry','','[]','頻年分將閫，那敢厭粗官。',48,'全唐诗/poet.song.91000.json','["頻年分將閫，那敢厭粗官。", "花著雙眸暗，霜侵兩鬢殘。", "四郊才罷警，七澤忽憂乾。", "未報君恩重，清高愧伯鸞。"]'),
('c3ce61b3-921c-4ea4-8ea5-302825a2ac36','和王巖起惠二詩  其二','張守','宋','宋诗','song-poetry','','[]','勝流還入幕，賢否數嘉賓。',48,'全唐诗/poet.song.91000.json','["勝流還入幕，賢否數嘉賓。", "婉畫無遺慮，佳言更可人。", "中郎才簡亮，開府句清新。", "淥水稱佳麗，於今不足云。"]'),
('d4b43c29-2483-4019-be8d-db11956a6b7f','和答少伊','張守','宋','宋诗','song-poetry','','[]','秋雨厭煩濁，清詩静垢氛。',48,'全唐诗/poet.song.91000.json','["秋雨厭煩濁，清詩静垢氛。", "向來佳句法，不遣俗人聞。", "和氣回霜簡，閑心付嶺雲。", "只應明主眷，符水未容分。"]'),
('3f9a69f3-35c7-4d22-bf7c-1044d47b5139','獨夜耿耿至旦蚤作偶書','張守','宋','宋诗','song-poetry','','[]','久客迷歲月，勞生念斗升。',48,'全唐诗/poet.song.91000.json','["久客迷歲月，勞生念斗升。", "寒侵風卷幔，夜靜月窺燈。", "暗穴鳴饑鼠，晨窗上凍蠅。", "起來看鏡懶，種種髪鬅鬙。"]'),
('5747fd1f-138d-4dad-920c-641ad10e22e7','野飲','張守','宋','宋诗','song-poetry','','[]','斜日明官柳，飛紅綴客衣。',48,'全唐诗/poet.song.91000.json','["斜日明官柳，飛紅綴客衣。", "隔林鶯對語，掠水燕爭飛。", "野飲聊排悶，羈懷得解圍。", "言歸歸未可，今昨兩俱非。"]'),
('94dbc64c-e108-4094-bfbc-88ac6bc7e542','胡已茂端明同年挽詞  其一','張守','宋','宋诗','song-poetry','','[]','孝友終身篤，詞章一世英。',48,'全唐诗/poet.song.91000.json','["孝友終身篤，詞章一世英。", "艱難扈行在，憔悴老承明。", "歸院花塼影，趨朝革履聲。", "一麾隨逝水，塵迹想平生。"]'),
('26f06d3a-8d7f-4371-bdb4-1905c98f9eda','胡已茂端明同年挽詞  其二','張守','宋','宋诗','song-poetry','','[]','道德文恭並，才猷修簡親。',48,'全唐诗/poet.song.91000.json','["道德文恭並，才猷修簡親。", "中庸漢伯始，清獻晉平春。", "望襲高華胄，身終侍從臣。", "不諧三老約，華屋繐帷新。"]'),
('11d9a330-0df0-48f8-a5c7-fb73799a7923','送秦楚材使高麗二首  其一','張守','宋','宋诗','song-poetry','','[]','虀鹽太學鬢先秋，乘興聊爲漫汗遊。',64,'全唐诗/poet.song.91000.json','["虀鹽太學鬢先秋，乘興聊爲漫汗遊。", "戲把漢旌行絕域，不因卭竹取封侯。", "波神侑飲鯨翻鱠，海雨催詩蜃吐樓。", "不獨鷄林傳好句，會看弭檝上瀛洲。"]'),
('c0bec894-4c25-4d51-8d75-0efd0eb2e48b','送秦楚材使高麗二首  其二','張守','宋','宋诗','song-poetry','','[]','學士風流異域傳，幾航雲海使南天。',64,'全唐诗/poet.song.91000.json','["學士風流異域傳，幾航雲海使南天。", "不因名動五千里，豈見文高二百年。", "貢外别題求妙札，錦中翻様織新篇。", "淹留却恨鴛行舊，不得飛觴駐蹕前。"]'),
('3b2a2213-ee85-4126-a851-4a959aede573','送提刑劉嶠解印還朝','張守','宋','宋诗','song-poetry','','[]','老懷欲别已辛酸，再歲周旋瞬息間。',64,'全唐诗/poet.song.91000.json','["老懷欲别已辛酸，再歲周旋瞬息間。", "誰遣暮潮催兩槳，却應清夢掛三山。", "功名不許淹行色，談話何時復解顔。", "鵷鷺行間如借問，爲言衰謝合投閑。"]'),
('c01c4e28-d613-4295-a639-d8890c8fca07','紹興丁已以大禮館客恩奏族叔祖有詩見戲次韻和答二首  其一','張守','宋','宋诗','song-poetry','','[]','少室山中計已成，卧看朝市等蠅營。',64,'全唐诗/poet.song.91000.json','["少室山中計已成，卧看朝市等蠅營。", "對門山雪惟詩思，過眼秋雲即宦情。", "長恐搢紳嘲捷徑，勿緣升斗誚虚名。", "翁看肉食顔如甲，何似村醪一笑赬。"]'),
('5be01bf0-2f87-4844-bc5b-ef573de2e194','紹興丁已以大禮館客恩奏族叔祖有詩見戲次韻和答二首  其二','張守','宋','宋诗','song-poetry','','[]','衣冠相望兩卿家，列鼎當年辦咄嗟。',64,'全唐诗/poet.song.91000.json','["衣冠相望兩卿家，列鼎當年辦咄嗟。", "後裔不應猶短褐，除書未怕失丹砂。", "恩光漫欲霑宗族，品秩何勞問等差。", "莫笑青衫同畫餅，也勝辛苦踏槐花。"]'),
('b6b63dd3-c8fc-43c1-813a-5ce3de6efd26','送仲并倅湖州','張守','宋','宋诗','song-poetry','','[]','佳麗江山得共遊，一時賓主亦風流。',64,'全唐诗/poet.song.91000.json','["佳麗江山得共遊，一時賓主亦風流。", "鳥飛魚泳青油幕，虎踞龍盤白鷺洲。", "坐席未温俄告别，題輿催上莫淹留。", "苕溪尺五煙霄近，入手功名不自由。"]'),
('cf2452a1-1be5-4b81-bb70-87febf7cbc94','伯恭侍郎自吳門謝事有詩和者無慮百餘人矣且命屬和不可辭次韻','張守','宋','宋诗','song-poetry','','[]','滄江洗盡眼中埃，飽看江山句更裁。',64,'全唐诗/poet.song.91000.json','["滄江洗盡眼中埃，飽看江山句更裁。", "風引前旌如挽去，山迎歸棹欲飛來。", "捐軀許國憂心在，袖手還家笑口開。", "應念龍鍾豫章守，沉迷薄領日回回。"]'),
('13c5aa24-6946-4578-82bf-0da382a1b432','次韻張煇惠詩三首  其一','張守','宋','宋诗','song-poetry','','[]','詩隣可卜擬誅茅，好句人間見一毫。',64,'全唐诗/poet.song.91000.json','["詩隣可卜擬誅茅，好句人間見一毫。", "吟就鉢聲應未絕，流傳紙價頓能高。", "謬成燕雀追黄鵠，已作蜻蜓避百勞。", "清夜月窗裁警句，霜梧風竹助蕭騷。"]'),
('eec71d93-9deb-4b4f-8a76-7c0d617b83f0','次韻張煇惠詩三首  其二','張守','宋','宋诗','song-poetry','','[]','投老須營一把茅，晚親珠玉看揮毫。',64,'全唐诗/poet.song.91000.json','["投老須營一把茅，晚親珠玉看揮毫。", "賦牛絕敏驚曹植，刻鵠無成愧伯高。", "已放閑身栖寂寞，時憑佳句洗塵勞。", "喜逢載酒經過客，老去無心作反騷。"]'),
('f6cae621-5523-4a6c-844e-1ffb675e1327','次韻張煇惠詩三首  其三','張守','宋','宋诗','song-poetry','','[]','老依背郭蔭堂茅，寒夜微吟自削毫。',64,'全唐诗/poet.song.91000.json','["老依背郭蔭堂茅，寒夜微吟自削毫。", "羨子筆迴霜氣勁，驚人句與月魂高。", "極知蹇足追隨苦，便覺長鬚走送勞。", "因識盧郎是佳器，定能痛飲誦離騷。"]'),
('3a3f3375-674e-40e4-a339-28a87685b6ba','張子華作詩誤用事有詩訟其過因次元韻','張守','宋','宋诗','song-poetry','','[]','咳唾成詩未許攀，腹中應著綺千端。',64,'全唐诗/poet.song.91000.json','["咳唾成詩未許攀，腹中應著綺千端。", "畫蛇思巧因饒足，倚馬才高肯駐鞍。", "割肉固非方朔社，蒸壺曾入老盧盤。", "小瑕不揜千金璧，能事寧容俗眼看。"]'),
('039d1b76-1db8-463f-b11f-7ecf8ebc993d','王承可再示次韻','張守','宋','宋诗','song-poetry','','[]','爲寮東越肯忘年，南越相逢兩皓然。',64,'全唐诗/poet.song.91000.json','["爲寮東越肯忘年，南越相逢兩皓然。", "杜守謬容居召後，楊文那敢在王前。", "誰能狡兔營三窟，深羨神龍襲九淵。", "便合從公下吳會，濟時無術擬求田。"]'),
('54ce35f7-4265-4c30-88d1-4eac2b5a8f32','張子華屢爲唱篇有詩要予爲首唱次韻謝之二首  其一','張守','宋','宋诗','song-poetry','','[]','百篇無一可譏評，落紙銀鈎慕伯英。',64,'全唐诗/poet.song.91000.json','["百篇無一可譏評，落紙銀鈎慕伯英。", "足蹇向來甘後乘，敵勍真合避先聲。", "探驪君每珠先獲，類鶩吾慙鵠不成。", "十五大都須趙璧，無勞鼠璞換秦城。"]'),
('638977f9-bafc-49ea-9ccb-c340d263241d','張子華屢爲唱篇有詩要予爲首唱次韻謝之二首  其二','張守','宋','宋诗','song-poetry','','[]','詩名宗黨不虛傳，又復舂容見大篇。',64,'全唐诗/poet.song.91000.json','["詩名宗黨不虛傳，又復舂容見大篇。", "李蔡名甘居廣下，照隣文合在楊前。", "盤斜敢下長鯨釣，引路須煩老驥先。", "紙貴韋郎一千首，不妨頻覓浣花牋。"]'),
('bc4ede10-30ca-49b8-9cfb-2e17b9043b42','李漢老參政寄和文字韻詩次韻謝之','張守','宋','宋诗','song-poetry','','[]','高誼天涯日講聞，欲趣函丈畏深文。',64,'全唐诗/poet.song.91000.json','["高誼天涯日講聞，欲趣函丈畏深文。", "佳言阻聽霏霏屑，秀句欣披藹藹雲。", "鴛序略同慙晚遇，鑾坡並直記宵分。", "中朝多少登龍客，應擬沙堤御李君。"]'),
('917d84ad-e234-49ee-9434-b559f1e55846','楚材出示汪廷俊唱和詩次韻','張守','宋','宋诗','song-poetry','','[]','大篇作者鬭舂容，肯爲明時歎不逢。',64,'全唐诗/poet.song.91000.json','["大篇作者鬭舂容，肯爲明時歎不逢。", "通塞任分蝸兩角，唱酬應秃兔千鋒。", "光依日月從初載，名在蓬瀛第幾重。", "聯轡盍歸廊廟去，支離容我受三鍾。"]'),
('959c1428-ff1f-4c42-abf7-384001933ca3','丞相惠詩復次前韻  其一','張守','宋','宋诗','song-poetry','','[]','學道居慙邴曼容，典刑今向海邊逢。',64,'全唐诗/poet.song.91000.json','["學道居慙邴曼容，典刑今向海邊逢。", "德容璞玉長涵潤，才刃硎刀始瑩鋒。", "養壽不憂潘鬢二，趣裝行覲舜瞳重。", "期公展盡調元手，盛取勲名勒景鐘。"]'),
('9b85570f-1454-461f-be3e-e40ac6e25fcf','丞相惠詩復次前韻  其二','張守','宋','宋诗','song-poetry','','[]','開函三復似南容，入眼清詩左右逢。',64,'全唐诗/poet.song.91000.json','["開函三復似南容，入眼清詩左右逢。", "絕唱自應開奧窔，全提誰敢觸機鋒。", "朱絃清越宜三疊，寶玉森羅富五重。", "袖手吟邊無好句，冥搜空恨五更鐘。"]'),
('0e39a50a-e7cb-4901-b676-c504e5087f02','李道士惠詩次韻二首  其一','張守','宋','宋诗','song-poetry','','[]','澤國秋霖漲渺瀰，天都久客厭驅馳。',64,'全唐诗/poet.song.91000.json','["澤國秋霖漲渺瀰，天都久客厭驅馳。", "不辭短褐供萊戲，苦憶長頭課楚詞。", "帳望巾車陶靖節，浪聞推轂鄭當時。", "此身長恐儒冠誤，已媿當年學稼遲。"]'),
('8bf6c19a-8da7-41a6-87f8-2a6fc45241ee','李道士惠詩次韻二首  其二','張守','宋','宋诗','song-poetry','','[]','秋空目斷白雲飛，過隙奔駒激箭馳。',64,'全唐诗/poet.song.91000.json','["秋空目斷白雲飛，過隙奔駒激箭馳。", "愛日王符空著論，悲秋宋玉漫徴詞。", "問天擬决行藏計，擇地猶難喜懼時。", "負郭儻容供旨味，窮年衡宇足棲遲。"]'),
('2b7685f3-a2c9-4a1f-81a0-f797b2c1e63e','次川字韻','張守','宋','宋诗','song-poetry','','[]','此生休問小行年，合抱遺經老玉川。',64,'全唐诗/poet.song.91000.json','["此生休問小行年，合抱遺經老玉川。", "處世長懷方外友，羨君今作地行僊。", "風塵京洛傷羈旅，雲水江鄉渺接連。", "歸夢但隨南雁去，懶追鵰鶚上青天。"]'),
('ca878523-1c73-4ce4-90d7-374b6ca643a8','再惠詩有學仙之意次前韻','張守','宋','宋诗','song-poetry','','[]','紅塵飄轉任吾年，羞媿丹砂葛稚川。',64,'全唐诗/poet.song.91000.json','["紅塵飄轉任吾年，羞媿丹砂葛稚川。", "海上黿鼉誰可駕，淮南鷄犬故能仙。", "棄家似欲追梅福，琢句何妨學惠連。", "待爾藥爐丹就日，御風同訪洞中天。"]'),
('62adbde1-2f98-4cd0-b16b-1720f6b23f1a','雨中復惠詩仍次前韻','張守','宋','宋诗','song-poetry','','[]','性靈陶冶賴遺篇，秋水愁看灌百川。',64,'全唐诗/poet.song.91000.json','["性靈陶冶賴遺篇，秋水愁看灌百川。", "索米誰憐身是客，餐霞還恨骨非仙。", "鳥驚急雨來還去，雲敵衝風斷復連。", "好句時時慰愁絕，仰慙高義薄雲天。"]'),
('1114d0e4-b44d-4b15-8534-95117b00113b','又詩有卜荆溪之意雅合鄙懷因次韻二首  其一','張守','宋','宋诗','song-poetry','','[]','短檠心醉養生篇，擬築高峰看逝川。',64,'全唐诗/poet.song.91000.json','["短檠心醉養生篇，擬築高峰看逝川。", "野性合休林下鞅，枯腸常愧飲中仙。", "化羝未是左元放，檄虎先煩顧少連。", "何處羽衣從漫汗，君山千仞水如天。"]'),
('46507252-28c3-47f1-a63e-d6a67fce56c4','又詩有卜荆溪之意雅合鄙懷因次韻二首  其二','張守','宋','宋诗','song-poetry','','[]','心醉微言九九篇，浩如滄海翕支川。',64,'全唐诗/poet.song.91000.json','["心醉微言九九篇，浩如滄海翕支川。", "著書柱史家傳道，辟穀留侯世學僊。", "蠧簡倦推三豕渡，長弓那解兩禽連。", "極知無用宜幽隱，杜曲無田擬問天。"]'),
('a50c154a-dbb8-43b8-be01-480801e0952e','被召赴經筵途中偶成','張守','宋','宋诗','song-poetry','','[]','度嶺三年歎陸沉，一抛城市洗塵襟。',64,'全唐诗/poet.song.91000.json','["度嶺三年歎陸沉，一抛城市洗塵襟。", "雷霆激石泉聲怒，煙雨埋雲樹色深。", "食肉向無編貝齒，憂時空有未灰心。", "露門勸講高華地，倦鳥終當返故林。"]'),
('0c9441b0-ab44-4546-a223-bf1e484bcf63','汴上小雨復霽','張守','宋','宋诗','song-poetry','','[]','堤沙不起潤如酥，坐看飛雲自卷舒。',64,'全唐诗/poet.song.91000.json','["堤沙不起潤如酥，坐看飛雲自卷舒。", "麥隴人閑牛舐犢，柳陂波淺鷺窺魚。", "殘花糝徑東風後，碧草粘天暮雨初。", "分付榮枯蝸兩角，濁醪青杏送春餘。"]'),
('ae0bc5b2-e84d-4d62-a98a-2f5e39ac2d0c','伯恭要賦薌林','張守','宋','宋诗','song-poetry','','[]','相門耆舊典刑餘，戚里豪華習氣除。',64,'全唐诗/poet.song.91000.json','["相門耆舊典刑餘，戚里豪華習氣除。", "遊遍雲山行樂耳，種成香草賦歸歟。", "紉芳蘭畹餘幽佩，辟蠧芸堂有舊書。", "奎畫煌煌照林壑，只應門外看鋒車。"]'),
('3ed6c652-7330-43de-ae24-f3bd77107024','次韻李丞相園亭二首  其一','張守','宋','宋诗','song-poetry','','[]','閑築池亭古刹邊，厭將勲業寫凌煙。',64,'全唐诗/poet.song.91000.json','["閑築池亭古刹邊，厭將勲業寫凌煙。", "柳湖寄傲王摩詰，丹鼎怡神葛稚川。", "樂聖一尊濃琥珀，平戎三尺舊龍泉。", "一邱勿作淹留計，袞繡歸時席夜前。"]'),
('4e5d19ee-e1bf-4af7-b9fa-abe2abf58880','次韻李丞相園亭二首  其二','張守','宋','宋诗','song-poetry','','[]','疏泉斸石寄高懷，仙藥名花取意栽。',64,'全唐诗/poet.song.91000.json','["疏泉斸石寄高懷，仙藥名花取意栽。", "履道醉吟齊步武，平泉景物付雲來。", "菰蒲雨洗雙池净，松竹風傳萬壑哀。", "怪底茅齋頻下榻，故時賓客滿翹材。"]'),
('125ef8b7-a24a-453b-931c-b9231d48a042','僦居城南人皆笑其陋戲作因以自解','張守','宋','宋诗','song-poetry','','[]','紛紛甲第照清都，誰信蝸牛亦自廬。',64,'全唐诗/poet.song.91000.json','["紛紛甲第照清都，誰信蝸牛亦自廬。", "未厭囂塵聊近市，不湏高大擬容車。", "窺牀夜月陪清冷，入户風埃痛掃除。", "豐屋從來招鬼瞰，却因容膝得安居。"]'),
('347d4a18-39f5-4b7f-910b-90830be8795d','題洗心亭次韻','張守','宋','宋诗','song-poetry','','[]','不貯閑愁學子山，此心分付水雲間。',64,'全唐诗/poet.song.91000.json','["不貯閑愁學子山，此心分付水雲間。", "臨池罷釣魚同樂，隱几忘機鶴伴閑。", "爲喜經臺依絕境，故安禪榻面孱顔。", "洪崖仙事皆陳迹，戲說遺巾笑李寰。"]'),
('e92e4d05-4b05-419c-be8f-bbe327462d13','豫章離濟江亭','張守','宋','宋诗','song-poetry','','[]','擬上籃輿趁曉晴，不妨小立聽江聲。',64,'全唐诗/poet.song.91000.json','["擬上籃輿趁曉晴，不妨小立聽江聲。", "青山合處江疑斷，野渡喧時潮欲平。", "雨脚又從天際起，霜毛偏傍鏡邊明。", "綠林未静煩宵旰，敢爲龍鍾歎遠行。"]'),
('8629c657-2c6a-475b-a615-56d173091176','久客感懷','張守','宋','宋诗','song-poetry','','[]','自笑行藏愧古人，歸與有意坐長貧。',64,'全唐诗/poet.song.91000.json','["自笑行藏愧古人，歸與有意坐長貧。", "霜毛不種自生鬢，雲路無梯寧致身。", "春韮秋菘聊當肉，冬裘夏葛聽懸鶉。", "何當即買扁舟去，醉兀五湖煙雨春。"]'),
('c7a4a965-0b7f-4167-98a3-6d82ed72487c','夜坐觀書','張守','宋','宋诗','song-poetry','','[]','青燈隻影夜迢迢，賴有塵編洗鬱陶。',64,'全唐诗/poet.song.91000.json','["青燈隻影夜迢迢，賴有塵編洗鬱陶。", "此事長慙作吏廢，少功又笑爲儒勞。", "行藏老驥思千里，用否九牛亡一毛。", "端爲鱸魚挽幽興，擬飛煙艇破秋濤。"]'),
('ddce0c9b-ddb4-4c06-a8bb-c0512ff9c6ed','睡起戲書呈葛魯卿席大光周舉同舍諸兄','張守','宋','宋诗','song-poetry','','[]','午夢初殘日未西，人情節物睡偏宜。',64,'全唐诗/poet.song.91000.json','["午夢初殘日未西，人情節物睡偏宜。", "花開花落紛無定，春到春歸漫不知。", "香縷細縈環堵室，槐陰清翳一枰棊。", "此間粗有超然處，雕琢天真却坐詩。"]'),
('931c16bd-3a88-4a1b-8e31-2f0f31786075','春晚即事','張守','宋','宋诗','song-poetry','','[]','風條日萼半披殘，不用登臨意惘然。',64,'全唐诗/poet.song.91000.json','["風條日萼半披殘，不用登臨意惘然。", "宿麥吐芒風卷浪，垂楊吹絮暖生煙。", "送春鶯友分明語，並水鳬雛取次眠。", "觸眼風光渾有味，人生行樂且加鞭。"]'),
('87507282-1d46-42e4-9475-2c995ac3c226','早秋書事','張守','宋','宋诗','song-poetry','','[]','江城暑退葉驚秋，環堵蕭蕭草樹幽。',64,'全唐诗/poet.song.91000.json','["江城暑退葉驚秋，環堵蕭蕭草樹幽。", "掃净塵心清似水，静看人態曲如鈎。", "一尊楚醴醇無敵，半榻湘波冷欲流。", "午枕日斜呼不省，夢魂還上五湖舟。"]'),
('fb488766-817c-4de0-8dc6-44393047109f','次韻曾天猷贈知宗趙端禮展鉢詩','張守','宋','宋诗','song-poetry','','[]','幾人能信見前因，滿意肥甘豢色身。',64,'全唐诗/poet.song.91000.json','["幾人能信見前因，滿意肥甘豢色身。", "曾是鼎鐘華貴胄，肯同瓶鉢苦空人。", "招呼善友明初地，降伏心魔浄六塵。", "翻笑花間霑醉客，空看高冢卧麒麟。"]'),
('1bc657fd-8635-4220-b583-2458505f9336','送德遠樞密初召赴經筵','張守','宋','宋诗','song-poetry','','[]','長驅敵騎傍淮淝，又是忠賢許國時。',64,'全唐诗/poet.song.91000.json','["長驅敵騎傍淮淝，又是忠賢許國時。", "扶義東吳回日轂，宣威西蜀正參旗。", "暫逢貝錦辭黄閣，却續金華上赤墀。", "聯事烏臺餘病骨，仰看麟閣寫英姿。"]'),
('e6ee0419-3f7f-4918-b8b6-3a780bb65fee','舍弟寄和送行詩有倦游之歎因勉之','張守','宋','宋诗','song-poetry','','[]','幾年頭角翳蒿萊，今日寧辭盡一杯。',64,'全唐诗/poet.song.91000.json','["幾年頭角翳蒿萊，今日寧辭盡一杯。", "好向明時聊自試，莫緣荒逕憶歸來。", "白頭休歎從人後，青眼多應爲汝開。", "老去豈堪頻作惡，風帆目斷首空回。"]'),
('3165f81c-0e64-4889-b3e7-7c58e9487872','和人晚秋白菊','張守','宋','宋诗','song-poetry','','[]','溥溥清露洗殘粧，静倚疏籬暗吐芳。',64,'全唐诗/poet.song.91000.json','["溥溥清露洗殘粧，静倚疏籬暗吐芳。", "不逐黄花候秋節，笑看殷葉隕風霜。", "寒潭誰致南陽種，晚景宜登靖節堂。", "我對冰姿賡雪唱，騎騾無計度飛黄。"]'),
('d22e7833-6b84-42ac-ad04-a23f4609f951','遊鳳池寺','張守','宋','宋诗','song-poetry','','[]','鳳去池荒今幾年，碧梧翠竹故依然。',64,'全唐诗/poet.song.91000.json','["鳳去池荒今幾年，碧梧翠竹故依然。", "鳴簷流水涓涓下，排闥羣山袞袞前。", "幸有清風繼蓮社，不堪斜日近虞淵。", "歸途滿眼春耕了，勸課無功愧力田。"]'),
('36e17de7-5754-462f-b802-bb17918d8132','友人惠猩猩毛筆一枝秃甚作詩戲之','張守','宋','宋诗','song-poetry','','[]','猩毛意重鵝毛贈，老不中書一悵然。',64,'全唐诗/poet.song.91000.json','["猩毛意重鵝毛贈，老不中書一悵然。", "宜付削毫貧鄭灼，政堪握筆晉僧虔。", "判冥即合防抛失，瘞塜寧甘便棄捐。", "瓦研蓬窗吾臭味，秃翁相對且忘年。"]'),
('d0dbd54c-6d7d-413d-9f58-967f8bd905b5','婢子翻羮','張守','宋','宋诗','song-poetry','','[]','杯羮卓午薦朝餐，一飽龜腸亦爾難。',64,'全唐诗/poet.song.91000.json','["杯羮卓午薦朝餐，一飽龜腸亦爾難。", "窮鬼還來調韓愈，夫人真欲試劉寛。", "尚餘食案韭三種，早悟官亭鱠兩盤。", "傳語廚人莫轑釡，不應餓死悔儒冠。"]'),
('0ddf7322-9a58-4a2e-8199-bd1a4756fc8b','李似矩尚書挽詞二首  其一','張守','宋','宋诗','song-poetry','','[]','元禮清門有四龍，雲孫遠跨舊家風。',64,'全唐诗/poet.song.91000.json','["元禮清門有四龍，雲孫遠跨舊家風。", "持荷入侍聲名早，仗鉞宣威節制雄。", "晚歲獨抛塵鞅外，高懷聊寄藥爐中。", "堂堂玉樹埋黄壤，何事凌煙欠此公。"]'),
('26d8a19a-659d-4d32-9cc1-41a6786dbb8a','李似矩尚書挽詞二首  其二','張守','宋','宋诗','song-poetry','','[]','只今耆舊幾晨星，又失三朝一老成。',64,'全唐诗/poet.song.91000.json','["只今耆舊幾晨星，又失三朝一老成。", "許國忠規關社稷，絕塵奇表照簪纓。", "秖應鼎裏金丹就，無復廷中革履聲。", "才大故難供世用，空餘拱木翳佳城。"]'),
('d124551b-a890-4687-9ac1-81b67284c6a5','胡進彦挽詞','張守','宋','宋诗','song-poetry','','[]','剸煩餘刃發硎刀，使節藩符久漫勞。',64,'全唐诗/poet.song.91000.json','["剸煩餘刃發硎刀，使節藩符久漫勞。", "腰綬六朝知壽考，懸車一紀足清高。", "光陰不用悲駒隙，温凊無違有鳳毛。", "晚綴葭莩公已病，送行無路首空搔。"]'),
('2f2f95a2-44ac-4b87-ba1c-a2d7e03b044d','惠彦光挽詞','張守','宋','宋诗','song-poetry','','[]','聲馳太學俊游先，膏火窮年味絕編。',64,'全唐诗/poet.song.91000.json','["聲馳太學俊游先，膏火窮年味絕編。", "百戰收名丹桂籍，一麾送老白雲邊。", "心閑要路門無轍，歲惡窮閻爨有煙。", "全福略無毫髪恨，更餘身後一經傳。"]'),
('ceb773a1-c81a-46d4-981b-8164926740eb','趙約不遠千里命駕相過中道寄示三詩姑和答一篇','張守','宋','宋诗','song-poetry','','[]','霅水論交今有誰，兩翁華髪映朝衣。',64,'全唐诗/poet.song.91000.json','["霅水論交今有誰，兩翁華髪映朝衣。", "功名晼晚君流落，衰病栖遲我倦飛。", "叔夜相思能肯顧，子猷乘興却言歸。", "人生動是參商别，三復清詩對落暉。"]'),
('af918be3-dcd7-4690-9ea6-f828fbfbd7f8','題明皇聯鑣圖','張守','宋','宋诗','song-poetry','','[]','風流誰復似三郎，並轡春風輦路香。',32,'全唐诗/poet.song.91000.json','["風流誰復似三郎，並轡春風輦路香。", "漫說宫中行樂祕，畫圖千古記興亡。"]'),
('8fffc92e-1f4c-4802-8338-0acea8577904','戲題四老堂十首  其一','張守','宋','宋诗','song-poetry','','[]','四老堂中四老人，飽經喪亂始收身。',32,'全唐诗/poet.song.91000.json','["四老堂中四老人，飽經喪亂始收身。", "蒼顔鶴髪團欒坐，知是時平有幸民。"]'),
('1d7f2f06-fefc-450f-bb9b-99ce89c0e739','戲題四老堂十首  其二','張守','宋','宋诗','song-poetry','','[]','兄弟當年七業興，精神如鶴齒如冰。',32,'全唐诗/poet.song.91000.json','["兄弟當年七業興，精神如鶴齒如冰。", "升沈存没今如許，且作隨堂粥飯僧。"]'),
('a1f72309-d5bc-4003-acd2-c2f381a3728f','戲題四老堂十首  其三','張守','宋','宋诗','song-poetry','','[]','已是平頭六十人，江湖身老寸心存。',32,'全唐诗/poet.song.91000.json','["已是平頭六十人，江湖身老寸心存。", "明窗净几翻經卷，深炷爐香答主恩。"]'),
('365cda4b-891b-43c9-be6f-0c153c15963c','戲題四老堂十首  其四','張守','宋','宋诗','song-poetry','','[]','一派荆溪過枕前，喜從人境得幽偏。',32,'全唐诗/poet.song.91000.json','["一派荆溪過枕前，喜從人境得幽偏。", "直疑身在煙波上，卧送飛帆落照邊。"]'),
('894401de-2298-4b11-9269-cb3020743cd8','戲題四老堂十首  其五','張守','宋','宋诗','song-poetry','','[]','堂後堂前竹與梅，老人多半手親栽。',32,'全唐诗/poet.song.91000.json','["堂後堂前竹與梅，老人多半手親栽。", "何時更作閑花草，亦遣羣芳次第開。"]'),
('da3c9734-18ce-4e82-aa75-eeed07384651','戲題四老堂十首  其六','張守','宋','宋诗','song-poetry','','[]','四時花草逐時新，袞袞年華過眼頻。',32,'全唐诗/poet.song.91000.json','["四時花草逐時新，袞袞年華過眼頻。", "景物無窮人自老，新花應解笑迎人。"]'),
('d68aa8fc-4569-4576-853d-7d3a2ebc5625','戲題四老堂十首  其七','張守','宋','宋诗','song-poetry','','[]','繫舟長傍柳堤陰，曳杖時穿竹徑深。',32,'全唐诗/poet.song.91000.json','["繫舟長傍柳堤陰，曳杖時穿竹徑深。", "薙草澆花課僮僕，更無餘事可關心。"]'),
('dcf332bb-f58d-4290-a8ee-b490709aedc1','戲題四老堂十首  其八','張守','宋','宋诗','song-poetry','','[]','多病經時不著冠，岸巾長對倦雲閑。',32,'全唐诗/poet.song.91000.json','["多病經時不著冠，岸巾長對倦雲閑。", "年來衰謝交遊絕，靖節柴門不用關。"]'),
('0d4603c3-8a1d-4ff0-8ae7-e8fdacb07ec0','戲題四老堂十首  其九','張守','宋','宋诗','song-poetry','','[]','鶴養丹成鹿養茸，羣呦對舞傍衰慵。',32,'全唐诗/poet.song.91000.json','["鶴養丹成鹿養茸，羣呦對舞傍衰慵。", "待看仙骨他年就，同訪蓬萊第一峰。"]'),
('265b39f4-cc47-4d74-b077-be8957e96006','戲題四老堂十首  其一○','張守','宋','宋诗','song-poetry','','[]','商嶺偷生計已疏，橘中樂事亦區區。',32,'全唐诗/poet.song.91000.json','["商嶺偷生計已疏，橘中樂事亦區區。", "洛陽耆舊今黄壤，會有人傳四老圖。"]'),
('a38abeec-9722-442d-a8e5-f995f2f71382','題茘枝亭','張守','宋','宋诗','song-poetry','','[]','色味清香美莫名，更憐圓樹碧亭亭。',32,'全唐诗/poet.song.91000.json','["色味清香美莫名，更憐圓樹碧亭亭。", "結根得所天然勝，爲對三台第一星。"]'),
('221f7f40-09c5-44c2-8677-808c0c2c73a2','竹亭詩和韻','張守','宋','宋诗','song-poetry','','[]','直上煙霄碧玉抽，静搖月露冷光浮。',32,'全唐诗/poet.song.91000.json','["直上煙霄碧玉抽，静搖月露冷光浮。", "堂堂勁節冰霜後，元老如今有壯猷。"]'),
('45bcf01e-a80c-4bcd-bac3-17c840d79777','和答錢文高四首  其一','張守','宋','宋诗','song-poetry','','[]','閉門不復過高軒，夢蝶悠揚栩栩然。',32,'全唐诗/poet.song.91000.json','["閉門不復過高軒，夢蝶悠揚栩栩然。", "睡起杖藜經略彴，静看鷗鷺浴晴川。"]'),
('cd404ad2-42a6-4f2f-bb9d-4ba50f5374cc','和答錢文高四首  其二','張守','宋','宋诗','song-poetry','','[]','毣毣精思愧鮑宣，如如不動契金仙。',32,'全唐诗/poet.song.91000.json','["毣毣精思愧鮑宣，如如不動契金仙。", "回觀争奪紛華地，已老吳蠶不復眠。"]'),
('d75d6c9a-95c6-46e7-8e92-dd6bf4b799f4','和答錢文高四首  其三','張守','宋','宋诗','song-poetry','','[]','跡抛朝市不妨清，心照空華故自明。',32,'全唐诗/poet.song.91000.json','["跡抛朝市不妨清，心照空華故自明。", "但憶滄浪時鼓枻，肯從金谷聽鳴筝。"]'),
('e2234665-483c-4067-a806-5d67eb4ee815','和答錢文高四首  其四','張守','宋','宋诗','song-poetry','','[]','覓句高攀孟浩然，藏經遠慕漢韋賢。',32,'全唐诗/poet.song.91000.json','["覓句高攀孟浩然，藏經遠慕漢韋賢。", "深林小隱成幽趣，我得爲隣愧子先。"]'),
('f8c881e6-669f-49bc-be93-5beb455467b0','和答諸兄弟四首  其一','張守','宋','宋诗','song-poetry','','[]','昔向丹墀侍玉軒，略無裨補髪蒼然。',32,'全唐诗/poet.song.91000.json','["昔向丹墀侍玉軒，略無裨補髪蒼然。", "元非食肉封侯相，合抱遺經老玉川。"]'),
('3f01e089-e69f-4412-9ca9-9bce1ac7b836','和答諸兄弟四首  其二','張守','宋','宋诗','song-poetry','','[]','三州皇化未能宣，山水清奇記九仙。',32,'全唐诗/poet.song.91000.json','["三州皇化未能宣，山水清奇記九仙。", "白首弟兄長掛夢，喜聽夜雨對床眠。"]'),
('c47b486e-30f1-4b59-af3f-1fcfe94850d2','和答諸兄弟四首  其三','張守','宋','宋诗','song-poetry','','[]','門對芙渠碧沼清，蕭蕭五柳似淵明。',32,'全唐诗/poet.song.91000.json','["門對芙渠碧沼清，蕭蕭五柳似淵明。", "遠聽林壑風鳴籟，戲看兒童草鼓筝。"]'),
('7ffcc9e5-1d9d-40f8-9e7c-0c39a136d7d0','和答諸兄弟四首  其四','張守','宋','宋诗','song-poetry','','["\u897f\u6e56"]','通塞升沈亦偶然，山林高卧更稱賢。',32,'全唐诗/poet.song.91000.json','["通塞升沈亦偶然，山林高卧更稱賢。", "似聞小築西湖上，擇勝渾輸一著先。"]'),
('e33458fe-c77e-43e2-b65a-9bb1d37ff515','族叔祖示四絕句次韻  其一','張守','宋','宋诗','song-poetry','','[]','摧頽病鶴怕乘軒，歸路風帆任渺然。',32,'全唐诗/poet.song.91000.json','["摧頽病鶴怕乘軒，歸路風帆任渺然。", "環堵故能容兩膝，掃除荒徑老斜川。"]'),
('d58da0c2-f896-48fc-a2e6-5f831b86eba4','族叔祖示四絕句次韻  其二','張守','宋','宋诗','song-poetry','','[]','不樂從軍學仲宣，那能辟穀慕飛僊。',32,'全唐诗/poet.song.91000.json','["不樂從軍學仲宣，那能辟穀慕飛僊。", "直緣衰病干明主，乞得南窗一覺眠。"]'),
('f069bed9-37ce-4c40-ad9b-f5d67a4543d4','族叔祖示四絕句次韻  其三','張守','宋','宋诗','song-poetry','','[]','衰懷底物能陶寫，社舞村歌眼暫明。',32,'全唐诗/poet.song.91000.json','["衰懷底物能陶寫，社舞村歌眼暫明。", "誰似玉人供巧笑，不勞長笛與哀筝。"]'),
('6de62ef5-2b67-4a5c-9991-d61e89dc43c6','族叔祖示四絕句次韻  其四','張守','宋','宋诗','song-poetry','','[]','追陪杖履已悠然，把玩詩篇更覺賢。',32,'全唐诗/poet.song.91000.json','["追陪杖履已悠然，把玩詩篇更覺賢。", "局上頻煩問瓜葛，吟邊端不敢争先。"]'),
('5cbfc2d9-1d74-443a-914c-38fbbc036f65','送客','張守','宋','宋诗','song-poetry','','[]','南渡登舟即水仙，西垣有客思悠然。',32,'全唐诗/poet.song.91000.json','["南渡登舟即水仙，西垣有客思悠然。", "因君相問爲官意，不買毘陵附郭田。"]'),
('dff68f8f-2de5-4784-926c-34becea01493','雙蓮閣','張守','宋','宋诗','song-poetry','','[]','小閣幽深枕淺波，直疑湘水見英娥。',32,'全唐诗/poet.song.91000.json','["小閣幽深枕淺波，直疑湘水見英娥。", "不將詩酒頻料理，奈此風前二妙何。"]'),
('7ad8c875-947a-45f8-90a7-c399ea0c6382','花塢','張守','宋','宋诗','song-poetry','','[]','意匠潛符造物工，笑談花塢出榛叢。',32,'全唐诗/poet.song.91000.json','["意匠潛符造物工，笑談花塢出榛叢。", "風條日萼隨時看，須信春藏指掌中。"]'),
('164b0e18-47b6-4537-9155-505f90af9b07','桂齋','張守','宋','宋诗','song-poetry','','[]','月裏移根傍小齋，不惟收子看花開。',32,'全唐诗/poet.song.91000.json','["月裏移根傍小齋，不惟收子看花開。", "搗香篩辣歸春甕，凖擬高人勝士來。"]'),
('41f674f9-c992-4d9d-b264-f60c533c239f','蘭室','張守','宋','宋诗','song-poetry','','[]','分得騷人九畹香，時人不服更幽芳。',32,'全唐诗/poet.song.91000.json','["分得騷人九畹香，時人不服更幽芳。", "小窗低户維摩室，苒苒奇芬春晝長。"]'),
('fd7c93ec-73de-4335-9b88-883445ee5f17','夢室','張守','宋','宋诗','song-poetry','','[]','笑取功名指顧間，歸來心與倦雲閑。',32,'全唐诗/poet.song.91000.json','["笑取功名指顧間，歸來心與倦雲閑。", "閉關不作南柯想，睡起香凝金愽山。"]'),
('2dabca5d-73a8-4b9a-a1b2-d6ed001c2c35','罷酒','張守','宋','宋诗','song-poetry','','[]','罷酒尋花涉斷磯，顛躋猶復强褰衣。',32,'全唐诗/poet.song.91000.json','["罷酒尋花涉斷磯，顛躋猶復强褰衣。", "可憐醉眼無分别，却把傍邊柳折歸。"]'),
('36f4286e-ed69-4ca9-8190-68b2d5f28d27','圭沼','張守','宋','宋诗','song-poetry','','[]','方銳新池卧介圭，水光如玉夜騰輝。',32,'全唐诗/poet.song.91000.json','["方銳新池卧介圭，水光如玉夜騰輝。", "不應只作韓侯覲，更喜姬公著袞衣。"]'),
('34dc2306-fe0d-44be-ba68-a28174299e7c','人惠方竹杖','張守','宋','宋诗','song-poetry','','[]','多病扶笻老自便，得君方竹更輕堅。',32,'全唐诗/poet.song.91000.json','["多病扶笻老自便，得君方竹更輕堅。", "平生正以方爲累，擬付山僧任削圓。"]'),
('bdd2eb8d-abc5-4871-b26d-cc20d98fac99','菖蒲澗','張守','宋','宋诗','song-poetry','','[]','蟠根带石傲年芳，秋雨春風拂水長。',32,'全唐诗/poet.song.91000.json','["蟠根带石傲年芳，秋雨春風拂水長。", "不用引年勞服食，相公勲業似汾陽。"]'),
('bd4aea6c-c095-4cc8-8819-b98f2037e4db','題崔慤畫','張守','宋','宋诗','song-poetry','','[]','風折枯荷蘆葦秋，蕭蕭鸂鶒上沙洲。',32,'全唐诗/poet.song.91000.json','["風折枯荷蘆葦秋，蕭蕭鸂鶒上沙洲。", "關心滿眼江湖趣，何日扁舟得自由。"]'),
('1373c57c-6534-425e-a6af-72c52812c899','建炎丞相呂忠穆公退老堂詩  其一','張守','宋','宋诗','song-poetry','','[]','大老歸周慶有源，中興吾宋屬雲孫。',64,'全唐诗/poet.song.91000.json','["大老歸周慶有源，中興吾宋屬雲孫。", "五龍夾日三辰正，一虎當溪百獸奔。", "何事雲山遽招隱，向來金鼎厭調元。", "追鋒早晚求黄髪，三徑還荒靖節園。"]'),
('51b726ab-330e-4adc-9cf5-87aec89b7f21','建炎丞相呂忠穆公退老堂詩  其二','張守','宋','宋诗','song-poetry','','[]','聞道抽身向急流，海邊暫艤濟川舟。',64,'全唐诗/poet.song.91000.json','["聞道抽身向急流，海邊暫艤濟川舟。", "功存社稷推元老，人向漁樵識故侯。", "綠野江山供笑傲，赤松儔侶伴淹留。", "閑棋小酌懷疇昔，清夢時追杖履遊。"]'),
('be127e79-1749-467a-8438-1b49e8470788','席大光邀同賦墨梅花  其一','張守','宋','宋诗','song-poetry','','[]','鏤冰斵雪賦精神，不受丹青一點塵。',32,'全唐诗/poet.song.91000.json','["鏤冰斵雪賦精神，不受丹青一點塵。", "施粉故應嫌太白，謾憑水墨見天真。"]'),
('296cd1ee-1ad9-4604-a08e-be98b3e25de2','席大光邀同賦墨梅花  其二','張守','宋','宋诗','song-poetry','','[]','騷人洗硯試松煙，造化鑪錘貯筆端。',32,'全唐诗/poet.song.91000.json','["騷人洗硯試松煙，造化鑪錘貯筆端。", "春破南枝入詩眼，句成祇許畫中看。"]'),
('a4afacfe-ecb9-4759-8d43-e501c14db883','席大光邀同賦墨梅花  其三','張守','宋','宋诗','song-poetry','','[]','笑揮墨妙當鉛華，真是天然玉雪花。',32,'全唐诗/poet.song.91000.json','["笑揮墨妙當鉛華，真是天然玉雪花。", "月冷霜清春不管，一枝寒影墮溪斜。"]'),
('b5626562-0b64-474a-b968-bf9d4f873a5a','席大光邀同賦墨梅花  其四','張守','宋','宋诗','song-poetry','','["\u897f\u6e56"]','墨白何妨俗眼疑，寫真妙處足天機。',32,'全唐诗/poet.song.91000.json','["墨白何妨俗眼疑，寫真妙處足天機。", "橫斜疏影黄昏月，貌盡西湖處士詩。"]'),
('970cec02-865d-49ef-87dd-aacf69f4ea13','席大光邀同賦墨梅花  其五','張守','宋','宋诗','song-poetry','','[]','墨竹文翁舊寫真，墨梅顔子更超群。',32,'全唐诗/poet.song.91000.json','["墨竹文翁舊寫真，墨梅顔子更超群。", "我家幸有篔簹谷，乞取冰姿伴此君。"]'),
('33b83b21-0346-417c-9473-7008bf3794eb','席大光邀同賦墨梅花  其六','張守','宋','宋诗','song-poetry','','[]','故園雪樹想彫零，卻向毫端見典型。',32,'全唐诗/poet.song.91000.json','["故園雪樹想彫零，卻向毫端見典型。", "夢破江南愁絕處，前村煙迥雨冥冥。"]'),
('4c3024cc-7d11-4b4c-99ab-6a643de68bd1','魚樂亭','張守','宋','宋诗','song-poetry','','[]','乃公倦經綸，結□俯滄浪。',48,'全唐诗/poet.song.91000.json','["乃公倦經綸，結□俯滄浪。", "風波不到處，修鱗自徜祥。", "一與芳餌辭，此樂殊未央。", "借問那得知，吾人亦相忘。"]'),
('860f7950-b900-44bc-bcb4-79f6e1481a40','暮步至江上','呂本中','宋','宋诗','song-poetry','','[]','客事久輸鸚鵡盃，春愁如接鳳凰臺。',64,'全唐诗/poet.song.91000.json','["客事久輸鸚鵡盃，春愁如接鳳凰臺。", "樹陰不礙帆影過，雨氣却隨潮信来。", "山似故人堪對飲，花如遺恨不重開。", "雪籬風榭年年事，辜負風光取次回。"]'),
('0d8eb77a-d574-4bfb-88ac-b49ac0f20392','題張君墨竹','呂本中','宋','宋诗','song-poetry','','[]','張卿畫竹今成癖，笑語揮毫不作難。',64,'全唐诗/poet.song.91000.json','["張卿畫竹今成癖，笑語揮毫不作難。", "欻見高標起蕭瑟，坐令炎暑變荒寒。", "筆頭似有千年韻，胸次猶須萬斛寛。", "歲晚雪霜君記取，此君懷抱要重看。"]'),
('16868cdb-feef-4891-ac2e-55c4b25558b4','陰','呂本中','宋','宋诗','song-poetry','','[]','涼風森爽遽如許，天氣蕭條殊未佳。',64,'全唐诗/poet.song.91000.json','["涼風森爽遽如許，天氣蕭條殊未佳。", "密逕留陰□□竹，敗畦藏雨鬬蛙蟆。", "碧雲莫合人千里，丹鳳□□天一涯。", "唯有雙叢庭下菊，殷勤還作去年花。"]'),
('2823e0be-a7fb-4a7e-9a5f-9c9127655831','符離諸賢詩','呂本中','宋','宋诗','song-poetry','','[]','窮居日荒涼，杜門與世絕。',156,'全唐诗/poet.song.91000.json','["窮居日荒涼，杜門與世絕。", "親故日夜疏，詩書固宜缺。", "符離雖陋邦，賢士稍羅列。", "德操青雲器，議論輩前哲。", "外貌發英華，中心瑩冰雪。", "介然特立士，勁氣剛于鐵。", "攘臂辯是非，孰能逃區别。", "信民粹而和，名利誠難悅。", "汩沒稠人中，獨抱雲松節。", "偉哉二三子，實乃邦家傑。", "我来從之游，內顧慙疏拙。", "欣然對三益，放懷歌數闋。", "已矣不須言，渠當爲君說。"]'),
('619e5da7-11db-41bf-b898-32d79c36bcb7','德操充之皆約九月間見過今皆未至扶杖出門悠然有感','呂本中','宋','宋诗','song-poetry','','[]','病着文書懶出門，偶扶藜杖看行雲。',64,'全唐诗/poet.song.91000.json','["病着文書懶出門，偶扶藜杖看行雲。", "屋頭日在轉花影，水面風来散縠紋。", "不厭莫城千嶂合，稍令明月萬家分。", "小庭留得清秋在，已見霜紅未見君。"]'),
('b98e5d09-7f40-4b5d-8e95-b4ea563df362','遊劉氏園','呂本中','宋','宋诗','song-poetry','','[]','暖日温風破淺寒，短青無數簇幽蘭。',32,'全唐诗/poet.song.91000.json','["暖日温風破淺寒，短青無數簇幽蘭。", "三年止酒償春意，可忍花梢带面看。"]'),
('a8a6e592-fe04-48cf-8cb9-9dc56d123775','上元','呂本中','宋','宋诗','song-poetry','','[]','步屧荒園日已昏，呼兒當逕掃苔痕。',32,'全唐诗/poet.song.91000.json','["步屧荒園日已昏，呼兒當逕掃苔痕。", "春愁不作遊人地，細雨殘梅過上元。"]'),
('8ebfb5bc-da88-4843-805b-0c6efca33458','柳','呂本中','宋','宋诗','song-poetry','','[]','含烟带雨過平橋，嫋嫋千絲復萬條。',32,'全唐诗/poet.song.91000.json','["含烟带雨過平橋，嫋嫋千絲復萬條。", "張令當年緣底事，風流才似女兒腰。"]'),
('63eb3de5-a3bb-4bfb-905a-5f26a420d494','喜雨','呂本中','宋','宋诗','song-poetry','','[]','天乞幽人一夜涼，故教微雨送斜陽。',64,'全唐诗/poet.song.91000.json','["天乞幽人一夜涼，故教微雨送斜陽。", "暝陰籠樹山更好，爽氣侵人土自香。", "多病不眠唯藥裹，居閑長坐只繩牀。", "五年謬作江湖客，幾對鱸魚憶故鄉。"]'),
('5b877539-769e-4845-a925-e5fbf688f048','舍東舊有花數百株自去歲大雨道路阻絕不復可尋感歎成詩','呂本中','宋','宋诗','song-poetry','','[]','無數新花替舊叢，兔葵高卧占春風。',32,'全唐诗/poet.song.91000.json','["無數新花替舊叢，兔葵高卧占春風。", "向来桃李成蹊處，今在陂塘渺莽中。"]'),
('bd480e51-50e8-4773-95ea-f91cf8faea29','送文潛歸因成一絕奉寄','呂本中','宋','宋诗','song-poetry','','[]','水天空闊片帆開，野岸蕭條送騎回。',32,'全唐诗/poet.song.91000.json','["水天空闊片帆開，野岸蕭條送騎回。", "重到張公泊船處，小亭春在鎖青苔。"]'),
('e09a391f-ea6b-4194-aeff-725dbea01d21','謝人送牡丹','呂本中','宋','宋诗','song-poetry','','[]','晚風初染嫩鵝黄，小雨仍添百和香。',32,'全唐诗/poet.song.91000.json','["晚風初染嫩鵝黄，小雨仍添百和香。", "折與病夫元不稱，玉瓶留待冶游郎。"]'),
('6469cc47-b85e-4545-8674-001677749c47','宿州初暑','呂本中','宋','宋诗','song-poetry','','[]','暑氣侵人始欲愁，簞瓢窮巷不堪憂。',64,'全唐诗/poet.song.91000.json','["暑氣侵人始欲愁，簞瓢窮巷不堪憂。", "亂蟬泊雨林塘静，密逕吹花草樹幽。", "春盡茅簷深着燕，日高田水故飛鷗。", "莫欺湫隘無餘地，待借元龍百尺樓。"]'),
('9cad4325-df82-4154-95b4-3fc2f225b295','夏日書事','呂本中','宋','宋诗','song-poetry','','[]','小行畏蛇蝎，端坐困蚊蚋。',78,'全唐诗/poet.song.91000.json','["小行畏蛇蝎，端坐困蚊蚋。", "終日方丈間，茫然豈唯供。", "病本兼恐添，藥費小園新。", "雨餘蔬畦共，飽聞譍門柳。", "清陰妙無對，便思攜杖往。", "行歌當游戲。", "千秋陶淵明，此意渠亦會。"]'),
('4cd6165e-1b62-41c0-a241-84b6974ccbb0','寄吉州若谷叔','呂本中','宋','宋诗','song-poetry','','[]','念我江西老斵輪，久無漫鼻與揮斤。',32,'全唐诗/poet.song.91000.json','["念我江西老斵輪，久無漫鼻與揮斤。", "千金莫買蛾眉笑，留寄溪堂病主人。"]'),
('390a5bd7-2be3-4bf4-9d32-27fddc79cb91','寄汪信民','呂本中','宋','宋诗','song-poetry','','[]','萬里江南雨外船，長腰秔米縮頭鯿。',32,'全唐诗/poet.song.91000.json','["萬里江南雨外船，長腰秔米縮頭鯿。", "廣文繋馬無由去，更有何人贈酒錢。"]'),
('49b9f861-4e02-41a4-a7f4-0913e81a1611','同諸子游城東園','呂本中','宋','宋诗','song-poetry','','[]','昔聞城東園，欲往常不款。',132,'全唐诗/poet.song.91000.json','["昔聞城東園，欲往常不款。", "今来天氣佳，茶甌起衰懶。", "杖藜出門去，如膜開病眼。", "木葉犯新霜，瓜田带餘暖。", "川源疑有無，風雲遞舒卷。", "不期魚鳥會，偶逐鷗鷺遠。", "淺水亂菰蒲，荒亭秀苔蘚。", "青山近在望，更悟秋意晚。", "同行二三子，詩語各蕭散。", "不愁罰觴難，苦恨白日短。", "千秋高陽池，令人憶山簡。"]'),
('d8cbc0e7-0a01-41f5-8f4e-58543f451ac2','楊道孚墨竹歌','呂本中','宋','宋诗','song-poetry','','[]','君不見渭川之陰卧龍横千秋，貌取者誰文湖州。',197,'全唐诗/poet.song.91000.json','["君不見渭川之陰卧龍横千秋，貌取者誰文湖州。", "十年筆意閉黄壤，只今妙手唯楊侯。", "楊侯畫竹盡真跡，功奪造化令人愁。", "滿堂迴頭看下筆，擾擾雲烟亂晴日。", "大叢縱横高入雲，斜風落葉秋紛紛。", "小叢欹傾病無力，傍水長根走蒼石。", "門前車馬汗成川，何得陰風動高壁。", "楊侯嘻笑辭未工，此意不與丹青同。", "粉黛初數無一錢費，酒炙能使千家空。", "襪材遠寄動盈屋，我子畫無由窮。", "剡溪寒藤不難致，須君放手爲雙叢。", "須君放手爲雙叢，與我俱隱南山中。"]'),
('3ef6c7ea-a31f-41e0-8131-488bfbb32bff','謝無逸秦處度諸人皆許省試後見訪冬夜有懷作此詩寄之','呂本中','宋','宋诗','song-poetry','','[]','八年去東都，觸事無一好。',144,'全唐诗/poet.song.91000.json','["八年去東都，觸事無一好。", "沈綿淹歲時，憂虞滿懷抱。", "欲歸故里閭，稀復舊耆老。", "悠悠歲欲盡，忽忽身向老。", "小堂佳有餘，所恨来不早。", "饑蟲語夜霜，疏星亂衰草。", "支撐壞壁高，側轉寒木小。", "詩書久棄置，詞林迹如掃。", "佳人何時来，路遠音信少。", "庭前冬開花，扶杖起千繞。", "春風回馬首，清尊待君倒。", "先期留酒錢，仍須具梨棗。"]'),
('e0fcb2ea-a500-4c6a-87eb-5bc44d4a2ab0','歲晚','呂本中','宋','宋诗','song-poetry','','[]','野竹新開徑，疏籬自著行。',48,'全唐诗/poet.song.91000.json','["野竹新開徑，疏籬自著行。", "暮寒收雨雪，落日散牛羊。", "生事顔公拙，才名謝奕狂。", "藥囊無奈汝，春到莫相妨。"]'),
('00b7d7d9-0cd9-42a4-9ea7-21af42372b46','晚步至江上','呂本中','宋','宋诗','song-poetry','','[]','浦口生春綠未酣，南山初見碧嶃巖。',64,'全唐诗/poet.song.91000.json','["浦口生春綠未酣，南山初見碧嶃巖。", "風聲入樹翻歸鳥，月影浮江倒客帆。", "破甑不堪充酒券，短蓑真欲換朝衫。", "往来泥雨城南路，可見輕鷗定不凡。"]'),
('00396b72-2132-4b2e-80f5-19ee75fb30c8','訪晁進道歸','呂本中','宋','宋诗','song-poetry','','[]','樹陰殘雪半成泥，尚想狂花一尺圍。',64,'全唐诗/poet.song.91000.json','["樹陰殘雪半成泥，尚想狂花一尺圍。", "小雨似酥黄草盡，澄江如練白鷗飛。", "未辭酒炙爲公費，政恐親知見面稀。", "南市津頭行艓子，無人識我醉中歸。"]'),
('0fb651b4-d5d0-4580-adb7-4920199d120d','怨歌行','呂本中','宋','宋诗','song-poetry','','[]','借君手中板，爲君歌一辭。',109,'全唐诗/poet.song.91000.json','["借君手中板，爲君歌一辭。", "辭中宛轉君不曉，爲君說盡長相思。", "輕霜夜度吳城暖，楓葉蘆花秋意晚。", "萬里春隨驛使歸，十年夢逐佳人遠。", "當時笑語似兒劇，象牀玉手無消息。", "古岸風江千里船，咫尺春愁那得憐。", "君不見信陵門下客，侯嬴不用今頭白。"]'),
('39645515-7a34-4e1f-a08e-2d8107d5c0cb','雪盡','呂本中','宋','宋诗','song-poetry','','[]','雪盡寒仍在，園荒春欲歸。',48,'全唐诗/poet.song.91000.json','["雪盡寒仍在，園荒春欲歸。", "晴空落雁小，古木聚鵶稀。", "肺病猶堪酒，囊空合典衣。", "碧雲愁不見，千里故山薇。"]'),
('1450a9ca-8464-401b-a7b9-8b83efbf83d1','三月一日泊舟宿州城外因縱步至城北遂過天慶觀道士留飲乃歸','呂本中','宋','宋诗','song-poetry','','[]','冰霜連暮春，既雨寒愈重。',216,'全唐诗/poet.song.91000.json','["冰霜連暮春，既雨寒愈重。", "扁舟纜荒亭，淺水咽微凍。", "今晨稍和柔，始覺芳意動。", "經旬厭拘束，樂事須一縱。", "籃輿無俗情，鴟夷當賓從。", "千花犯濃雲，紅紫相餞送。", "未知滕薛長，乃若鄒魯鬨。", "娉婷北門柳，别淚作凄痛。", "陵陂少荒蕪，亦未妨耕種。", "道人喜我来，清談破昏夢。", "彈琴不須弦，風林助吟諷。", "嫰玉擣香秔，浮蛆撥春甕。", "嘉蔬剪朝露，奇果市新貢。", "西鄰亦可人，明窗碾雙鳳。", "人生一飽適，此外更何用。", "七年城北交，事與朱阮共。", "長詩不成篇，臨行當三弄。", "瓊瑶報木桃，爲子末後供。"]'),
('bf86f836-9e4c-4e02-a601-bf4a3d229c51','宿青陽驛','呂本中','宋','宋诗','song-poetry','','[]','燈火客帆盡，人烟村市幽。',48,'全唐诗/poet.song.91000.json','["燈火客帆盡，人烟村市幽。", "晚風號古木，高岸束黄流。", "物色淮山近，春光霧雨愁。", "棲遲舊游地，来豁十年憂。"]'),
('be72f8c9-d554-4d3b-80a6-ff6e5ee773ce','游南山歸簡張嘉父博士','呂本中','宋','宋诗','song-poetry','','[]','吾生復何往，樂事亦匆匆。',48,'全唐诗/poet.song.91000.json','["吾生復何往，樂事亦匆匆。", "寶塔千帆外，春城萬壑中。", "亂花緣側逕，晚照落晴空。", "坐想西倉老，掀髯一笑同。"]'),
('1e86055c-be73-46aa-845e-912c024c2395','書懷','呂本中','宋','宋诗','song-poetry','','[]','拄腹文章未補饑，積瘕潛愧不堪悲。',32,'全唐诗/poet.song.91000.json','["拄腹文章未補饑，積瘕潛愧不堪悲。", "兒曹怪我疏愚甚，不見田光盛壯時。"]'),
('49be0f25-1dcb-49ad-88cf-19225a46ee4f','客居書懷奉寄介然若谷才仲兼簡信民','呂本中','宋','宋诗','song-poetry','','[]','客愁如長河，浩蕩去不息。',276,'全唐诗/poet.song.91000.json','["客愁如長河，浩蕩去不息。", "未来已相關，千里在咫尺。", "抱疾寄他鄉，終年守岑寂。", "中虛耗神志，內熱損筋力。", "長虞二豎攖，復有寒餒廹。", "怪渠甑上煙，愧爾囊中帛。", "平生所讀書，已如不相識。", "坐貽鄉黨笑，敢辭塵埃没。", "舊游今幾時，轉眄忽陳迹。", "死者不復見，墓草春已碧。", "生者天一涯，未免陳蔡厄。", "兒曹乳臭在，瞑目分黑白。", "雖無未見書，頗多雌黄筆。", "出言輒周孔，而不辨菽麥。", "啾啾要酬和，內顧頗牽率。", "坐令懷抱惡，更覺天宇窄。", "忽忽十年事，俯仰同戲劇。", "從来肺腑親，翻手胡與越。", "獨餘二三子，肝膽猶鐵石。", "尚怪東郭貧，亦訝懷祖黠。", "西軒来何時，簞瓢共饑渴。", "念君不能已，一飯再三噎。", "誰能明予心，皎皎霜夜月。"]'),
('a5c82d19-2851-4e6b-b7fa-da028fbfbb79','小園','呂本中','宋','宋诗','song-poetry','','[]','小園常在眼，春事已天涯。',48,'全唐诗/poet.song.91000.json','["小園常在眼，春事已天涯。", "雨暗堤前路，苔深林外家。", "曲池通小徑，密樹隱殘花。", "長愧隣翁酒，囊空尚可賖。"]'),
('cd92ad66-5b59-4fd4-8343-e5cc4c5aa734','謁雍道士','呂本中','宋','宋诗','song-poetry','','[]','紛紛乾沒混泥沙，暫遣塵言掛齒牙。',64,'全唐诗/poet.song.91000.json','["紛紛乾沒混泥沙，暫遣塵言掛齒牙。", "妙畫已歸三語掾，壯游空記五侯家。", "古壇背日藏芳草，小樹留春放晚花。", "能共山翁同活計，隔林分聽一池蛙。"]'),
('ec204707-2720-445f-82d5-99be6e459519','春日即事二首  其一','呂本中','宋','宋诗','song-poetry','','[]','隱几虛堂俗客稀，片心真與道相宜。',64,'全唐诗/poet.song.91000.json','["隱几虛堂俗客稀，片心真與道相宜。", "風搖柳带千絲亂，雨勒花心十日期。", "瘦病才蘇休强酒，良辰雖好少題詩。", "賈生詞賦常流落，歸去来兮在幾時。"]'),
('fbbacab4-3315-4157-a0be-aa827d1861eb','春日即事二首  其二','呂本中','宋','宋诗','song-poetry','','[]','病起多情白日遲，强来庭下探花期。',64,'全唐诗/poet.song.91000.json','["病起多情白日遲，强来庭下探花期。", "雪消池館初春後，人倚欄干欲暮時。", "亂蝶狂蜂俱有意，兔葵燕麥自無知。", "池邉垂柳腰肢活，折盡長條爲寄誰。"]'),
('a8837a75-72fe-435c-9c0e-0f3040010605','寄前鎮西楊法曹','呂本中','宋','宋诗','song-poetry','','[]','楊子文章老更新，狂吟寡和過陽春。',64,'全唐诗/poet.song.91000.json','["楊子文章老更新，狂吟寡和過陽春。", "雙聲疊韻俱難敵，指物程形似有神。", "畫馬已無韓幹肉，草書真得伯英筋。", "可憐一首閑居賦，解道連蜷能幾人。"]'),
('ea26d37a-e6a6-463f-9db7-4188f31a5ec5','飲酒','呂本中','宋','宋诗','song-poetry','','[]','人生百歲能幾何，顧我把酒胡不歌。',112,'全唐诗/poet.song.91000.json','["人生百歲能幾何，顧我把酒胡不歌。", "窮通大抵夢南柯，我復夢中多蹉跎。", "自古英雄亦何有，往事紛紛不如酒。", "嗟予真得酒中趣，幾度尊前揖星斗。", "病起槐陰鸚已老，今日相逢還草草。", "匆匆數日是行人，且向尊前一傾倒。", "人生樂事亦難并，明月清風况都好。"]'),
('1de9ce81-7e63-4211-b12e-250a710b2553','讀史','呂本中','宋','宋诗','song-poetry','','[]','陳壽謂諸葛，將略非所長。',48,'全唐诗/poet.song.91000.json','["陳壽謂諸葛，將略非所長。", "私恨寫青史，千古何茫茫。", "謗議終自破，公論不可當。", "是非倘可定，青蠅果何傷。"]'),
('a8025021-6e8a-45a0-9092-d98c68d10d06','戲呈七十七叔','呂本中','宋','宋诗','song-poetry','','[]','大阮愛我詩，謂我能詩矣。',48,'全唐诗/poet.song.91000.json','["大阮愛我詩，謂我能詩矣。", "我詩来無極，愛之終不已。", "吾非聖者也，但智慮多耳。", "賜始可言詩，吾智由商起。"]'),
('be2d1233-77e3-48b1-a8a3-554a42bb1d0b','偶作','呂本中','宋','宋诗','song-poetry','','[]','去年芳草又萋萋，休歎王孫猶未歸。',32,'全唐诗/poet.song.91000.json','["去年芳草又萋萋，休歎王孫猶未歸。", "更見春深送春雁，三三兩兩傍雲飛。"]'),
('3b2b6b94-9710-43e1-ad29-bfdf71843450','謁陶朱公廟','呂本中','宋','宋诗','song-poetry','','[]','悠悠千載五湖心，古廟無人鎖綠陰。',32,'全唐诗/poet.song.91000.json','["悠悠千載五湖心，古廟無人鎖綠陰。", "爲問功成肥遯後，不知何術累千金。"]'),
('8ce3b199-2425-4b52-8367-91174d72d323','睡','呂本中','宋','宋诗','song-poetry','','[]','終日題詩詩不成，融融午睡夢頻驚。',32,'全唐诗/poet.song.91000.json','["終日題詩詩不成，融融午睡夢頻驚。", "覺來心緒都無事，牆外啼鶯一兩聲。"]'),
('3f63cc3a-fc78-488e-a2c6-ace7a713464a','夢','呂本中','宋','宋诗','song-poetry','','[]','夢入長安道，萋萋盡春草。',24,'全唐诗/poet.song.91000.json','["夢入長安道，萋萋盡春草。", "覺来春已去，一片池塘好。"]'),
('b041965c-f6f2-4037-8cfb-7e2c11fc589c','讀陶元亮傳  其一','呂本中','宋','宋诗','song-poetry','','[]','我愛陶彭澤，解言歸去来。',24,'全唐诗/poet.song.91000.json','["我愛陶彭澤，解言歸去来。", "醉眠猶遣客，却使世人猜。"]'),
('81efa4d2-6fc6-4bdb-b4ce-bfb2e9d66b27','讀陶元亮傳  其二','呂本中','宋','宋诗','song-poetry','','[]','我愛陶彭澤，不求弦上聲。',24,'全唐诗/poet.song.91000.json','["我愛陶彭澤，不求弦上聲。", "琴中如有趣，曾遣幾人聽。"]'),
('c3617c99-af72-4089-91a1-a7e6bd4484a9','寄璧上人','呂本中','宋','宋诗','song-poetry','','[]','出門厭交情，袖手看世故。',108,'全唐诗/poet.song.91000.json','["出門厭交情，袖手看世故。", "紛紛駒過隙，忽忽豹隱霧。", "生平喜退縮，未到心已悟。", "尚餘好事人，相就討新句。", "雖非琢肝腎，終自費調護。", "君看雪霜根，豈受桃李妬。", "胥疏老支離，骯髒舊賓傅。", "何由兩行纒，遠泛一大瓠。", "從君乞妙語，一洗詩酒汚。"]'),
('6ed258ed-cb78-4e4c-a7e9-b5c8b9e92e22','寄璧公道友','呂本中','宋','宋诗','song-poetry','','[]','符離城裏相逢處，酒肉如山放手空。',64,'全唐诗/poet.song.91000.json','["符離城裏相逢處，酒肉如山放手空。", "已見神通過鶖子，未應鮮健勝龐公。", "且尋扇子舊頭角，一任杏花能白紅。", "破箬笠前江萬里，無人曾識此家風。"]'),
('9684e9a0-d977-4b99-8cd4-b4eeecab3587','用前韻寄商老','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','先生昔據道玄峰，咳唾珠玉家爲空。',64,'全唐诗/poet.song.91000.json','["先生昔據道玄峰，咳唾珠玉家爲空。", "只今江西二三子，可到元和六七公。", "雙髩只期他日白，千花猶是去年紅。", "須君吸盡西江水，不假扶搖萬里風。"]'),
('7a72f0d3-7d56-4efa-b606-86eebdbfcb06','又寄無逸信民','呂本中','宋','宋诗','song-poetry','','[]','文字撐腸不療窮，詩来想見左書空。',64,'全唐诗/poet.song.91000.json','["文字撐腸不療窮，詩来想見左書空。", "雖非問道暏狂屈，猶勝遺書訪子公。", "銀杯久拚浮大白，桃花且看舒小紅。", "記取浮盃無剩語，他年說似馬牛風。"]'),
('d7a94e14-c680-4097-accb-7aa33458bb00','奉答璧公兼簡諸友','呂本中','宋','宋诗','song-poetry','','[]','江山取别太匆匆，對面難尋一段空。',64,'全唐诗/poet.song.91000.json','["江山取别太匆匆，對面難尋一段空。", "顧我自無黄閣様，如君合是黑頭公。", "客塵袞袞催前浪，俗眼紛紛替舊紅。", "炙日茅簷那接膝，重来肯借一帆風。"]'),
('747bf834-4e86-43e7-91e1-44bfb2a582c3','得李去言詩次韻答之','呂本中','宋','宋诗','song-poetry','','[]','歌呼屢回曹相國，牋書或似魏司空。',64,'全唐诗/poet.song.91000.json','["歌呼屢回曹相國，牋書或似魏司空。", "半生懷抱向餘子，千載風流獨此公。", "未用反身藏白黑，更須着眼辨青紅。", "無人與助求田費，雅稱謝家林下風。"]'),
('dcec001e-1f58-40cc-9218-bb24827e2c2a','督山伯蕭遠和詩并示舍弟','呂本中','宋','宋诗','song-poetry','','[]','愛閑多病老封戎，看子垂天上碧空。',64,'全唐诗/poet.song.91000.json','["愛閑多病老封戎，看子垂天上碧空。", "懶惰未須攀此老，典刑政爾賴諸公。", "鬚如震澤三春淥，詩似芙蕖五月紅。", "坐此逃禪夫可恕，不應獨許我乘風。"]'),
('93d20062-d390-4d43-b98a-1151c41675d6','用寄璧上人韻寄范元實趙才仲及從叔知止兼率山伯同賦','呂本中','宋','宋诗','song-poetry','','[]','故人瓶錫各西東，吾道從来冀北空。',64,'全唐诗/poet.song.91000.json','["故人瓶錫各西東，吾道從来冀北空。", "病去漸于文字懶，南来猶覺歲時公。", "江回夜雨千巖黒，霜着高林萬葉紅。", "政好還家君未肯，莫教慚愧北窗風。"]'),
('b8b5a3cd-ab41-46e4-9a80-8394d9fd00d7','夜作呈諸公','呂本中','宋','宋诗','song-poetry','','[]','風江舞暮帆，野樹散歸鳥。',84,'全唐诗/poet.song.91000.json','["風江舞暮帆，野樹散歸鳥。", "寒燈上壁角，疏星綴林杪。", "歸來静無事，獨坐搜黙藁。", "放筆有新功，無人與傾倒。", "不知新恨多，但覺舊愁少。", "石鼎倚殘爐，茶煙看清裊。", "明朝尋酒錢，折簡喚諸老。"]'),
('f0dc3811-5cbc-4911-9d1c-d2a490f606c5','山陽寶應道中與汪信民兄弟洪玉父杜子師張益中日夕過從自過高郵不復有此樂也因作此詩寄懷','呂本中','宋','宋诗','song-poetry','','[]','日日南風沙打圍，掛帆端爲故人回。',64,'全唐诗/poet.song.91000.json','["日日南風沙打圍，掛帆端爲故人回。", "長空渺渺水無際，遠樹冥冥花自開。", "疾病久辜鸚鵡杓，江山稍近鳳凰臺。", "月明雪霽山陰道，尚想王郎乘興來。"]'),
('f5fd9df4-2b99-4c7e-9fc9-0b0f865dbe24','春日','呂本中','宋','宋诗','song-poetry','','[]','春風未雌雄，尊酒自賢聖。',24,'全唐诗/poet.song.91000.json','["春風未雌雄，尊酒自賢聖。", "燕巢樓閣間，鶯語花柳静。"]'),
('58deae28-78b2-47d8-a434-28443447fd4f','知止歗傲軒','呂本中','宋','宋诗','song-poetry','','[]','貪夫九鼎猶不足，淵明一軒長有餘。',144,'全唐诗/poet.song.91000.json','["貪夫九鼎猶不足，淵明一軒長有餘。", "人生趨向等天壤，鴟嚇腐鼠猜鵷雛。", "中郎妙處世不識，風期自與常人殊。", "開軒便有千載韻，友葛天氏無懷徒。", "坐看松菊換時節，兔葵桃樹紛榮枯。", "五年却走各南北，千里懷想空煩紆。", "雙魚沈浮久不至，三径寂寞今何如。", "文章潦倒付丘壑，疾病蹭蹬思江湖。", "何時共坐北風裏，煩君小摘園中蔬。"]'),
('326c520e-9082-42ae-b596-b8f75cb8afec','暑夕乍涼二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','三旬埃鬱得清風，領袖猶飜汗摺紅。',32,'全唐诗/poet.song.91000.json','["三旬埃鬱得清風，領袖猶飜汗摺紅。", "已是夢清無俗夢，更移涼簟月明中。"]'),
('3214fcdc-1699-4c26-a312-ab1c681d7667','暑夕乍涼二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','暮蟬蕭瑟下斜陽，已似茅簷氣味長。',32,'全唐诗/poet.song.91000.json','["暮蟬蕭瑟下斜陽，已似茅簷氣味長。", "團扇未須憂棄置，竹奴猶可助清涼。"]'),
('257eb82c-19a2-4f80-80c1-1eebc4b79aa3','寄知止二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','少年樂事未全諳，疾病侵凌已不堪。',32,'全唐诗/poet.song.91000.json','["少年樂事未全諳，疾病侵凌已不堪。", "尚喜步兵頻入夢，夢中猶復似曹南。"]'),
('02a4f0f6-4227-44bc-89e8-53fcdc9e8c30','寄知止二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','竹林還往風流絕，剡縣交游氣味疏。',32,'全唐诗/poet.song.91000.json','["竹林還往風流絕，剡縣交游氣味疏。", "今代高人多惜費，千金未抵一行書。"]'),
('379ec574-356f-469b-9a8b-3afa8232c128','游北李園三絕  其一','呂本中','宋','宋诗','song-poetry','','[]','雨映煙籠萬竹蟠，枯條高下不堪看。',32,'全唐诗/poet.song.91000.json','["雨映煙籠萬竹蟠，枯條高下不堪看。", "非干秋後多霜露，自是芙蓉不耐寒。"]'),
('5f315d6d-c8f4-41a9-a8dd-f5a9895fe488','游北李園三絕  其二','呂本中','宋','宋诗','song-poetry','','[]','去馬來舟絕往還，此中情味却相干。',32,'全唐诗/poet.song.91000.json','["去馬來舟絕往還，此中情味却相干。", "明年知是明寒食，待約花梢月下看。"]'),
('2764ff06-8651-41c0-9759-8d21bb2f7869','游北李園三絕  其三','呂本中','宋','宋诗','song-poetry','','[]','壁間詩字有凝塵，庭下梅梢又作春。',32,'全唐诗/poet.song.91000.json','["壁間詩字有凝塵，庭下梅梢又作春。", "獨有城南汪教授，當時同是看花人。"]'),
('1138f855-aae3-470a-84f3-de180c2619d5','游北李園','呂本中','宋','宋诗','song-poetry','','[]','小徑縱横出紫苔，綠陰高下綴黄梅。',32,'全唐诗/poet.song.91000.json','["小徑縱横出紫苔，綠陰高下綴黄梅。", "榴花却是多情思，留宿薰風未肯開。"]'),
('3c92284d-6e09-444c-ae17-f76828f221be','寄李怤去言','呂本中','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','東南之望廬山英，李郎落落奇後生。',208,'全唐诗/poet.song.91000.json','["東南之望廬山英，李郎落落奇後生。", "鳳凰麒麟在郊藪，芝蘭玉樹生階庭。", "文章初如濫觴水，行見萬里通滄溟。", "汪侯愛君筆不停，謂君詩似秋風清。", "世間兒子甘縮手，蘇過趙柟俱抗行。", "少年才氣乃如此，後来定是賢公卿。", "伊昔先朝文物盛，君家諸父當朝廷。", "外兄復是不世才，奇祥異瑞相輝映。", "翻雲覆雨十年後，昏昏醉夢須君醒。", "我生未壯日向衰，疾病侵凌心已灰。", "眼中之人不易見，千變百技常追隨。", "詩書深藏半鼠矢，筆墨高卧封蛛絲。", "功名已矣付公等，田園肯放吾先歸。"]'),
('2b79e215-1fad-4fb2-b03b-28b422cadfcd','贈汪莘叔野','呂本中','宋','宋诗','song-poetry','','[]','汪子宦不達，四海漫聲名。',192,'全唐诗/poet.song.91000.json','["汪子宦不達，四海漫聲名。", "有弟極磊落，氣宇和而清。", "三冬文史足，十年書劍成。", "出言見瓌穎，府庫森五兵。", "於身則已拙，泛如池中萍。", "輕肥置度外，辛苦抱遺經。", "乃知佳子弟，必由賢父兄。", "念子初来時，我方疾病攖。", "相從四寒暑，所歷不可聽。", "昏昏醉夢裏，得君時一醒。", "擁爐共殘火，軟語當盃鐺。", "君亦不我厭，爲我雙眼青。", "勿云軀幹小，氣吞横海鯨。", "懸榻念文舉，開逕憶淵明。", "二子風流遠，感君兄弟情。", "窮通有時節，此士爾勿輕。"]'),
('4bedc019-c9ba-4119-9e2f-1c4ab8507872','新冬','呂本中','宋','宋诗','song-poetry','','[]','西風吹禾黍，落日在陋巷。',132,'全唐诗/poet.song.91000.json','["西風吹禾黍，落日在陋巷。", "杖藜訪新冬，霜樹眇空曠。", "人煙村舎西，行旅古原上。", "晚山晴更好，秀色常在望。", "居閑得真趣，日欲就疏放。", "豈惟憎俗徒，庶自免嘲謗。", "東鄰酒初熟，清香亂盆盎。", "徑須騎牆頭，挈榼獻窮狀。", "吾生足羈旅，久病非少壯。", "銀杯多羽化，布帆且無恙。", "雖非陶潛隱，不負徐邈暢。"]'),
('4f5fd3dd-e362-4e51-9181-564732f34019','贈謝無逸','呂本中','宋','宋诗','song-poetry','','[]','君不見城南千樹桃，君不見澗底百尺松。',74,'全唐诗/poet.song.91000.json','["君不見城南千樹桃，君不見澗底百尺松。", "松生偃蹇卧霜雪，桃李一笑隨春風。", "百年澗底終自若，桃花猶得暫時紅。", "嗚呼志士每如此，衡門高卧不見用，心雖無瑕饑欲死。"]'),
('43c16154-45bd-47e6-816c-c667acd2e7ae','贈張若虛','呂本中','宋','宋诗','song-poetry','','[]','病憶江湖去，書無尺寸工。',48,'全唐诗/poet.song.91000.json','["病憶江湖去，書無尺寸工。", "平時窶人子，忽是富家翁。", "活計呻吟裏，交情夢寐中。", "獨於張處士，相近數過從。"]'),
('ffaddf8b-cbdf-4873-8359-b65bde981bea','贈信民','呂本中','宋','宋诗','song-poetry','','[]','五年客符離，端坐受貧病。',132,'全唐诗/poet.song.91000.json','["五年客符離，端坐受貧病。", "從来疏出門，今乃懶成性。", "官多豪富郎，分明與時競。", "取醉不論錢，定無塵生甑。", "豈但相娱樂，頗復自賢聖。", "汪侯雖官居，笑語怯豪橫。", "折腰衆人後，瓊林自輝映。", "背後足官府，眼前謬恭敬。", "偷閑過草堂，遣興眯眼浄。", "雖非醉紅裙，清談却差勝。", "秋高數能來，勿厭阻泥濘。"]'),
('6a1d5866-8511-435a-8eef-b5879a1e0cad','符離行','呂本中','宋','宋诗','song-poetry','','[]','符離之民難與居，五年坐此如囚拘。',99,'全唐诗/poet.song.91000.json','["符離之民難與居，五年坐此如囚拘。", "比屋生涯但剽劫，諸生學問只鄉閭。", "南鄰經年不相見，北里雖見復粗疏。", "窄衣小帽走塵土，也復生貌施襟裾。", "對此自然憂氣滿，疾病日益何由除。", "君不見圖經所記又可哀，此州自古無賢才。"]'),
('4d85d080-8685-407a-8c70-bcb9720c1b0d','探梅呈汪信民','呂本中','宋','宋诗','song-poetry','','[]','縞带銀杯欲着塵，小園幽樹已含春。',64,'全唐诗/poet.song.91000.json','["縞带銀杯欲着塵，小園幽樹已含春。", "風流王謝佳公子，臭味曹劉入幕賓。", "細朵定無泥土涴，暗香猶带雪霜新。", "剩摩枵腹搜奇句，去惱城南得定人。"]'),
('162862d0-cdac-4244-92d1-29e1db9b3516','奉懷張公潛舍人二首  其一','呂本中','宋','宋诗','song-poetry','','[]','顔子置身陋巷，屈原放跡江湖。',28,'全唐诗/poet.song.91000.json','["顔子置身陋巷，屈原放跡江湖。", "何似我公歸去，馬羸不厭長途。"]'),
('021db2a6-a610-4710-95e4-2eae7872210e','奉懷張公潛舍人二首  其二','呂本中','宋','宋诗','song-poetry','','[]','腕中有萬斛力，胸次乃千頃陂。',28,'全唐诗/poet.song.91000.json','["腕中有萬斛力，胸次乃千頃陂。", "字畫顔行楊草，文章韓筆杜詩。"]'),
('51569798-f16a-472f-920d-92ddfbb0e5bb','答無逸惠書','呂本中','宋','宋诗','song-poetry','','[]','三年讀書少餘味，燈火可親病爲祟。',224,'全唐诗/poet.song.91000.json','["三年讀書少餘味，燈火可親病爲祟。", "謝侯好事憐我窮，時遣雙魚問憔悴。", "交情乃似親骨肉，學行坐越諸公輩。", "胸中萬卷書屈蟠，少日力戰登詩壇。", "下帷卻掃謝俗子，凍吟不管兒號寒。", "只今食粥已數月，千慮百憂煩筆端。", "高才本是棟梁器，苦語終無儒生酸。", "樂章短句又清絕，陶寫萬象嘲江山。", "江南草木不得閑，問君何爲愁肺肝。", "十年行坐想風采，千里魂夢勞追攀。", "我無良田歸不得，忍窮氣味君應識。", "囊貯未了歲寒計，學道空愧琳與璧。", "交親零落半鬼錄，白日輕去真可惜。", "終朝撥火煮蘆菔，南山之南待君喫。"]'),
('dbb13022-1238-4903-b06f-51bda2e190ec','寄知止才仲','呂本中','宋','宋诗','song-poetry','','[]','一門叔父到卿好，中表弟兄惟爾賢。',64,'全唐诗/poet.song.91000.json','["一門叔父到卿好，中表弟兄惟爾賢。", "往事關心空自語，新詩好句與誰傳。", "溪山已近堪投老，文史雖窮莫取憐。", "仲弟墓頭今宿草，爲渠先賦補亡篇。"]'),
('8dcb296a-8fb4-4fe6-bcfd-dac7da55da9c','寄張益中','呂本中','宋','宋诗','song-poetry','','[]','五年望張子，兀坐四壁空。',168,'全唐诗/poet.song.91000.json','["五年望張子，兀坐四壁空。", "今晨千里来，如熱濯清風。", "笑談不改舊，憐我衰病攻。", "斯人舊豪氣，頗似陳元龍。", "只今更省事，終歲兩頬紅。", "何知珊瑚樹，却倚塵埃中。", "晁侯夙所敬，見渠如見公。", "網羅枝出脚，遠逐冥冥鴻。", "同會得玉郎，敲門夜相從。", "殷勤一盃酒，目送西歸鴻。", "人生少如意，此樂難再逢。", "君家老季鷹，高韻留吴淞。", "風流遠孫在，一櫂何時東。", "不嫌道里遠，爲我略從容。"]'),
('2797d9aa-1974-4aa5-91cd-ff69794b0b5a','元日贈沈宗師四首  其一','呂本中','宋','宋诗','song-poetry','','[]','東家起傳觴，西家起相喚。',48,'全唐诗/poet.song.91000.json','["東家起傳觴，西家起相喚。", "我亦了新詩，成此奇一段。", "念無毫髮益，但見日月換。", "出門語沈郎，造請我亦漫。"]'),
('8cf31cc8-dc74-4014-a7e0-cad997bd3aad','元日贈沈宗師四首  其二','呂本中','宋','宋诗','song-poetry','','[]','念昔從諸賢，關汪老耆舊。',48,'全唐诗/poet.song.91000.json','["念昔從諸賢，關汪老耆舊。", "是事今則無，斯人亦難又。", "爾来見公子，却立兩公後。", "不倦以終之，可以爲子壽。"]'),
('4ed225da-6bd7-49e0-8199-5f9fc580753a','元日贈沈宗師四首  其三','呂本中','宋','宋诗','song-poetry','','[]','沈郎固可人，好善乃天性。',48,'全唐诗/poet.song.91000.json','["沈郎固可人，好善乃天性。", "迹隨萬事遠，心與一物定。", "蕭然四立壁，筆墨自温凊。", "更持孟賁勇，少折楚士脛。"]'),
('85a04009-b88b-4021-829a-e2bbf76bc5ec','元日贈沈宗師四首  其四','呂本中','宋','宋诗','song-poetry','','[]','君無綺紈氣，我有冰雪容。',48,'全唐诗/poet.song.91000.json','["君無綺紈氣，我有冰雪容。", "相期五石瓠，共濟萬里風。", "江山秀句在，內子空洞中。", "還身視塵滓，當有一日功。"]'),
('a0a94558-502e-4db6-a971-452b0a92155e','梅','呂本中','宋','宋诗','song-poetry','','[]','南雪看未穏，北風吹已殘。',48,'全唐诗/poet.song.91000.json','["南雪看未穏，北風吹已殘。", "才堪十年夢，不稱一生酸。", "日月方回首，風霜與凭欄。", "遲明出謝客，頓覺帽圍寛。"]'),
('994b10ce-983d-4a75-8853-8cbbe12730c6','苦陰','呂本中','宋','宋诗','song-poetry','','[]','破臘冬仍在，逢正陰更頻。',48,'全唐诗/poet.song.91000.json','["破臘冬仍在，逢正陰更頻。", "寒流未解凍，雪意欲妨春。", "畏病還疏酒，逃寒懶見人。", "郊東小桃李，還是一番新。"]'),
('9b63b27b-9ff1-47a3-82eb-38e66fada09f','贈浹上人','呂本中','宋','宋诗','song-poetry','','[]','一庵便送淵明老，四海共傳摩詰詩。',64,'全唐诗/poet.song.91000.json','["一庵便送淵明老，四海共傳摩詰詩。", "本自妨人枕邊夢，不能陪汝劍頭炊。", "交游大半饑寒裏，疾病中分少壯時。", "西寺木魚東寺鼓，三年三見浹闍黎。"]'),
('3645ab96-8c37-402d-8dd5-74296fd7fa72','正月十二日夜作','呂本中','宋','宋诗','song-poetry','','[]','春来消息未真傳，久負蒲團一味禪。',64,'全唐诗/poet.song.91000.json','["春来消息未真傳，久負蒲團一味禪。", "燈火侵尋作佳境，冰霜偃蹇過新年。", "江聲悮落三更雨，野色遥看萬斛船。", "咫尺風光不相貸，忍令好語到愁邊。"]'),
('f29fe203-0c05-4ffb-9a85-c7a4510caf41','咸安公主','呂本中','宋','宋诗','song-poetry','','[]','漢朝公主歌黄鵠，秦地佳人唱柳枝。',32,'全唐诗/poet.song.91000.json','["漢朝公主歌黄鵠，秦地佳人唱柳枝。", "想見雲車度沙漠，一盃湩酪酹明妃。"]'),
('595753d9-024f-4674-9676-ba2031dae83d','明妃','呂本中','宋','宋诗','song-poetry','','[]','秦人彊盛時，百戰無逡巡。',108,'全唐诗/poet.song.91000.json','["秦人彊盛時，百戰無逡巡。", "漢氏失中策，清邊烽燧頻。", "丈夫不任事，女子去和親。", "君王爲置酒，單于来奉珍。", "朝辭漢宫月，暮隨胡地塵。", "鞍馬白沙暮，旃裘黄草春。", "人生在相合，不論越與秦。", "但取眼前好，莫言長苦辛。", "君看輕薄兒，何殊胡地人。"]'),
('2ad28aa1-bc28-4998-a445-398af19ec7f0','正月十三日河堤上作','呂本中','宋','宋诗','song-poetry','','[]','雨着河堤柳着煙，小樓燈火又今年。',32,'全唐诗/poet.song.91000.json','["雨着河堤柳着煙，小樓燈火又今年。", "東風不與行人便，留滯長亭十里船。"]'),
('baa93122-3b2c-49c4-a1e6-ede292395e71','昨日晚歸戲成四絕呈子之兼煩轉示進道丈  其一','呂本中','宋','宋诗','song-poetry','','[]','疏燈欲盡漁商市，小雨似開桃李顔。',32,'全唐诗/poet.song.91000.json','["疏燈欲盡漁商市，小雨似開桃李顔。", "一夜簷聲鳴甕盎，無人知我坐蒲團。"]'),
('34d8d817-a677-4e40-ae4f-0ef7519f3543','昨日晚歸戲成四絕呈子之兼煩轉示進道丈  其二','呂本中','宋','宋诗','song-poetry','','[]','卧疾江邊久未回，懶随兒輩走塵埃。',32,'全唐诗/poet.song.91000.json','["卧疾江邊久未回，懶随兒輩走塵埃。", "天公尚有餘情在，肯放梅花自在開。"]'),
('5bfeaae6-5cc0-44c9-817a-233977ea0d43','昨日晚歸戲成四絕呈子之兼煩轉示進道丈  其三','呂本中','宋','宋诗','song-poetry','','[]','春愁故故妨人樂，舊蘚新苔不暫晴。',32,'全唐诗/poet.song.91000.json','["春愁故故妨人樂，舊蘚新苔不暫晴。", "想見江郎閉船卧，滿川風雨報天明。"]'),
('2b281d78-d0cb-44b2-a4d3-a6ad0901b283','昨日晚歸戲成四絕呈子之兼煩轉示進道丈  其四','呂本中','宋','宋诗','song-poetry','','[]','晁卿白髮風流在，肯伴香車作夜遨。',32,'全唐诗/poet.song.91000.json','["晁卿白髮風流在，肯伴香車作夜遨。", "借問典衣充戲責，何如沽酒喚吾曹。"]'),
('050476e5-9d39-4af3-bb31-fa952b43d4e3','上元夜招沈宗師不至聞已赴郡會作二絕戲之  其一','呂本中','宋','宋诗','song-poetry','','[]','燈火滿城公不來，爲公雕句洗塵埃。',32,'全唐诗/poet.song.91000.json','["燈火滿城公不來，爲公雕句洗塵埃。", "春愁不到城西寺，更約梅花緩緩開。"]'),
('2907dfcf-92f0-4d47-a1a9-d3b54b01b357','上元夜招沈宗師不至聞已赴郡會作二絕戲之  其二','呂本中','宋','宋诗','song-poetry','','[]','白酒紅燈稱意春，知公未免踏黄塵。',32,'全唐诗/poet.song.91000.json','["白酒紅燈稱意春，知公未免踏黄塵。", "繩牀好在休相憶，輸與瑯琊浹上人。"]'),
('7c8cd906-d98a-4573-a117-894be28255e2','浹上座求枯木庵詩戲成兩絕贈之  其一','呂本中','宋','宋诗','song-poetry','','[]','枯木庵中浹道人，百年無影卧輪囷。',32,'全唐诗/poet.song.91000.json','["枯木庵中浹道人，百年無影卧輪囷。", "未須特地通身去，放取枝條自在春。"]'),
('88b1de7b-3e59-4b43-90c1-88641a4078d6','浹上座求枯木庵詩戲成兩絕贈之  其二','呂本中','宋','宋诗','song-poetry','','[]','前身石霜後身浹，如印印泥風去塵。',32,'全唐诗/poet.song.91000.json','["前身石霜後身浹，如印印泥風去塵。", "認得當時侍者意，無人知是密庵人。"]'),
('4ebd3de1-7e85-428e-98d6-02ace63da18b','正月末雪中小酌','呂本中','宋','宋诗','song-poetry','','[]','柳着河冰雪着船，小桃應誤取春憐。',32,'全唐诗/poet.song.91000.json','["柳着河冰雪着船，小桃應誤取春憐。", "牀頭有酒須君醉，又廢蒲團一夜禪。"]'),
('85fb97aa-babf-44ee-bcb2-234aca5995c2','次韻張生','呂本中','宋','宋诗','song-poetry','','[]','密庵居士渠不識，齒髮則衰心未然。',64,'全唐诗/poet.song.91000.json','["密庵居士渠不識，齒髮則衰心未然。", "樽下不知公子貴，酒中差覺孟生賢。", "已吞舌本三千丈，却住人間五百年。", "觸忤風光君莫怪，棒頭無地可逃禪。"]'),
('fe5581f2-5606-49f9-9116-1c77daa891a4','追成舊作','呂本中','宋','宋诗','song-poetry','','[]','滿江風月一船霜，無計留君只自狂。',32,'全唐诗/poet.song.91000.json','["滿江風月一船霜，無計留君只自狂。", "燈火隔簾香隔坐，無人知是竹枝娘。"]'),
('d07b2f5f-2dcb-4d79-b429-d0000547f4ac','久不得才仲書因成二絕寄之  其一','呂本中','宋','宋诗','song-poetry','','[]','望大趙書如渇驥，憶老汪膠無續弦。',32,'全唐诗/poet.song.91000.json','["望大趙書如渇驥，憶老汪膠無續弦。", "看徧江南與江北，小屏微雨是斜川。"]'),
('34f9619d-fd5c-4074-a264-4757123712f8','久不得才仲書因成二絕寄之  其二','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','病去詩無一點塵，亦知摩詰是前身。',32,'全唐诗/poet.song.91000.json','["病去詩無一點塵，亦知摩詰是前身。", "憐君更似西江水，合伴倚松庵裏人。"]'),
('47cd9cf6-f51b-48a6-9e0a-8820f5400a48','晚晴','呂本中','宋','宋诗','song-poetry','','[]','斜陽入花柳，渾欲不勝情。',48,'全唐诗/poet.song.91000.json','["斜陽入花柳，渾欲不勝情。", "春事乃如此，病軀安得平。", "尚堪衝宿酒，復作快新晴。", "荒簷足烏鳥，莫厭晚来聲。"]'),
('a6e50e8a-3372-492b-a7be-0f7f647b9a4b','連日與一上人會話密庵清坐附火乃有山居氣息因成一詩奉呈','呂本中','宋','宋诗','song-poetry','','[]','春風吹茅簷，落日半花柳。',108,'全唐诗/poet.song.91000.json','["春風吹茅簷，落日半花柳。", "餘寒盛氣來，佳辰爲誰有。", "公来但黙坐，有味皆可口。", "端如列鼎食，衣被以醇酒。", "煩言不知要，實自費斗藪。", "南泉山下人，了不計可否。", "山柴晚復焰，當爲一舉手。", "荒江甚泬寥，此味亦長久。", "不嫌薰病眼，重當爲公取。"]'),
('440e98c6-1d3c-47f9-a602-181775c8e228','一上人屢言瑯琊南塔之勝予蓋樂之而未能往也','呂本中','宋','宋诗','song-poetry','','[]','二頃良田一畝宫，好山當自屬林公。',32,'全唐诗/poet.song.91000.json','["二頃良田一畝宫，好山當自屬林公。", "須君留我卓錐地，安聽颼飀萬壑風。"]'),
('a92a9649-5ef6-4849-8dde-2e158381b1e9','夜坐有懷','呂本中','宋','宋诗','song-poetry','','[]','西還豈不好，本自乏周旋。',48,'全唐诗/poet.song.91000.json','["西還豈不好，本自乏周旋。", "道有魯一變，歲無官九遷。", "疾風驚半夜，惡况極今年。", "咫尺沙頭路，猶堪着釣船。"]'),
('10a3d44a-22e8-454e-8238-ac6925f8b012','晚春即事','呂本中','宋','宋诗','song-poetry','','[]','春色不自惜，曉寒摧折之。',48,'全唐诗/poet.song.91000.json','["春色不自惜，曉寒摧折之。", "殘花带雨去，薄酒信風吹。", "尚有尋行債，初無了事癡。", "論詩得奇味，當使阿戎知。"]'),
('5095309e-8791-48a0-ab3d-0abb94038aea','廣陵道中寒食日  其一','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','風雨屬連春事休，碧鱗三尺薦行舟。',32,'全唐诗/poet.song.91000.json','["風雨屬連春事休，碧鱗三尺薦行舟。", "短牆不見桃花面，付與長江自在流。"]'),
('d6b8533b-b01b-461d-8219-1536592a1f33','廣陵道中寒食日  其二','呂本中','宋','宋诗','song-poetry','','[]','南來消息不真傳，正恐相逢却未然。',32,'全唐诗/poet.song.91000.json','["南來消息不真傳，正恐相逢却未然。", "何處青帘足沽酒，粥香餳白是今年。"]'),
('090e3f71-c0bc-44a8-8d66-01c9d6163661','就甯子儀求酒','呂本中','宋','宋诗','song-poetry','','[]','鼻息咈然君莫驚，饑腸渠自作雷鳴。',32,'全唐诗/poet.song.91000.json','["鼻息咈然君莫驚，饑腸渠自作雷鳴。", "須公一勺羔兒酒，伴我夜窗聽雨聲。"]'),
('9d71f8a4-2fa6-48bd-ad3f-c36f310dd349','廣陵','呂本中','宋','宋诗','song-poetry','','[]','往來六十里，各是一江郊。',48,'全唐诗/poet.song.91000.json','["往來六十里，各是一江郊。", "柳色團渦岸，春風揚子橋。", "好山當斷岸，野鳥度空巢。", "一任雷塘路，暮天風雨號。"]'),
('d9c14341-31f2-40bf-a262-5a88e00c1ff2','沈宗師甚喜江梅而微貶酴醿因成一絕','呂本中','宋','宋诗','song-poetry','','[]','淡綠衣裳玉作粧，好風涼月自相當。',32,'全唐诗/poet.song.91000.json','["淡綠衣裳玉作粧，好風涼月自相當。", "沈郎笑汝多情在，不似江梅滿意香。"]'),
('9278ecd0-4f2a-4346-8dfa-e8f401e4dfe4','勸張李二君酒','呂本中','宋','宋诗','song-poetry','','[]','張侯好詩如好色，不敢爲主而爲客。',152,'全唐诗/poet.song.91000.json','["張侯好詩如好色，不敢爲主而爲客。", "李侯好酒如好詩，心雖甚壯無人知。", "兩侯風味俱不惡，如芙蓉與木芍藥。", "午窗留客看筆快，曉枕無人猶睡着。", "廣袖漸變天寶粧，大字不作元和脚。", "世人譏笑乃其分，政是仍叔之子弱。", "病夫坐隱無所求，荒簷斷雨鳴春鳩。", "爐烟未盡消百憂，恨不緩带從公游。", "何時清江横小舟，與公一醉荻花秋，却来密庵参牧牛。"]'),
('9c3c4eb1-2ec9-46d4-912a-516638dab660','庵居','呂本中','宋','宋诗','song-poetry','','[]','鳥語花香變夕陰，稍閑復恐病相尋。',64,'全唐诗/poet.song.91000.json','["鳥語花香變夕陰，稍閑復恐病相尋。", "正應獨有江山分，素自都無廊廟心。", "堂上老親雙白髪，門前稚子舊青衿。", "兒曹不會庵居意，古澗寒泉疑至今。"]'),
('820bd482-9334-4d06-a5c1-2a21c1d14d6c','小園即事','呂本中','宋','宋诗','song-poetry','','[]','千花老無蹤，衆草来可喜。',120,'全唐诗/poet.song.91000.json','["千花老無蹤，衆草来可喜。", "欣然得幽尋，我亦病良已。", "飛飛兩蝴蝶，不悟塵士裏。", "禽聲甚可人，亦似相汝爾。", "人生貴愜志，不必須甚羙。", "三年白沙詩，已費千幅紙。", "問君何所樂，赤手費磨洗。", "短屏看遠山，心作千萬里。", "此豈畫者功，實自一念起。", "君當如是觀，在此不在彼。"]'),
('66ad9269-ea12-4889-9071-0eaff2ed5ff3','登舟','呂本中','宋','宋诗','song-poetry','','[]','夜雨曉猶滴，怒風晴更吹。',48,'全唐诗/poet.song.91000.json','["夜雨曉猶滴，怒風晴更吹。", "已無行役念，寧有别離悲。", "舟楫三年路，江山一月期。", "東庵舊還往，不廢百篇詩。"]'),
('5ac2caff-6660-412e-b926-3a79f7bf55b7','張褘秀才乞詩','呂本中','宋','宋诗','song-poetry','','[]','白蓮庵中張居士，夢斷世間風馬牛。',64,'全唐诗/poet.song.91000.json','["白蓮庵中張居士，夢斷世間風馬牛。", "風塵表物自無意，神仙中人聊與游。", "澄江似趁北城曉，苦雨不放南山秋。", "君當先行我繼往，向吳亭東留小舟。"]'),
('bb75086b-fc02-4e16-8360-03a84c6fb527','效古樂府三首  其一','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','君住長江邊，妾上長江去。',24,'全唐诗/poet.song.91000.json','["君住長江邊，妾上長江去。", "長江日夜流，相思不相顧。"]'),
('783f1365-0d82-4608-af03-7ea99bde13c3','效古樂府三首  其二','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江日夜流，妾心終不改。',24,'全唐诗/poet.song.91000.json','["長江日夜流，妾心終不改。", "誰謂江頭人，相思不相待。"]'),
('db50286f-3475-4249-8101-8736d07d2bb0','效古樂府三首  其三','呂本中','宋','宋诗','song-poetry','','[]','東家石榴紅，西家石榴紫。',24,'全唐诗/poet.song.91000.json','["東家石榴紅，西家石榴紫。", "俱是一種花，同生不同死。"]'),
('479c3573-4da4-4e84-b2ff-5e245687b6f6','讀太真外傳','呂本中','宋','宋诗','song-poetry','','[]','上盡馬嵬路，東風吹舊京。',48,'全唐诗/poet.song.91000.json','["上盡馬嵬路，東風吹舊京。", "乾坤已新主，草木自秋聲。", "錦襪千年恨，皇輿萬里程。", "寧知挽船士，亦有别離情。"]'),
('3babfe83-43fc-4384-9fe0-77fa7fd6fb42','簡甯子儀二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','只恐老去被花惱，更欲忘憂須酒澆。',32,'全唐诗/poet.song.91000.json','["只恐老去被花惱，更欲忘憂須酒澆。", "何似山堂病居士，閉門高枕過春朝。"]'),
('09d829df-b39e-45bf-8855-361844cb7cb1','簡甯子儀二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','新晴欲上南樓月，柳可藏鵶水蘸牆。',32,'全唐诗/poet.song.91000.json','["新晴欲上南樓月，柳可藏鵶水蘸牆。", "無限客愁芳草裏，不知風雨阻斜陽。"]'),
('67d100ac-0085-4020-b20b-4349cdf8bbea','書寄浹上人','呂本中','宋','宋诗','song-poetry','','[]','胸中無一毫事，筆下有千斛力。',30,'全唐诗/poet.song.91000.json','["胸中無一毫事，筆下有千斛力。", "走徧江南江北山，滿堂禪和不相識。"]'),
('9f1dd7aa-51f3-4dbd-9ec2-d4e88149e3b8','呈愚上人','呂本中','宋','宋诗','song-poetry','','[]','不能歸續侍中貂，遂有聲名伴老饒。',64,'全唐诗/poet.song.92000.json','["不能歸續侍中貂，遂有聲名伴老饒。", "萬里更行看騕褭，一枝才足賦鷦鷯。", "詩囊磈礧君其漫，藥裹侵尋我亦聊。", "舉目雲天盡新語，殷勤收寄一牛腰。"]'),
('45dd7df4-6114-4f05-877f-c2c2f86a9586','贈浹上人一上人','呂本中','宋','宋诗','song-poetry','','[]','君行南山南，我在北山北。',180,'全唐诗/poet.song.92000.json','["君行南山南，我在北山北。", "不聞浴鵠白，但見染絲黑。", "老境欲垂垂，快意須得得。", "孰知百雉堅，而有一日克。", "浹如澗底松，縱老終不踣。", "一如雲間鶴，不復可覊勒。", "我如千里風，遇此兩鴻鵠。", "明珠脫氛翳，曉日破昏塞。", "宿障不盡除，胸次猶筆墨。", "君看說詩口，乃是拔山力。", "冷霜卧偃蹇，歲月飽封殖。", "誰能窺藩籬，未易得閫閾。", "政當歛光芒，不必須緣飾。", "相從無何鄉，敗衲依破裓。", "更令好事人，妙語添一則。"]'),
('65616b28-6d61-4726-a23a-b2e68f42c15e','雨後月夜懷沈宗師承務','呂本中','宋','宋诗','song-poetry','','[]','雨雲攬江色，偃蹇破昏睡。',144,'全唐诗/poet.song.92000.json','["雨雲攬江色，偃蹇破昏睡。", "千花閉紅紫，妙見一室內。", "披政當歛光，芒不必須緣。", "飾衣行夜永，明月在船背。", "微風過蕭瑟，古柳立蒼翠。", "翛然一蒲團，堅坐覓詩對。", "我生無南北，所到意趣遂。", "孰知十年游，保此清浄退。", "頗念城北人，結友老杉檜。", "漫随長鋏歸，甘作短檠棄。", "出門萬里塗，已駕安得稅。", "何當持被来，把酒相就醉。"]'),
('a56ed077-2903-4369-ab75-10dce929267c','秋夜示李十','呂本中','宋','宋诗','song-poetry','','[]','晴鳩不時鳴，雨鳩不暫歇。',180,'全唐诗/poet.song.92000.json','["晴鳩不時鳴，雨鳩不暫歇。", "相去跬步間，屢見屐齒折。", "寒泥擁衰草，秋扇罷殘熱。", "今晨好風景，稍貸屋頭月。", "清光冷相照，玉豔滿金玦。", "喚客坐前窗，文字相澡雪。", "殷勤傍詩律，未暇了麴糵。", "瀾翻談經口，邂逅如意鐵。", "我歌君輒書，字字有行列。", "不須陛枑嚴，但要兵衛設。", "譬如南山石，瑑齒當井渫。", "真成一戰覇，未可三鼓竭。", "人生各涇渭，世事亦滕薛。", "高堂食肉人，兩馬方踶齧。", "何知緼袍底，猶有不安節。"]'),
('eedc84bc-de07-46dc-953b-1d474e0a6f3c','中秋日沈宗師約游城西泥雨不果因成四十字兼寄趙才仲','呂本中','宋','宋诗','song-poetry','','[]','遂阻城西步，兼懷霅上游。',48,'全唐诗/poet.song.92000.json','["遂阻城西步，兼懷霅上游。", "長風掠歸燕，苦雨應鳴鳩。", "月向誰邊好，寒催社後秋。", "傳杯有新韻，能憶老兄不。"]'),
('eb9c09c6-b680-4844-a527-5087a3fa2d58','桃花菊','呂本中','宋','宋诗','song-poetry','','[]','嫩粉殷勤換淺黄，鬱金叢裏見新粧。',32,'全唐诗/poet.song.92000.json','["嫩粉殷勤換淺黄，鬱金叢裏見新粧。", "已翻百疊紅衣潤，更沐九回沈水湯。"]'),
('5e84c06d-c743-4c97-90d6-8213e437c070','九日晨起','呂本中','宋','宋诗','song-poetry','','[]','漸歇敺蚊手，真成把酒天。',48,'全唐诗/poet.song.92000.json','["漸歇敺蚊手，真成把酒天。", "長河印曉月，老木聚荒烟。", "了了江山夢，區區文字緣。", "南階兩三菊，極意作今年。"]'),
('cb361402-2bf5-4f65-aa06-ebb67bbbfedf','王氏郊居','呂本中','宋','宋诗','song-poetry','','[]','江山處處好，落日極登臨。',48,'全唐诗/poet.song.92000.json','["江山處處好，落日極登臨。", "雨續蔬畦潤，風吹杮葉陰。", "客船頻上下，水鳥故浮沈。", "尚有南飛雁，丁寧可寄音。"]'),
('20d64462-cbb1-46bb-b451-251d08d240a8','對菊','呂本中','宋','宋诗','song-poetry','','[]','稚子尋花莫漫狂，已知衰疾負重陽。',32,'全唐诗/poet.song.92000.json','["稚子尋花莫漫狂，已知衰疾負重陽。", "新霜有意留青蕊，更放殘枝十月黄。"]'),
('bd338acd-b73d-4326-940d-6bfd20903590','雨後至江上有懷諸子','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','落日滿寒雨，長江收夕霏。',48,'全唐诗/poet.song.92000.json','["落日滿寒雨，長江收夕霏。", "定知聊復爾，敢望不相違。", "野鳥晴相喚，殘螢晚自飛。", "殷勤兩山口，好爲放朝暉。"]'),
('fa5cce8d-1939-4b40-aa53-990feec8a0cd','登南樓','呂本中','宋','宋诗','song-poetry','','[]','疾風吹沙不成雨，十日狂陰倒殘暑。',64,'全唐诗/poet.song.92000.json','["疾風吹沙不成雨，十日狂陰倒殘暑。", "江頭樹木半焦枯，不厭潮頭洗塵土。", "南樓反照千丈紅，落日却在洪濤中。", "舟父漁子莫惆悵，更借朝来東北風。"]'),
('cff082e3-fe26-4544-8957-5459f0c5223f','歲晚作','呂本中','宋','宋诗','song-poetry','','[]','南山雪雲千丈高，北山晚田無寸毫。',80,'全唐诗/poet.song.92000.json','["南山雪雲千丈高，北山晚田無寸毫。", "富兒巨家飽欲死，笑我陋巷長蓬蒿。", "道人坐穏忘作勞，百念解縱如垂櫜。", "但當折簡喚我曹，並坐擇蝨煩抑搔。", "筆力可借秋江濤，莫學人間膏火熬。"]'),
('7c1414c7-3710-446c-9672-a44598b31ead','吊古冢','呂本中','宋','宋诗','song-poetry','','[]','荆榛閉莽蒼，千歲一孤墳。',48,'全唐诗/poet.song.92000.json','["荆榛閉莽蒼，千歲一孤墳。", "生則無是叟，死應冥漠君。", "略無他日念，唯有不堪聞。", "想得西陵道，荒臺亦暮雲。"]'),
('7eaf34d4-17de-4654-8c09-20390143d67c','奉送子之還京師','呂本中','宋','宋诗','song-poetry','','[]','日月老投閑，文字今削跡。',216,'全唐诗/poet.song.92000.json','["日月老投閑，文字今削跡。", "便然腰十圍，欲吐啄三尺。", "頗懷平生友，相就語肝膈。", "諸江好兄弟，夫子眉最白。", "詞林三二公，子實門下客。", "布帆千里来，許我間賓席。", "階庭出蘭樹，户牖照圭璧。", "詩如駕高浪，萬頃隨筆力。", "寧爲首陽餓，不作嬖奚獲。", "乃知工語言，要是飽糠覈。", "茫然李杜壇，未免陳蔡厄。", "出門觀善陣，歛手避勍敵。", "澄江搖夜霜，歲晚見沙石。", "釵頭罥蛛絲，即有梁宋役。", "士生多艱虞，道遠自古昔。", "相期逍遥游，不計天地窄。", "名聲了三黜，談笑供百謫。", "别君爲此言，可當繞朝策。"]'),
('66b96e0f-c6d4-492e-a424-27de72ad7804','外弟趙才仲數以書來論詩因作此答之','呂本中','宋','宋诗','song-poetry','','[]','君才如長刀，大窽當一割。',180,'全唐诗/poet.song.92000.json','["君才如長刀，大窽當一割。", "正須礱其鋒，却立望容髮。", "平生江海念，不救文字渇。", "茫然攬轡來，六驥仰朝秣。", "病夫百無用，念子故疏闊。", "未能即山林，頗復便裘褐。", "前時少年累，如燭今見跋。", "胸中塵埃去，漸喜詩語活。", "孰知一杯水，已見千里豁。", "初如彈丸轉，忽若秋兔脫。", "旁觀不知妙，可受不可奪。", "君看擲白盧，乃是中箭筈。", "不聞鐵甲利，反畏彊弩末。", "輿薪遵大路，過眼有未察。", "君能探虎穴，不但鬚可捋。"]'),
('78a2866b-f2e3-486b-b2f0-18eeff8f838f','過子之泊船舊亭','呂本中','宋','宋诗','song-poetry','','[]','江郎泊船處，草徑不勝秋。',48,'全唐诗/poet.song.92000.json','["江郎泊船處，草徑不勝秋。", "客裏終年别，春前萬斛愁。", "山横采菱口，月滿望江樓。", "政可夢春草，莫令吟白頭。"]'),
('afa05e9a-27cc-4e87-8504-edaa33a71838','望金陵偶成兩絕  其一','呂本中','宋','宋诗','song-poetry','','[]','臺城南望入斜陽，尚想能詩玉樹郎。',32,'全唐诗/poet.song.92000.json','["臺城南望入斜陽，尚想能詩玉樹郎。", "乘興風流莫相笑，眼看直北走雷塘。"]'),
('eed23da8-21ee-4244-a0f0-02f6572cf650','望金陵偶成兩絕  其二','呂本中','宋','宋诗','song-poetry','','[]','雷塘别有風流坐，可作南舟兩日行。',32,'全唐诗/poet.song.92000.json','["雷塘别有風流坐，可作南舟兩日行。", "江水自流春自好，不知芳草爲誰生。"]'),
('e6e4c9ce-1857-434a-80d6-38f87c639f7c','烹茶','呂本中','宋','宋诗','song-poetry','','[]','水光欲盡瑠璃影，玉色初浮翡翠斑。',32,'全唐诗/poet.song.92000.json','["水光欲盡瑠璃影，玉色初浮翡翠斑。", "便覺麴生風味好，小爐新火對蒲團。"]'),
('7dcf377c-925c-4b6a-bb26-3c637b2a62ac','西樓','呂本中','宋','宋诗','song-poetry','','[]','小院無人日自長，隔簾時有芰荷香。',32,'全唐诗/poet.song.92000.json','["小院無人日自長，隔簾時有芰荷香。", "客游未作安居計，更借西樓一夜涼。"]'),
('d6cb8eae-6341-4e4f-b689-9ae61d10215a','寄信上人','呂本中','宋','宋诗','song-poetry','','[]','笑語三年别，舟航十里淮。',48,'全唐诗/poet.song.92000.json','["笑語三年别，舟航十里淮。", "新霜變草木，好雨過風霾。", "萬事不如意，一生常好乖。", "何因伴明月，特地入君懷。"]'),
('06b06051-431c-4f45-a223-7168d32a7ef7','秦處度與一上人同宿密庵處度爲一畫斷崖枯木','呂本中','宋','宋诗','song-poetry','','[]','小庵無客亦無氊，遂有高人借榻眠。',32,'全唐诗/poet.song.92000.json','["小庵無客亦無氊，遂有高人借榻眠。", "一夜西風撼枯柳，不知春在石崖邊。"]'),
('cbb2debc-a705-49e5-b3c4-8cb86f8bd1f1','寄謝無逸并汪叔野兄弟','呂本中','宋','宋诗','song-poetry','','[]','老謝風流綠綺琴，小汪兄弟亦南金。',64,'全唐诗/poet.song.92000.json','["老謝風流綠綺琴，小汪兄弟亦南金。", "文章已悮半生事，江海略酬他日心。", "好酒不當愁偪仄，舊書差慰病侵尋。", "平生恩義伴宫老，斷綆寒泉百尺深。"]'),
('1e29415b-c5bc-4c01-95bc-04d0d017b252','月下','呂本中','宋','宋诗','song-poetry','','[]','白鷗笑汝不能飲，澄江惱人勤作詩。',32,'全唐诗/poet.song.92000.json','["白鷗笑汝不能飲，澄江惱人勤作詩。", "可惜南樓好風月，只無春柳對瓊枝。"]'),
('84869a1b-b2ad-474c-a2c9-035b75874a6e','劉穆之','呂本中','宋','宋诗','song-poetry','','[]','金柈一斛貯檳榔，戲調兒童走欲狂。',32,'全唐诗/poet.song.92000.json','["金柈一斛貯檳榔，戲調兒童走欲狂。", "不謂林間有元亮，念公時在酒中藏。"]'),
('5a8b3b67-5d25-4a35-be15-22a4c5d298c3','戲贈浹上人','呂本中','宋','宋诗','song-poetry','','[]','忽逢邗溝道人浹，如見錫山居士秦。',32,'全唐诗/poet.song.92000.json','["忽逢邗溝道人浹，如見錫山居士秦。", "問着世緣渾忘却，知公不是箇中人。"]'),
('31667eeb-255a-4a80-9708-9a817dd76eb1','喜章仲孚朝奉見過十韻','呂本中','宋','宋诗','song-poetry','','[]','苦語不難好，舊交今則無。',120,'全唐诗/poet.song.92000.json','["苦語不難好，舊交今則無。", "但能留客坐，已勝折腰趨。", "只有連根煮，初非滿眼酤。", "苔痕記拄杖，雪影傍跏趺。", "語道我恨晚，說詩公不迂。", "丁寧入漢魏，委曲上唐虞。", "歷歷有全體，匆匆或半塗。", "真當置度外，不敢望庭隅。", "日月換新歲，江山非故吾。", "他年佳句在，與畫密庵圖。"]'),
('3eee60b6-f5f0-4f83-8492-7b5a57ebef61','觀甯子儀所蓄維摩寒山拾得唐畫歌','呂本中','宋','宋诗','song-poetry','','[]','君不見寒山子，垢面蓬頭何所似。',112,'全唐诗/poet.song.92000.json','["君不見寒山子，垢面蓬頭何所似。", "戲拈拄杖喚拾公，似是同游國清寺。", "又不見維摩老，結習已空無可道。", "牀頭誰是散花人，墮地紛紛不須掃。", "嗚呼妙處雖在不得言，尚有丹青傳百年。", "請公着眼落筆前，令我琢句逃幽禪。", "異時净社看白蓮，莫忘只今香火緣。"]'),
('255344b4-f161-4bb9-a9f0-67a06a092ec7','寄朱時發','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','菱橋脊梁硬如鐵，天下拄杖打不折。',64,'全唐诗/poet.song.92000.json','["菱橋脊梁硬如鐵，天下拄杖打不折。", "倒騎佛殿出三門，南頭學來北頭說。", "昔苗未生今作米，更判阿師三尺觜。", "公但吸盡西江水，莫怕庭前簸箕尾。"]'),
('176636bf-eeb1-4bc0-a8ed-1f1885e28da3','寄穎昌諸叔','呂本中','宋','宋诗','song-poetry','','[]','身如許縣老聾丞，心是江湖版下僧。',64,'全唐诗/poet.song.92000.json','["身如許縣老聾丞，心是江湖版下僧。", "萬事聊憑曲肱夢，一尊時近短檠燈。", "舊游可數終難又，惡况雖多不厭曾。", "尚憶少年情語否，夜窗相對髮鬅鬙。"]'),
('3179c2c0-7195-4c5c-bafd-fba111d2fd3d','謝人送瓊花白沙人謂瓊花爲無雙花戲成兩絕  其一','呂本中','宋','宋诗','song-poetry','','[]','凝塵欲滿讀書窗，忽有瓊花對小缸。',32,'全唐诗/poet.song.92000.json','["凝塵欲滿讀書窗，忽有瓊花對小缸。", "更喜風流好名字，百金一朵號無雙。"]'),
('4b447e1c-d85c-4c2c-9d11-0ab4d53a772a','謝人送瓊花白沙人謂瓊花爲無雙花戲成兩絕  其二','呂本中','宋','宋诗','song-poetry','','[]','斷腸風味久難尋，尚有名花寄此心。',32,'全唐诗/poet.song.92000.json','["斷腸風味久難尋，尚有名花寄此心。", "折盡長枝已春晚，只宜涼月不宜陰。"]'),
('62a4ab2d-5cd3-406a-a6c1-313a7a9ca154','觀甯子儀朝奉山堂諸石三絕  其一','呂本中','宋','宋诗','song-poetry','','[]','箇中真味久難忘，但覺人間萬事忙。',32,'全唐诗/poet.song.92000.json','["箇中真味久難忘，但覺人間萬事忙。", "今日爲公留不得，剩分詩思入山堂。"]'),
('54e01f7c-31a1-45ba-a2f1-daba90495772','觀甯子儀朝奉山堂諸石三絕  其二','呂本中','宋','宋诗','song-poetry','','[]','向人懷抱終何有，過眼峥嶸得暫醒。',32,'全唐诗/poet.song.92000.json','["向人懷抱終何有，過眼峥嶸得暫醒。", "更喚秦髯與湔祓，爲公題作小南屏。"]'),
('98852c5a-5de1-446d-9414-e9dfe7ac6aec','觀甯子儀朝奉山堂諸石三絕  其三','呂本中','宋','宋诗','song-poetry','','[]','知公心似山堂石，悮落人間几案間。',32,'全唐诗/poet.song.92000.json','["知公心似山堂石，悮落人間几案間。", "今日風光已相負，看朱成碧未能還。"]'),
('642c8824-5622-46ba-8f03-2cbaa2afc5dd','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其一','呂本中','宋','宋诗','song-poetry','','[]','終年想顔色，未有食頃忘。',48,'全唐诗/poet.song.92000.json','["終年想顔色，未有食頃忘。", "君寧不我念，苦畏冰雪妨。", "斯文百戰罷，閱士如堵牆。", "孰知五湖口，一葦可以航。"]'),
('fb3c8e56-b9b8-41de-9654-1b2bda1db50c','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其二','呂本中','宋','宋诗','song-poetry','','[]','君才不長貧，太阿之在匣。',48,'全唐诗/poet.song.92000.json','["君才不長貧，太阿之在匣。", "故知讒慝口，不受龍象踏。", "此道有從來，骯髒端不乏。", "相期甕頭春，夜語重一呷。"]'),
('98e06910-4675-4697-800e-c1edf002b5d3','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其三','呂本中','宋','宋诗','song-poetry','','[]','盛欲與子談，乃復爲此别。',48,'全唐诗/poet.song.92000.json','["盛欲與子談，乃復爲此别。", "匆匆得餘歡，把酒到耳熱。", "人生不如意，肝膽有楚越。", "何知若人胸，中有積立鐵。"]'),
('fee3c570-1068-41aa-81cc-a65abd1ac324','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其四','呂本中','宋','宋诗','song-poetry','','[]','伯姑無恙時，令我與子友。',48,'全唐诗/poet.song.92000.json','["伯姑無恙時，令我與子友。", "周旋以至今，各是遺種叟。", "文字種聲名，于身亦何有。", "還書問兩弟，是事君識否。"]'),
('50a1df88-a142-439e-9c55-8ee8118c15b6','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其五','呂本中','宋','宋诗','song-poetry','','[]','婦如先姑賢，兒似乃翁好。',48,'全唐诗/poet.song.92000.json','["婦如先姑賢，兒似乃翁好。", "識君相與心，見我亦傾倒。", "頻年作離情，悟賞到丘嫂。", "卜鄰洛水陽，此語當在早。"]'),
('9d20eca6-db06-4893-b4e8-345519c181b0','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其六','呂本中','宋','宋诗','song-poetry','','[]','低頭拜東野，未厭擿抉窮。',48,'全唐诗/poet.song.92000.json','["低頭拜東野，未厭擿抉窮。", "停車問縮酒，不訃牛馬風。", "胸次絕塵滓，欲與秋水同。", "斯人未遽遠，當在阿堵中。"]'),
('9bfd7a5d-4ad9-4b91-97a0-c7156605205f','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其七','呂本中','宋','宋诗','song-poetry','','[]','往者汪信民，愛我不自勝。',48,'全唐诗/poet.song.92000.json','["往者汪信民，愛我不自勝。", "以我如古人，得與子並稱。", "若士不復有，斯言當伏膺。", "期君極膏沃，更作無盡燈。"]'),
('8ad8e1e9-60cf-4768-8a18-9bd7b1894bf2','十一月五日與才仲弟相别于白沙東門之外悵然久之不能自釋乃知謝安石作惡之語不爲過也因成八詩奉寄可見别後氣味亦可并示京洛間親舊也  其八','呂本中','宋','宋诗','song-poetry','','[]','鍛以百鍊剛，淬以萬里流。',48,'全唐诗/poet.song.92000.json','["鍛以百鍊剛，淬以萬里流。", "閉門待彊敵，忽見天地秋。", "以石投水中，萬歲終不浮。", "堂堂倚松老，于今忘百憂。"]'),
('6adb0688-96b7-4731-9394-fde79d8409e1','山水圖歌','呂本中','宋','宋诗','song-poetry','','[]','君不見南江老龍夜不眠，令我破屋開青天。',134,'全唐诗/poet.song.92000.json','["君不見南江老龍夜不眠，令我破屋開青天。", "千巖倒壁卷角上，一榻却在洪濤前。", "又不見江頭古木一尺圍，猿猱接手懸高枝。", "雨中寒蘆披靡去，天際風帆先後歸。", "陳生故是可憐人，筆雖未到心已親。", "南村北村渴欲死，怪此一室無纖塵。", "鄭虔祁嶽不解奇，韓幹畫馬空多肥。", "萬里咫尺君得之，更看湘江雷雨垂。"]'),
('ceb71242-f5f3-4113-b02e-f12297df56c7','庚寅年正旦郡中客次作','呂本中','宋','宋诗','song-poetry','','[]','曉霜挾霧入寒廳，四座伊優不暫停。',64,'全唐诗/poet.song.92000.json','["曉霜挾霧入寒廳，四座伊優不暫停。", "剩欲禪房作新歲，念無餘瀝到空瓶。", "詼諧與世聊從俗，嘯傲他年可乞靈。", "更爲旁人住俄頃，坐間愁殺兩螟蛉。"]'),
('be052829-dea9-41d9-a0a1-fbb1127cc4a2','題李伯時維摩畫像圖','呂本中','宋','宋诗','song-poetry','','[]','老松攙天四無壁，小庵不勞容一室。',96,'全唐诗/poet.song.92000.json','["老松攙天四無壁，小庵不勞容一室。", "野竹入户芭蕉肥，下有無言病摩詰。", "文殊妙對亦未真，身如浮雲那得親。", "驚倒同行問話人，彼上人者何所云。", "龍眠好事筆有神，不避世間狐兔羣。", "掃渠胸中千斛塵，多口阿師聞不聞。"]'),
('a9a2f741-8843-4f3c-9a84-92232c6c59ae','遣懷三首  其一','呂本中','宋','宋诗','song-poetry','','[]','何山不堪隱，何家不可居。',72,'全唐诗/poet.song.92000.json','["何山不堪隱，何家不可居。", "古来子華門，亦着荷畚夫。", "荒田脱積雨，未免供晚租。", "今日視昨日，但見有不如。", "故人勸加餐，老親憐嗜書。", "寧知毛錐子，不可一日無。"]'),
('1f78b568-0490-4543-bed6-3edda9513075','遣懷三首  其二','呂本中','宋','宋诗','song-poetry','','[]','秋風襲殘暑，忽過江上林。',72,'全唐诗/poet.song.92000.json','["秋風襲殘暑，忽過江上林。", "旦日扶杖來，不見十畝陰。", "蔬畦甚寂寞，亦受霜雪侵。", "念此不常好，如我宿昔心。", "濤頭落崩岸，野鳥助謳吟。", "潛魚着沙底，避網冬更沈。"]'),
('4ea56cd6-271c-4a62-b79b-7799a719b0c6','遣懷三首  其三','呂本中','宋','宋诗','song-poetry','','[]','異時忘言人，馬鬛今宿草。',72,'全唐诗/poet.song.92000.json','["異時忘言人，馬鬛今宿草。", "生平不如意，欲伴寒木槁。", "遂令藜莧腸，更盡組繡巧。", "三年對空案，誦子詩可飽。", "從來文字工，不解顔色好。", "相逢期後身，再訪西院老。"]'),
('aa794b02-9900-4ab7-896b-abcf314db923','符離阻雨','呂本中','宋','宋诗','song-poetry','','[]','東風吹船窗，未曉天復雨。',132,'全唐诗/poet.song.92000.json','["東風吹船窗，未曉天復雨。", "篙師促添纜，卧聽泥㶁㶁。", "不知城北園，春事今幾許。", "舊游如宿昔，花柳黙可數。", "鄰里先後来，頗復相勞苦。", "東家獻牛酒，西家饋雞黍。", "感渠長久情，愧我無所取。", "汪侯哦詩處，積水敗環堵。", "念此不忍行，不但出入阻。", "七年此端居，畏病如畏虎。", "故人饒與黎，此老可出語。"]'),
('68e9491d-1629-4b89-bef3-7dbf18ec7652','伍員祠','呂本中','宋','宋诗','song-poetry','','[]','伍員廟前一丈碑，上有野鶴雙来棲。',64,'全唐诗/poet.song.92000.json','["伍員廟前一丈碑，上有野鶴雙来棲。", "水雲杳杳涼去遠，風雨冥冥秋到遲。", "江花相趁野花發，舊燕不隨新燕歸。", "大夫遺恨竟何許，楚越勾吳今是非。"]'),
('4939a77f-fb73-4b2d-87bf-b329a660ce73','東園','呂本中','宋','宋诗','song-poetry','','[]','垢汙久思出，江山秋更新。',48,'全唐诗/poet.song.92000.json','["垢汙久思出，江山秋更新。", "荒田拆龜兆，老檜落龍鱗。", "風月猶堪夜，蒲蓮浪作春。", "籃輿亦乘興，實自厭冠巾。"]'),
('8e5d093c-d904-42cd-a245-71b860dd05a1','寄琦監院','呂本中','宋','宋诗','song-poetry','','[]','往時濟陽晁公子，今日靈巖琦上人。',64,'全唐诗/poet.song.92000.json','["往時濟陽晁公子，今日靈巖琦上人。", "千山不礙一月曉，北樹忽見南枝春。", "箇中有味渠不識，底處無情公得親。", "不知碧眼之面壁，何如魋顔西入秦。"]'),
('ed1374f9-eb41-4ee3-a2a2-ffe72100ba2b','即事戲答季一','呂本中','宋','宋诗','song-poetry','','[]','斜陽着高柳，環堵半黄昏。',48,'全唐诗/poet.song.92000.json','["斜陽着高柳，環堵半黄昏。", "小圃三年旱，荒池一尺渾。", "粗知詩有味，寧使婦無禈。", "不信晁公子，猶招楚些魂。"]'),
('23366171-2728-4ec6-8555-ae18c79036cc','湘竹','呂本中','宋','宋诗','song-poetry','','[]','小雨催寒入夕曛，湘江風味可憐人。',32,'全唐诗/poet.song.92000.json','["小雨催寒入夕曛，湘江風味可憐人。", "斑斑玉淚無時盡，裊裊金梢别是春。"]'),
('ba5c0a75-8497-4563-a884-dbd3bd02eff5','有懷宿州城北因作詩寄才仲','呂本中','宋','宋诗','song-poetry','','[]','宿州古城城北隅，雨罷晴開如畫圖。',64,'全唐诗/poet.song.92000.json','["宿州古城城北隅，雨罷晴開如畫圖。", "雜花亂蕊未湏道，白杏一枝天下無。", "香風裊裊入短袖，明月蕭蕭隨蹇驢。", "二年不復見此樂，清江萬頃正愁予。"]'),
('206c8367-c2dc-412b-bacc-5330595f5e6e','示沈宗師  其一','呂本中','宋','宋诗','song-poetry','','[]','十日兒號不出房，殘梅猶在小瓶香。',32,'全唐诗/poet.song.92000.json','["十日兒號不出房，殘梅猶在小瓶香。", "沈郎喚客煮湯餅，政恐匆匆未得嘗。"]'),
('4dbe5ebe-97ff-45d3-a366-915b461440df','示沈宗師  其二','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','九日狂陰一日晴，落花飛絮作清明。',32,'全唐诗/poet.song.92000.json','["九日狂陰一日晴，落花飛絮作清明。", "與君擕手南樓去，共聽長江月下聲。"]'),
('111ceacd-0457-43f5-9633-95e717e69c26','夜坐戲成兩絕呈迪吉宗師二友  其一','呂本中','宋','宋诗','song-poetry','','[]','夜窗燈火著新寒，喜見蒲團一味閑。',32,'全唐诗/poet.song.92000.json','["夜窗燈火著新寒，喜見蒲團一味閑。", "縱有好詩人不要，却須還與檻前山。"]'),
('6792d126-5b31-4e75-ba19-0ba61fcbd8b9','夜坐戲成兩絕呈迪吉宗師二友  其二','呂本中','宋','宋诗','song-poetry','','[]','疏簾欲上梧楸影，遠枕微聞盆盎鳴。',32,'全唐诗/poet.song.92000.json','["疏簾欲上梧楸影，遠枕微聞盆盎鳴。", "甚欲分身就公宿，只愁塵土變江聲。"]'),
('ed3ab4db-7fdf-4b33-8d55-e6a30a297af5','戲成兩絕奉簡章仲孚兼呈宗師  其一','呂本中','宋','宋诗','song-poetry','','[]','日日勃鳩相應鳴，年年春草趁愁生。',32,'全唐诗/poet.song.92000.json','["日日勃鳩相應鳴，年年春草趁愁生。", "道人不怕冰霜面，又作南舟十日行。"]'),
('829a34f0-dfcc-4d02-be3b-fce2e481af20','戲成兩絕奉簡章仲孚兼呈宗師  其二','呂本中','宋','宋诗','song-poetry','','[]','沈郎愛客如愛酒，章子問詩如問禪。',32,'全唐诗/poet.song.92000.json','["沈郎愛客如愛酒，章子問詩如問禪。", "肯共寒爐撥殘火，共搜佳句作新年。"]'),
('4992d634-5c91-416c-be71-fd3be466a146','老松','呂本中','宋','宋诗','song-poetry','','[]','奉君以綠綺琴報，我以雙南金盃中。',80,'全唐诗/poet.song.92000.json','["奉君以綠綺琴報，我以雙南金盃中。", "琥珀不須盡聽妾，一聲行路吟君看。", "庭前老松樹上有，杳黙不斷之清陰。", "牆低未礙髯髮古，歲晚不辭霜雪侵。", "東園桃李自妍好，與君百歲同此心。"]'),
('d36f48b2-b53e-4b89-a70e-00d88696f23c','揚州雍熙寺納涼','呂本中','宋','宋诗','song-poetry','','[]','高樓有餘涼，但見旗脚動。',60,'全唐诗/poet.song.92000.json','["高樓有餘涼，但見旗脚動。", "鳥語簷角来，仰聽風響弄。", "江山舊還往，草木老賓從。", "平生一笑適，可得萬鈞重。", "翛然六尺牀，更許佳月共。"]'),
('07d5ce70-22f6-47dd-8fce-d389f49bd6ed','訪張鑑秀才兄弟','呂本中','宋','宋诗','song-poetry','','[]','眼看霍霍萬錢食，便就匆匆五鼎烹。',32,'全唐诗/poet.song.92000.json','["眼看霍霍萬錢食，便就匆匆五鼎烹。", "何似張侯五兄弟，閉門相對飽芹羮。"]'),
('337c3b60-a8f1-4bf4-ac7f-068dd47ad7bd','邵伯埭路中','呂本中','宋','宋诗','song-poetry','','[]','行前蒲柳後鷗鳥，乃似白沙之舊居。',64,'全唐诗/poet.song.92000.json','["行前蒲柳後鷗鳥，乃似白沙之舊居。", "忽見雲天有新語，不知風雨對殘書。", "往来河樹幾傾蓋，上下江船如貫魚。", "更與河山結香火，夜窗重枉故人車。"]'),
('558db436-deea-4a39-a4a7-7f5064197267','寄周司理','呂本中','宋','宋诗','song-poetry','','[]','日月走劻勷，舟楫卧煩暑。',120,'全唐诗/poet.song.92000.json','["日月走劻勷，舟楫卧煩暑。", "涼秋在萬里，客子安得語。", "周侯磊落人，憐我自熬煮。", "殷勤半月留，可得一笑許。", "别来今幾日，坐此百里阻。", "清風不時来，曉月仍半吐。", "卷簾看脩竹，忽似對眉宇。", "人生行樂耳，舍此皆自苦。", "終期卜隣歸，重聽對牀雨。", "雖無嗚嗚歌，亦有坎坎鼓。"]'),
('5ae2e5ec-92dc-434e-8474-5e2e785ab290','山光寺前泊舟值雨','呂本中','宋','宋诗','song-poetry','','[]','輕雷喚小雨，憶在白沙時。',48,'全唐诗/poet.song.92000.json','["輕雷喚小雨，憶在白沙時。", "綠酒留連醉，紅燈取次詩。", "好風那復有，涼月自相隨。", "獨上山光寺，清歌無柳枝。"]'),
('43fef8cd-3dca-4663-816b-cbe5c5f297d8','步月有懷','呂本中','宋','宋诗','song-poetry','','[]','平生最愛花梢月，可與青樓一等看。',32,'全唐诗/poet.song.92000.json','["平生最愛花梢月，可與青樓一等看。", "病去老来渾忘却，曉窗晴日上蒲團。"]'),
('02ccecf7-9edd-49ff-b66b-1146ec3d6049','揚州留一上人','呂本中','宋','宋诗','song-poetry','','[]','日日東風吹客衣，小園春在掩芳菲。',64,'全唐诗/poet.song.92000.json','["日日東風吹客衣，小園春在掩芳菲。", "殘花過雨飄零盡，好鳥穿林自在飛。", "往事虚成采薇瘦，故人頻有食言肥。", "知公未厭西行晚，且伴江船緩緩歸。"]'),
('c1534cf4-881f-497a-be36-ad97050ecc43','送一上人之京師','呂本中','宋','宋诗','song-poetry','','[]','東風吹雲十日雨，卧聽城頭打衙鼓。',160,'全唐诗/poet.song.92000.json','["東風吹雲十日雨，卧聽城頭打衙鼓。", "道人遠自山中來，共坐南窗濯泥土。", "自然高韻到羲皇，豈止微言變齊魯。", "萬牛回首不震掉，一葉横江且掀舞。", "未能入水取蛟蜃，尚欲投戈代貔虎。", "念公守此非一朝，木病磈瘣無枝條。", "已盡千峰西嶺雪，更夢八月錢塘潮。", "京城塵沙深一尺，是中莫留公履迹。", "權門蹲𠴲兒女笑，我一思之不能食。", "片帆無事早歸来，爲公一洗山中石。"]'),
('38ce652a-cae2-4d20-9082-d3eaeed8cc92','擬古  其一','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','狡兔死三窟，老松堅百尋。',84,'全唐诗/poet.song.92000.json','["狡兔死三窟，老松堅百尋。", "物生各有願，共此分寸陰。", "荒城六月旱，長江三日霖。", "稻苗不遂死，幸無蟊賊侵。", "皇天不私覆，一語銷百壬。", "先王典刑在，落落傳至今。", "願以小人腹，而爲君子心。"]'),
('a0865372-fb49-419a-a33e-8e0970adb413','擬古  其二','呂本中','宋','宋诗','song-poetry','','[]','寒雞不能晨，苦雨自朝夕。',84,'全唐诗/poet.song.92000.json','["寒雞不能晨，苦雨自朝夕。", "上爲雲雷巢，下乃龍蜃宅。", "坐懷陰外天，缺月掛殘魄。", "少來可喜人，牖户陳玉帛。", "平生千萬言，略省二三策。", "牛山所種木，日在斤斧厄。", "念君十年心，使我雙髩白。"]'),
('2e92e39e-2416-46cc-bbc1-859650c256ee','潘邠老嘗得詩云滿城風雨近重陽文章之妙至此極矣後托謝無逸綴成無逸詩云病思王子同傾酒愁憶潘郎共賦詩蓋爲此語也王子立之也作此詩未數年而立之邠老墓木已拱無逸窮困江南未有定止感歎之餘輒成二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','漫營新句補殘章，寄與烏衣玉樹郎。',32,'全唐诗/poet.song.92000.json','["漫營新句補殘章，寄與烏衣玉樹郎。", "他日無人識佳景，滿城風雨近重陽。"]'),
('0c38427c-a66a-4c46-9f5e-9688b39ced30','潘邠老嘗得詩云滿城風雨近重陽文章之妙至此極矣後托謝無逸綴成無逸詩云病思王子同傾酒愁憶潘郎共賦詩蓋爲此語也王子立之也作此詩未數年而立之邠老墓木已拱無逸窮困江南未有定止感歎之餘輒成二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','好詩政似佳風月，會賞能知已不凡。',32,'全唐诗/poet.song.92000.json','["好詩政似佳風月，會賞能知已不凡。", "萬里潘郎舊鄉縣，半江斜日落歸帆。"]'),
('ecb095b2-71e6-4fdb-b418-ffe215db26be','寄李商老','呂本中','宋','宋诗','song-poetry','','[]','竹不可一日無，酒不可飲不醉。',238,'全唐诗/poet.song.92000.json','["竹不可一日無，酒不可飲不醉。", "平生嗜酒愛風竹，此意不許凡兒會。", "南来經年飽塵垢，袖手甘隨百夫後。", "文章漫作無功身，只了兒曹補窗竇。", "黄沙障日江漫流，青山喚我十年舊。", "憶昔泊船鵝翎口，把酒遥爲故人壽。", "只今身在心已老，千巖想像靈芝秀。", "君家兄弟固不凡，解挽三友勤相就。", "中郎卧病過春晚，昔則酒狂今詩瘦。", "山房大名不墜地，諸老風流未宜棄。", "老檜参天可乞盟，粢食鉶羮乃無味。", "如君高韻千載同，可更托身三數公。", "丈夫勁挺要長久，百萬叩關一夫守。", "胸中江海不須道，此流何必計升斗。", "眼前勃窣訴二友，聽客所爲公絕口。"]'),
('9a7852cd-cf7b-4ee9-bfa3-4893224794fa','雨中作','呂本中','宋','宋诗','song-poetry','','[]','咄咄真成夢，悠悠復未知。',48,'全唐诗/poet.song.92000.json','["咄咄真成夢，悠悠復未知。", "寧爲牛背語，不作劍頭炊。", "雨挟秋聲亂，江含暝色悲。", "故知無事飲，猶勝頃来詩。"]'),
('8004febf-aa53-4e21-ab52-7ef4dfa6c827','示內','呂本中','宋','宋诗','song-poetry','','[]','貧賤不可忘，富貴安足羡。',144,'全唐诗/poet.song.92000.json','["貧賤不可忘，富貴安足羡。", "我生未三十，種種厭貧賤。", "宦情肱九折，老味金百鍊。", "稍回功名心，來結香火願。", "平生所知人，久已焚筆硯。", "是中無真實，不在儒術緣。", "有如退飛鷁，更借逆風便。", "病妻頗癡絕，可與共開宴。", "小女真吾兒，語學春鳥囀。", "初非本来有，且作夢中見。", "君看手捉鼻，絕勝扇障面。", "他年從我居，同入隱士傳。"]'),
('f72e5807-3d6f-4ed7-bf3c-df59a2539908','寄外弟趙柟才仲','呂本中','宋','宋诗','song-poetry','','[]','長年更多疾，念爾不能忘。',240,'全唐诗/poet.song.92000.json','["長年更多疾，念爾不能忘。", "夢去關山静，書來道里長。", "形骸且憔悴，草木自蒼唐。", "古縣疏還往，微官絕簸揚。", "頗聞能吏事，仍不廢文章。", "客舍襄江下，人家筑水傍。", "屢成千里目，虛斷九迴腸。", "我老知無用，身閑欲半藏。", "預愁章服裹，仍怯簿書忙。", "事業煩詩卷，生涯在藥囊。", "得非嵇叔懶，寧似次公狂。", "野檜多鱗甲，寒松半雪霜。", "高天一雁遠，小徑百年荒。", "每惜朱絲斷，空懷素錦張。", "舊交渾潦倒，此語更微茫。", "欲判五斗米，先尋百本桑。", "殘羮得共啜，薄酒要同嘗。", "匣裏出鳴劍，眼中除眯糠。", "未容窺突奧，虚自倚門牆。", "指點飛鴻路，何人識故鄉。"]'),
('c8573970-28dc-44e8-b116-8b5694354894','京師贈大有叔','呂本中','宋','宋诗','song-poetry','','[]','尊酒相逢十載前，綠髮紅顔俱少年。',112,'全唐诗/poet.song.92000.json','["尊酒相逢十載前，綠髮紅顔俱少年。", "尊酒相逢十載後，皮黄肉皺俱白首。", "叔如鴻鵠但高飛，姪似麕鼯更深走。", "南来行李初一逢，長安舊第冰雪中。", "閉門不識故人面，豪氣直欲輕元龍。", "平生爲道不爲食，少小所期皆目撃。", "何時相就過江南，同訪曾游舊泉石。"]'),
('b2c93cc3-4460-4e51-bb51-c24502577371','寄蔡伯世趙才仲  其一','呂本中','宋','宋诗','song-poetry','','[]','我恨不識鹿門公，蔡郎心期千載同。',32,'全唐诗/poet.song.92000.json','["我恨不識鹿門公，蔡郎心期千載同。", "不隨吏部曹中板，去赴長蘆寺裏鐘。"]'),
('53ec00a9-6d5a-496d-8274-4e9d3906de9a','寄蔡伯世趙才仲  其二','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一坐十月長江濵，自君之來心轉親。',32,'全唐诗/poet.song.92000.json','["一坐十月長江濵，自君之來心轉親。", "還書起居清源君，人間紛紛何足云。"]'),
('137f0b4b-b021-45ba-9fbb-ce12dc00be5b','寄蔡伯世趙才仲  其三','呂本中','宋','宋诗','song-poetry','','[]','同行者誰平原孫，于我不但骨肉親。',32,'全唐诗/poet.song.92000.json','["同行者誰平原孫，于我不但骨肉親。", "誰言不爲桃花去，只愛江山亦可人。"]'),
('51504284-f76a-4038-815a-bdf385235107','寄蔡伯世趙才仲  其四','呂本中','宋','宋诗','song-poetry','','[]','二子逃禪不計年，江湖重去水粘天。',32,'全唐诗/poet.song.92000.json','["二子逃禪不計年，江湖重去水粘天。", "直饒透盡三關語，到底終成百漏船。"]'),
('405c8377-e2f0-49b0-9e4f-631543a4b252','寄蔡伯世趙才仲  其五','呂本中','宋','宋诗','song-poetry','','[]','木魚光裏兩蒲團，意氣與我平生歡。',32,'全唐诗/poet.song.92000.json','["木魚光裏兩蒲團，意氣與我平生歡。", "盡底告君君不會，空得癡人尋筆端。"]'),
('93a18122-4e2b-48ca-a93f-432cddf5cc73','寄范子','呂本中','宋','宋诗','song-poetry','','[]','范郎平生萬人傑，只今未免兒號寒。',64,'全唐诗/poet.song.92000.json','["范郎平生萬人傑，只今未免兒號寒。", "三江五湖在胸次，琨玉秋霜看筆端。", "舊疾祇令肝肺熱，春風欲開桃李顔。", "待約南江今夜月，與渠萬里報平安。"]'),
('229a4083-c444-4d34-829e-a761507871cc','春風','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春風随長江，一日行萬里。',84,'全唐诗/poet.song.92000.json','["春風随長江，一日行萬里。", "蕭條起岷山，欻忽度揚子。", "江南千酒樓，春風樓上頭。", "金樽開翠幄，青帘吹客愁。", "長堤二月暖，寒溪千古流。", "紛紛桃李花，處處作芳華。", "不見梁間燕，空悲王謝家。"]'),
('3295ec3c-f25a-4555-988d-8614a9075dd6','聽琴','呂本中','宋','宋诗','song-poetry','','[]','君不見龍門之下百尺桐，漂霰飛雪愁寒空。',182,'全唐诗/poet.song.92000.json','["君不見龍門之下百尺桐，漂霰飛雪愁寒空。", "何年班爾落君手，小窗伴坐歌南風。", "恍然如著山巖裏，不知身在塵埃中。", "初聞平野飛鴻鵠，欻聽金盤起珠玉。", "遶壇古樹鬱嵯峨，六月吹霜作寒綠。", "折楊黄華不須道，别鶴離鸞尚堪續。", "君不見開元天子醉西都，音聲十院留歡娱。", "當時臨軒奏此曲，徑須解穢煩花奴。", "乃知恬淡世莫識，無弦之趣何時無。", "歸家愁厭筝笛耳，此聲一聽還已矣。", "會須流水訪鍾期，試向爐中覓焦尾。"]'),
('2f6279b2-1acc-4d53-b714-ef7806cc8732','雨後','呂本中','宋','宋诗','song-poetry','','[]','新花欲盡竹當欄，喜見空牆野色團。',64,'全唐诗/poet.song.92000.json','["新花欲盡竹當欄，喜見空牆野色團。", "稚子乘陰蒔蘭菊，僕夫留水灌萵蔓。", "茶香于汝初無分，酒熟逢人也强歡。", "惱亂春光君會否，小瓶猶占一枝殘。"]'),
('cb60af73-a293-487f-9924-12a307e5d62d','送山伯良佐東歸以務道期息塗爲韻  其一','呂本中','宋','宋诗','song-poetry','','[]','荆棘生良心，米鹽入塵務。',60,'全唐诗/poet.song.92000.json','["荆棘生良心，米鹽入塵務。", "芬芳老不達，豈不以此故。", "人生錐處囊，穎末要立露。", "玉壺近青蠅，沒沒自點汚。", "刳心萬物表，却立看脱兔。"]'),
('2f533ffa-5982-490e-b8c1-a0c052308680','送山伯良佐東歸以務道期息塗爲韻  其二','呂本中','宋','宋诗','song-poetry','','[]','臨别當一言，懇懇念忠告。',60,'全唐诗/poet.song.92000.json','["臨别當一言，懇懇念忠告。", "縹囊可取足，往結萬古好。", "黙識古則然，愚智同一道。", "遠師顔氏子，近比伯業操。", "文章有妙斵，期子開窔奧。"]'),
('69cd931a-79df-404c-96f5-fbcef64c5a16','送山伯良佐東歸以務道期息塗爲韻  其三','呂本中','宋','宋诗','song-poetry','','[]','吾詩如清風，去留不可期。',60,'全唐诗/poet.song.92000.json','["吾詩如清風，去留不可期。", "灑然或一來，不繋凡子知。", "兩郎從我游，豈但窺藩籬。", "山房光焰在，實藉衆木枝。", "斯言可三復，如我清風詩。"]'),
('18dc5dc2-0acb-43de-8760-d93759c882f1','送山伯良佐東歸以務道期息塗爲韻  其四','呂本中','宋','宋诗','song-poetry','','[]','昔我同學生，文字虎而翼。',60,'全唐诗/poet.song.92000.json','["昔我同學生，文字虎而翼。", "仲弟最多才，去以六月息。", "自吾失若人，每語輒氣塞。", "子如求數君，慎莫怪蟊賊。", "胸懷但明了，几案付塵黑。"]'),
('ecefedf2-598e-42af-a10c-16fd75b3730b','送山伯良佐東歸以務道期息塗爲韻  其五','呂本中','宋','宋诗','song-poetry','','[]','贈我貂襜褕，報以明月珠。',60,'全唐诗/poet.song.92000.json','["贈我貂襜褕，報以明月珠。", "古來聲名人，一一行此塗。", "漢中屠沽兒，適可曹公奴。", "人生嗜好異，至有海上夫。", "孰能識其然，飽此萬卷書。"]'),
('8ed03070-3fb5-4f46-9639-32a030301c08','河水清贈良佐兼寄商老','呂本中','宋','宋诗','song-poetry','','[]','河水清，江水黄，南山北山自相望。',72,'全唐诗/poet.song.92000.json','["河水清，江水黄，南山北山自相望。", "恨君不止白石房，與誰同遊南郡郎。", "白玉刻佩明月璫，如鳳四海求其凰。", "道里遼遠日月長，爽氣自足陵朝陽，舉酒送君君莫忘。"]'),
('46fc6fe2-81fb-4714-868b-c5e3c979969e','同晁季一李天紀過沈宗師北荘因成長韻','呂本中','宋','宋诗','song-poetry','','[]','三年城南居，不識城北土。',144,'全唐诗/poet.song.92000.json','["三年城南居，不識城北土。", "但聞玉雪郎，去作猿鶴主。", "今晨籃輿來，握手相勞苦。", "勝遊有佳士，洗耳聽妙語。", "晴窗背雲壑，落日在環堵。", "晚風生白楊，想像原野古。", "斷崕懸老木，小港聚寒雨。", "却觀城市人，努力自熬煮。", "畏塗出衽席，禍福有未覩。", "杜陵懷壯游，無忌笑豪舉。", "二者覓真是，政恐君未許。", "千秋柴桑翁，妙句聊一吐。"]'),
('0264d851-9502-4484-a054-19140a8260cd','郵上祈雨','呂本中','宋','宋诗','song-poetry','','[]','泥龍蜴蜥困追求，旱徧淮南二十州。',32,'全唐诗/poet.song.92000.json','["泥龍蜴蜥困追求，旱徧淮南二十州。", "寄語天公莫輕許，少留眀月作中秋。"]'),
('ce2aec7b-8489-47da-a1e1-bb3092999fa9','清風','呂本中','宋','宋诗','song-poetry','','[]','清風如君子，所至有餘情。',72,'全唐诗/poet.song.92000.json','["清風如君子，所至有餘情。", "忻然破煩溽，有醉時一醒。", "嗟我二三友，飄散秋葉零。", "不知城南王，何以識我名。", "欹斜左手字，勞苦如平生。", "會寫登樓賦，一吊漳濵靈。"]'),
('1e461633-be66-4c13-8b07-d880e48ccc11','學視','呂本中','宋','宋诗','song-poetry','','[]','學視覩懸虱，病耳聞鬬蟻。',72,'全唐诗/poet.song.92000.json','["學視覩懸虱，病耳聞鬬蟻。", "紛然酬六鑿，萬劫費揩洗。", "君看杯中蛇，妄想從何起。", "忽然一妙語，初無强料理。", "回觀積年疾，乃是一念使。", "誰能明此心，香山老居士。"]'),
('62127762-fc30-4771-8dfa-a6049330d896','寄舍弟','呂本中','宋','宋诗','song-poetry','','[]','殘暑墜空屋，舊書穿破帷。',48,'全唐诗/poet.song.92000.json','["殘暑墜空屋，舊書穿破帷。", "才蒙小雨潤，遽得好風吹。", "逸少每作惡，淵明常病羸。", "他鄉憶吾弟，苦語自成詩。"]'),
('bf35151e-53fb-4597-9acd-c57c46c407c6','斷雲','呂本中','宋','宋诗','song-poetry','','[]','斷雲西南來，好風東北去。',96,'全唐诗/poet.song.92000.json','["斷雲西南來，好風東北去。", "翩然兩無心，空中忽相遇。", "化爲一尺雪，照我亭前路。", "昔者甚可憐，今來渺無處。", "故人多勌色，留我不少住。", "覊愁動中腸，疾病增百慮。", "虚庭著明月，皎皎如積素。", "不見乘鸞子，空懷舊烟霧。"]'),
('652c51e7-02b5-4857-8b7a-71100c7f43fe','如臯道中','呂本中','宋','宋诗','song-poetry','','[]','客路三日雨，頗知袍袴單。',48,'全唐诗/poet.song.92000.json','["客路三日雨，頗知袍袴單。", "長河貫沃野，薄酒動新寒。", "晚日魚鰕市，秋風藜藿盤。", "衰顔定可笑，不必鏡中看。"]'),
('e4d42c79-dd63-4487-95ee-eaf4d4d07124','初去白沙再望路中江南諸山慨然有懷','呂本中','宋','宋诗','song-poetry','','[]','青山如美人，濃淡各有態。',120,'全唐诗/poet.song.92000.json','["青山如美人，濃淡各有態。", "挽之不肯來，乃似孤竹隘。", "念無千里風，限此一衣带。", "夏木與藩屏，不畏炎日曬。", "三年白沙游，藉爾寛眼界。", "脱身塵垢中，一笑終不壞。", "别君更舉酒，未了清净債。", "雖無絲竹娱，會有詩律快。", "何如少陵翁，亦爲杜鵑拜。", "吾詩有餘歡，此語君勿怪。"]'),
('ba6014b8-e508-472f-8595-d2466cd3e865','赴濟陰留别一公','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','近别君莫嗟，遠别君莫惜。',240,'全唐诗/poet.song.92000.json','["近别君莫嗟，遠别君莫惜。", "往来天壤間，誰爲不相識。", "十年幾相别，日月虛棄擲。", "見君長江口，已作胡眼碧。", "别君廣陵城，妙語摧霹靂。", "今别知幾時，復念駒過隙。", "坐成千里阻，當有片言益。", "不勸君愛身，不勸君强食。", "勸君以勇决，萬事要努力。", "愚夫之所欣，智士之所戚。", "譬如醉而顛，亦有傍震虩。", "聲色糾纒人，萬劫困封植。", "本自驕惰生，亦以因循得。", "實惟招侮慢，豈止礙空寂。", "居然耳目內，反務化勍敵。", "誰能深山中，弄此無孔笛。", "芳草變蕭艾，每爲長太息。", "如公定不然，此語當謾憶。", "何妨膏腴地，更論去荆棘。", "君看一壺用，亦有千金直。"]'),
('bb931164-49dc-49d6-a17c-88e580467b07','五月五日泊舟北神與關聖功唐充之李元輔作别意殊惘然端午日行次洪澤把酒北望已如異世事矣因念屈大夫之死正是此日慨然有感於心輒成長韻奉寄李民師翁士時來可求和也','呂本中','宋','宋诗','song-poetry','','[]','麥上蝴蝶飛，水邉鸂鶒卧。',120,'全唐诗/poet.song.92000.json','["麥上蝴蝶飛，水邉鸂鶒卧。", "却望山陽城，已若一夢過。", "今晨又端午，把酒意亦惰。", "風回浪蹙船，閘淺沙著柂。", "故人阻情話，客子且清坐。", "更念屈大夫，是日遇奇禍。", "空餘後世名，第子只增些。", "寶璐與明月，皎皎不受涴。", "固知汨羅沈，可到首陽餓。", "還書二三老，此語君可和。"]'),
('491bf0ad-1d43-4b90-b9a6-ff41abe7bfa0','贈唐充之兼簡益中','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','三年白沙看江山，可當中原故人面。',224,'全唐诗/poet.song.92000.json','["三年白沙看江山，可當中原故人面。", "今来千里逢故人，笑談却作江山見。", "江山故人不相遠，平生志願于君滿。", "唐侯獨立一代無，張侯與之來集枯。", "老松本自歲寒外，良馬不畏長途驅。", "饑年百室仰粟廪，暑路六月懸冰壺。", "念昔關汪不相貸，視世好爵如機械。", "上書索去不作難，云我未了平生債。", "後生少年延頸觀，諸公故人思一快。", "基本未定天奪之，賴有君侯數人在。", "龍媒已遠風馭回，坐歎四海梁木摧。", "爾來老謝又繼往，但覺眼界常塵埃。", "長江無津出光怪，迥野入夜開風雷。", "此語不誣君可驗，請君更討防身劍。"]'),
('4d3c5169-9d9e-4760-b6a7-fe79332589ef','夜雨','呂本中','宋','宋诗','song-poetry','','[]','夢短添惆悵，更深轉寂寥。',24,'全唐诗/poet.song.92000.json','["夢短添惆悵，更深轉寂寥。", "如何今夜雨，只是滴芭蕉。"]'),
('2879424b-2f2c-4ce0-9e87-fc4842934baf','出門見明月','呂本中','宋','宋诗','song-poetry','','[]','出門見明月，入門思故人。',96,'全唐诗/poet.song.92000.json','["出門見明月，入門思故人。", "故人如此月，一見一回新。", "明月相見多，故人相見少。", "問爾何因緣，長似此月好。", "故人在何處，南北東西路。", "明月在咫尺，夜夜庭前樹。", "明月莫虧缺，故人莫離别。", "願月如故人，故人亦如月。"]'),
('e179ac18-d7f8-4639-b89a-6bf0e59a3e67','往歲在白沙見江上往来祀神者殺猪羊鵝鴨日夕相屬也有感於心後至濟陰因成長韻當托白沙故人投之廟前庶幾神少知自戒乎','呂本中','宋','宋诗','song-poetry','','[]','今日殺一羊，明日殺一豬。',144,'全唐诗/poet.song.92000.json','["今日殺一羊，明日殺一豬。", "問神何所樂，而必爲此歟。", "羊死噤無聲，豬死足號呼。", "傷哉鴨與鵝，閉目頸已朱。", "問神此何負，神亦何所取。", "吾知斯民愚，非是神所許。", "江船一帆風，江田一犁雨。", "民或謝神勞，尚使相告語。", "但采澗溪毛，足以薦筐筥。", "何須汚刀几，而後羞鼎爼。", "于物固無怨，于神亦無苦。", "更令嗚嗚歌，時送坎坎鼓。"]'),
('f79bd82c-c3f3-4a81-9b11-58cc7c362d82','濟陰野次','呂本中','宋','宋诗','song-poetry','','[]','去年騎馬古城西，雨涴鞍韉一尺泥。',32,'全唐诗/poet.song.92000.json','["去年騎馬古城西，雨涴鞍韉一尺泥。", "今日重来轉無緒，强扶衰疾遶河隄。"]'),
('00548f53-c522-4138-bb3e-498e91a59e6b','毛彦謨容膝軒','呂本中','宋','宋诗','song-poetry','','[]','黄金爲樓玉爲梯，畫旗素錦生光輝。',176,'全唐诗/poet.song.92000.json','["黄金爲樓玉爲梯，畫旗素錦生光輝。", "不如一庵醉而歸，倒卧側立無東西。", "君才于用無不宜，會稽竹箭梁山犀。", "賈而不售君不疑，亦不自以爲珍奇。", "淵明妙處君得之，萬古一首歸来辭。", "一庵容膝君所知，不用芥子藏須彌。", "望風懷想三歸依，眼前有睫見者誰。", "世人紛紛不自治，何異羊質蒙臯比。", "見豺而戰忘其皮，牆頭燕雀莫漫肥。", "汝不仰看鴻鵠飛，伯夷去採西山薇。", "想渠瘦亦不勝衣，不羡汝曹腰十圍。"]'),
('8e922184-8efb-4fe5-b19d-801df9f76ccd','濟陰寄故人','呂本中','宋','宋诗','song-poetry','','[]','柳絮飛時與君别，南樓把酒看新月。',96,'全唐诗/poet.song.92000.json','["柳絮飛時與君别，南樓把酒看新月。", "月似當年離别時，柳絮隨君何處飛。", "千書百書要相就，思君不見令人瘦。", "念君情意只如新，顧我形骸已非舊。", "朝来有信渡黄河，雁足繋書多網羅。", "城南城北芳草多，明月如此奈愁何。"]'),
('36e3be7d-fee0-4854-afe9-8ab5d1a61900','晁叔用得古鏡二一以遺法一上人澄澈可愛底水隱然蜃樓突起又作杯渡禪師像翩然衣動正在中流間也一求記于予因爲作歌','呂本中','宋','宋诗','song-poetry','','[]','晁郎高居卧冰雪，得此懸空兩秋月。',160,'全唐诗/poet.song.92000.json','["晁郎高居卧冰雪，得此懸空兩秋月。", "已將屋角倒魑魅，更與人間洗炎熱。", "一月團團如扇面，一月菱花光掣電。", "憐君囊中一物無，意欲分君托方便。", "菱花入袖世莫識，空堂夜留疏雨滴。", "天生寶氣有期會，復恐藏去終無益。", "君行萬里尋劍術，山精喚君君莫出。", "寒泉百尺傍枮樹，狡兔九月投霜鶻。", "未須潘謂苦哦詩，或自蘇公識神物。", "下有禪和不笑人，須君一照蛟龍窟。"]'),
('e3496265-96d5-4870-860c-d01c3908372c','别離行','呂本中','宋','宋诗','song-poetry','','[]','城頭草木日夜黄，九月北風天雨霜。',96,'全唐诗/poet.song.92000.json','["城頭草木日夜黄，九月北風天雨霜。", "月色入户侵我牀，美人乃在天一方。", "舊游可樂不可忘，恨君不隨雁南翔。", "恨妾愧守此空房，曉風忽来吹夢長。", "夢中與君還故鄉，黄金爲屋玉爲堂。", "與君更笑億千塲，不須合佩雙鴛鴦。"]'),
('6904b30c-bdfe-47f7-a3ed-2518dfa19b42','李念七久不見過二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','不隨殘暑退青蠅，入眼囂塵漸可憎。',32,'全唐诗/poet.song.92000.json','["不隨殘暑退青蠅，入眼囂塵漸可憎。", "静裏工夫君莫厭，夜窗重對短檠燈。"]'),
('45ac30d3-07a8-421f-bde1-16abc32c0b1e','李念七久不見過二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','羅襦襟解燭滅後，喝雉喝盧人散時。',32,'全唐诗/poet.song.92000.json','["羅襦襟解燭滅後，喝雉喝盧人散時。", "願君莫忘點軒老，少小先蒙國士知。"]'),
('309c79b9-6f69-41f7-8e6a-14bee790ff70','往年與關止叔相别甬上止叔見勉學道甚勤且曰無爲專事文字間也及今五年矣尚未有所就因作詩見志且以自警也','呂本中','宋','宋诗','song-poetry','','[]','老關别我時，笑我勤苦甚。',144,'全唐诗/poet.song.92000.json','["老關别我時，笑我勤苦甚。", "曰吾與子然，同此一味静。", "收功粥魚底，筆墨有譏評。", "五年念此語，但見日月競。", "雖無蛾眉斧，亦有晏安鴆。", "斯人今何往，想作大樹蔭。", "我走足欲蠒，始學兩鳥噤。", "君看齊聲謳，何異衆哭臨。", "繁紅成春條，本自其天性。", "風雨頌繋之，不有十日盛。", "人生亦作聊，共未免此病。", "乃知钁頭通，已勝狗脚朕。"]'),
('bb0912c0-0fc8-4a09-bc92-d03ec8a58f43','六月初三日雨後步至城東','呂本中','宋','宋诗','song-poetry','','[]','涼秋生郊原，快雨灑庚伏。',120,'全唐诗/poet.song.92000.json','["涼秋生郊原，快雨灑庚伏。", "曲肱訪幽睡，朝夢不可續。", "開門招此山，爽氣滿岩谷。", "村蹊沒衰草，古院蟠翠木。", "東行得幽亭，小徑來已熟。", "下有十里濠，暑退萬荷綠。", "恨無沽酒錢，一醉起枵腹。", "人生要快意，豈止寄幽獨。", "若看後池蛙，聲韻故不俗。", "怡然供清歡，何必絲與竹。"]'),
('f6c150f1-bba0-4b70-9b3e-dbe44b334fc7','得揚州書','呂本中','宋','宋诗','song-poetry','','[]','書来每恨日月晚，書去還憂道里長。',64,'全唐诗/poet.song.92000.json','["書来每恨日月晚，書去還憂道里長。", "但得老親常健好，不辭新歲且窮忙。", "文章已受塵埃涴，禪觀多爲疾病妨。", "趁得殘春北歸否，近箕臨潁是吾鄉。"]'),
('f3eb5387-3cbf-461a-90fc-bc23893428c2','歸計未成作詩寄懷','呂本中','宋','宋诗','song-poetry','','[]','萬里田園半有無，十年歸夢阻江湖。',64,'全唐诗/poet.song.92000.json','["萬里田園半有無，十年歸夢阻江湖。", "文章謬忝聲名在，氣體猶須藥餌扶。", "客路因風起舟楫，水田無雨卧菰蒲。", "青帘白酒斜陽外，不與行人滿眼酤。"]'),
('bf4d86c0-1672-435e-9d85-1f3741ce0233','閲舊詩卷有懷','呂本中','宋','宋诗','song-poetry','','[]','好詩無過亦無功，準擬還家贈阿宗。',64,'全唐诗/poet.song.92000.json','["好詩無過亦無功，準擬還家贈阿宗。", "會有江山與湔祓，且無塵土共從容。", "大汪矯矯雲間鶴，老謝森森澗底松。", "回首百年俱一夢，暮年文采更誰從。"]'),
('7f0039a7-0ccd-4543-b8c1-6b921559f357','高郵道中荷花極目平生所未見','呂本中','宋','宋诗','song-poetry','','[]','綠净紅深水不流，炎天烈日自然秋。',64,'全唐诗/poet.song.92000.json','["綠净紅深水不流，炎天烈日自然秋。", "只供野父已無計，便與行人亦暗投。", "明月不来江北岸，好山應在石城頭。", "何年得映潘妃步，更放君王作意游。"]'),
('b63a4f15-45c5-4a32-87b0-4be8fe5cc2af','高郵遇大熱作','呂本中','宋','宋诗','song-poetry','','[]','南風極炎暑，赤日不可傍。',168,'全唐诗/poet.song.92000.json','["南風極炎暑，赤日不可傍。", "扁舟在地底，淺水安得强。", "坐懷長河冰，未盡暍飲狀。", "甚憎食案蠅，意欲不相讓。", "旱苗乾欲死，蒲藕秋可望。", "平生投筆手，中有無盡藏。", "爾來夜深藏，穏着犢鼻上。", "有如三年艾，更復加百壯。", "黑雲翻日脚，好雨終不放。", "雷聲無事來，殷殷車百兩。", "東街暴泥龍，西街設銅像。", "利害有不同，未易相得喪。", "農夫責催租，日夕困大杖。", "那知清歌前，把酒有餘量。"]'),
('c908da52-4b24-4bd1-8dc9-99eb1a8f8059','題孫廣伯主簿家壁','呂本中','宋','宋诗','song-poetry','','[]','古木輪囷老歲寒，好花無力便凋殘。',32,'全唐诗/poet.song.92000.json','["古木輪囷老歲寒，好花無力便凋殘。", "秋風只在盆池上，但見江湖萬里看。"]'),
('1262f7b7-7d04-4dda-a00a-b7df5502b818','贈孫廣伯','呂本中','宋','宋诗','song-poetry','','[]','人皆笑君拙，我獨喜君直。',192,'全唐诗/poet.song.92000.json','["人皆笑君拙，我獨喜君直。", "拙則世所無，直則未易識。", "昔者中丞公，事主以一德。", "從容進退間，多士所取則。", "朝廷九鼎重，冠冕萬夫特。", "塵埃困大路，此老難再得。", "至今門下士，必以身許國。", "孰知强弩末，而有百鈞力。", "賢孫後來秀，見我好顔色。", "收功却掃中，欲任門內責。", "空弮入善陣，匹馬見勍敵。", "不嫌不識察，但恨無此獲。", "欲赤莫如丹，欲黑莫如墨。", "吾常持此言，以辨主與賊。", "苟無牛羊害，則有天地塞。", "君能但拙直，亦莫忘黑白。"]'),
('bd18a4f1-ead6-4714-957a-5766306039f6','與吳迪吉諸人赴晁季一陳塘范園之游因成十韻','呂本中','宋','宋诗','song-poetry','','[]','春風未寂寞，頻枉故人車。',120,'全唐诗/poet.song.92000.json','["春風未寂寞，頻枉故人車。", "客舎輕寒下，村煙宿雨餘。", "曉紅留隱映，新綠上扶疏。", "妙墨懸高榜，殘章得舊書。", "蛟龍忽舒卷，草木自清虛。", "渺渺登臨地，悠悠水竹居。", "只今那復有，本自不關渠。", "塘水空遺廟，鼉淙亦故墟。", "同行喜佳士，所到即吾廬。", "政恐習池飲，風流却未如。"]'),
('f48f02d1-c2f1-4956-9722-71b33e448867','送晁季一罷官西歸','呂本中','宋','宋诗','song-poetry','','[]','少年閱人若郵傳，漢廷公卿日千變。',208,'全唐诗/poet.song.92000.json','["少年閱人若郵傳，漢廷公卿日千變。", "故人一蹙便青雲，咫尺相逢不相見。", "丈夫鬚髯但如戟，黄塵沒馬渠未識。", "晁侯文采老不聞，兩耳壁塞目爲昏。", "三年刺促簿書裏，更覺和氣生春温。", "誰能種蘭生九畹，從公不辭墮車蹇。", "冰霜入眼蚊蚋去，桃李成蹊草茅遠。", "胸中滄海無水旱，眼底浮雲看舒卷。", "頃來江上幾送迎，聚蚊成雷公不驚。", "笙竽沸地不知曉，公但寒窗延短檠。", "乃知風雨晝窈冥，我亦不廢晨鷄鳴。", "箕山之下潁水邊，脱冠便歸須壯年。", "諸公先尋買山錢，我亦從今當着鞭。"]'),
('09ad13ac-ab0c-4852-ad5f-7fd907687c30','侯嬴','呂本中','宋','宋诗','song-poetry','','[]','游士縱横飜覆手，山東諸侯望關走。',96,'全唐诗/poet.song.92000.json','["游士縱横飜覆手，山東諸侯望關走。", "歷下邯鄲無使來，長城易水非燕有。", "大梁賓客舊如雲，夷門監者未有聞。", "謾將苦語送公子，市井屠兒虛見存。", "後来毫髮争得喪，紛紛小兒誇跌宕。", "不知世有公子牟，一生放迹江海上。"]'),
('37f1f79c-7f13-46e6-8a74-a1400ae9c726','昭君','呂本中','宋','宋诗','song-poetry','','[]','凍雲霾空風折木，烏孫公主歌黄鵠。',82,'全唐诗/poet.song.92000.json','["凍雲霾空風折木，烏孫公主歌黄鵠。", "昭君請自嫁單于，當時各倚顔如玉。", "露髩雲鬟胡地塵，帳中誰是可憐人。", "左抱琵琶右揮手，胡地漢宫能幾春。", "嗚呼古來出婦嫁鄉曲，何曾肯望秦雲哭。"]'),
('97a654d5-9d60-4cbb-b4fa-75ac39aea6e6','戲呈外弟趙才仲','呂本中','宋','宋诗','song-poetry','','[]','趙郎風味春月柳，可到阮公青眼邊。',64,'全唐诗/poet.song.92000.json','["趙郎風味春月柳，可到阮公青眼邊。", "秋水黏天劇空闊，曉霜扶月作嬋娟。", "北来好句傳新雁，一夜客愁如少年。", "安得瓊枝更當眼，沙頭同理釣魚船。"]'),
('eaf8e7b5-ca34-4095-ac3d-1c6dba7b14b4','城北别江子之','呂本中','宋','宋诗','song-poetry','','[]','但覺與君别，孰知歸興長。',48,'全唐诗/poet.song.92000.json','["但覺與君别，孰知歸興長。", "亂畦分宿雨，老木掛晨霜。", "未計緣詩瘦，只知如許忙。", "他年風雨夜，重約細商量。"]'),
('091c3de8-b272-4f8d-af66-bf37570f491a','訪晁季一','呂本中','宋','宋诗','song-poetry','','[]','近人鳥雀昆弟語，堆案簿書鳬鶩行。',64,'全唐诗/poet.song.92000.json','["近人鳥雀昆弟語，堆案簿書鳬鶩行。", "是中亦自有佳趣，公但徐之渠自忙。", "西風忽来涼月曉，楓葉蘆花秋意少。", "勸君多飲莫多談，截斷中流公更参。"]'),
('9e0801c4-f9d2-4689-89f3-a66d9a33858c','吳君求詩因作四韻寄之并簡小吳與甯生','呂本中','宋','宋诗','song-poetry','','[]','文字縛人同束濕，吳君不言如坐忘。',64,'全唐诗/poet.song.92000.json','["文字縛人同束濕，吳君不言如坐忘。", "知公胸中有餘地，萬頃亦在一葦航。", "寒梢倒掛夜来雨，細草已披秋後霜。", "寄語兩吳兼小甯，莫因詩律廢相望。"]'),
('4ff399e0-4ec0-417d-ac4e-a34352bf72aa','古劍歌','呂本中','宋','宋诗','song-poetry','','[]','寒江九月雷殷空，落日倒射千山紅。',163,'全唐诗/poet.song.92000.json','["寒江九月雷殷空，落日倒射千山紅。", "江頭樹木半傾倒，袞袞不盡洪濤風。", "風中有物如長戟，電光忽来傾霹靂。", "雨罷晴開不復知，乃是潛蛟倚長石。", "蒼皮半卷頗飛動，澁蘚中開欲跳擲。", "青熒野火下絕水，夭矯長烟轉空壁。", "天生神物有時出，歲月飄流爲誰得。", "銅花欲盡秋水渾，尚有千年妖血痕。", "向来天地亦兒戲，俄頃變怪徒紛紜。", "君不見豐城之來亦不久，寶氣何爲上牛斗。"]'),
('39b461a3-ed66-459a-9446-6e4d57aef62f','初夏即事','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','歌呼連牆亦任渠，移門賓從又何如。',64,'全唐诗/poet.song.92000.json','["歌呼連牆亦任渠，移門賓從又何如。", "晴階仰日卧紅藥，野水趁船跳白魚。", "多病且参篐桶話，得閑時近養生書。", "平生不盡幽居興，付與長江拯釣車。"]'),
('410c1903-8ea0-42b8-9ea4-a9e395d8ab67','偶作','呂本中','宋','宋诗','song-poetry','','[]','鄙夫養病苦不足，諸公覓官常有餘。',32,'全唐诗/poet.song.92000.json','["鄙夫養病苦不足，諸公覓官常有餘。", "自是閑人不更事，可隨雲鳥更深居。"]'),
('9e034417-f7c9-4462-aea8-426ac992b75c','癸已自南京過泗上','呂本中','宋','宋诗','song-poetry','','[]','昔我往矣天欲霜，今我来思梅已黄。',64,'全唐诗/poet.song.92000.json','["昔我往矣天欲霜，今我来思梅已黄。", "淮山澡雪塵垢面，魚稻掃除藜藿腸。", "好風肯伴客帆遠，故國不辭歸夢長。", "塔中老人莫相笑，我自寂然渠自忙。"]'),
('382ba0a6-f3c2-42db-aa9d-6602276be0c5','泗上贈楊吉老二首  其一','呂本中','宋','宋诗','song-poetry','','[]','杯中蛇去無恙，醉裏詩成有神。',28,'全唐诗/poet.song.92000.json','["杯中蛇去無恙，醉裏詩成有神。", "相逢不及世故，長年倍覺情親。"]'),
('a8afd59f-cfab-42eb-81e1-dfe3e4015ffd','泗上贈楊吉老二首  其二','呂本中','宋','宋诗','song-poetry','','[]','置王坦之膝上，着陳長文車中。',28,'全唐诗/poet.song.92000.json','["置王坦之膝上，着陳長文車中。", "何似維摩丈室，蕭然一榻清風。"]'),
('ca50e559-4b15-4dd1-bafb-2162f937ed5e','題寶應張氏草堂','呂本中','宋','宋诗','song-poetry','','[]','好風殘暑不同塗，穏看饑蚊自掃除。',32,'全唐诗/poet.song.92000.json','["好風殘暑不同塗，穏看饑蚊自掃除。", "不謂南軒有佳竹，捲簾相對一牀書。"]'),
('e9e522a2-6cd8-4fac-8bd5-016598edc62a','學仙行','呂本中','宋','宋诗','song-poetry','','[]','長松拂雲根合抱，雪虐霜凌不相到。',125,'全唐诗/poet.song.92000.json','["長松拂雲根合抱，雪虐霜凌不相到。", "下有千歲老茯苓，化爲琥珀光自照。", "食之便可登廣寒，不但無病長少年。", "浮生溷濁那可言，和氣乃爲塵務煎。", "坐看靈藥置泥土，五味雜置成薰羶。", "豈不聞齊天子，黄金丹成不肯仙。", "且貪人間樂，不能從汝飛上天。", "惜哉韋郎之妙語，一失毫釐千萬年。"]'),
('b7c9082c-2a5a-4509-8d6a-2a0a7823693f','冬日訪朱深明博士二首  其一','呂本中','宋','宋诗','song-poetry','','[]','北風迎馬入裘茸，來訪殘爐半日紅。',32,'全唐诗/poet.song.92000.json','["北風迎馬入裘茸，來訪殘爐半日紅。", "敗屋數間書百篋，無人知是陸龜蒙。"]'),
('2b91deb4-d745-4d1b-bea0-7eb8febd939e','冬日訪朱深明博士二首  其二','呂本中','宋','宋诗','song-poetry','','[]','見公便是倚松老，念我不忘擔板心。',32,'全唐诗/poet.song.92000.json','["見公便是倚松老，念我不忘擔板心。", "萬里江山一尊酒，主人無古亦無今。"]'),
('3ae3f355-a811-4912-88ef-1206fa1e0b3e','初别清源姑才仲弟過楚丘作','呂本中','宋','宋诗','song-poetry','','[]','前村後村鳩亂鳴，梨花點雪柳半青。',64,'全唐诗/poet.song.92000.json','["前村後村鳩亂鳴，梨花點雪柳半青。", "斷雲忽過楚丘縣，驟雨已見龍丘亭。", "故人愁緒各南北，宿酒别時同醉醒。", "語離情緒乃如此，故園可歸公不聽。"]'),
('9980994e-5377-4af0-9730-cefd6b6229fe','宿楚丘懷石子植顔平仲趙才仲','呂本中','宋','宋诗','song-poetry','','[]','暮行楚丘北，適與寒雨值。',108,'全唐诗/poet.song.92000.json','["暮行楚丘北，適與寒雨值。", "旅舍一尺泥，又乏芻秣費。", "故人渺天涯，客子初夜至。", "披衣附殘火，煮茗當晚饋。", "昏昏傍晚枕，悄悄入清睡。", "向來談笑聲，已若異世事。", "但覺舌本間，尚有宿酒味。", "鴻鵠乘秋風，意在網羅外。", "强飯無多談，此語敢失墜。"]'),
('b0702190-88d0-4fec-92f6-a0891496f857','發召伯埭二首  其一','呂本中','宋','宋诗','song-poetry','','[]','柳外鵓鳩相應鳴，屋頭新月半輪生。',32,'全唐诗/poet.song.92000.json','["柳外鵓鳩相應鳴，屋頭新月半輪生。", "知公未便爲官去，且放扁舟自在行。"]'),
('ab4a827f-caaa-4bc0-8e5b-6ffed3f30a2f','發召伯埭二首  其二','呂本中','宋','宋诗','song-poetry','','[]','曉日烘窗不得眠，夾河高柳亂鳴蟬。',32,'全唐诗/poet.song.92000.json','["曉日烘窗不得眠，夾河高柳亂鳴蟬。", "西風種種入愁思，更有長亭十里船。"]'),
('b01f11d9-f255-420e-9659-06ebe1847f26','余病不能蔬食懼有五味口爽之責作詩自戒','呂本中','宋','宋诗','song-poetry','','[]','君不如屈大夫，夕餐但秋菊。',194,'全唐诗/poet.song.92000.json','["君不如屈大夫，夕餐但秋菊。", "又不如顔平原，未晝且食粥。", "雖知舌本欠滋味，頗覺和氣實其腹。", "癡人要盈餘，椒有八百斛。", "錢有一百屋，鼎俎涴腥膻。", "杯盤眩紅綠，四方採珍異。", "亦未極所欲，寧知下箸處，但有一飽足。", "坐償姓命債，百死有未贖。", "何如野僧飯，晚菜下脱粟。", "撞鐘撃鼓坐高堂，童奴唱飯來相續。", "竹間新筍大如椽，樹頭老耳肥於肉。", "亦不見蟹躁擾，亦不見牛觳觫。", "石郎愛惜韭萍虀，晉侯睥睨熊蹯熟。", "以此相重輕，於君未爲福。"]'),
('62e0b2b0-8d1c-4c0c-a04c-de98ee08746a','南山','呂本中','宋','宋诗','song-poetry','','[]','南山佳有餘，我病不自得。',180,'全唐诗/poet.song.92000.json','["南山佳有餘，我病不自得。", "今日飲君家，把酒到曛黒。", "秋風浩萬頃，涼月挂江色。", "對此不能歡，何以消偪塞。", "人生少如意，百語輸一黙。", "喜逢佳主人，略爲解覊勒。", "歡然有餘味，即此自温克。", "陽春內空洞，隱如一敵國。", "世賢首陽餓，我愛鄭朝穆。", "却懷三年艾，未盡一醉力。", "青蠅鬨殘暑，小雨頻敗北。", "漸須把蟹螯，莫訃舟摧抑。", "君看女兒笑，終勝官事逼。", "殘盃蓋餘瀝，慎勿貸鷄肋。", "要看知我真，不獨觀酒德。"]'),
('3396512c-ca60-481a-9d47-b5272f441782','與諸弟諸李同登塔山愚壁以事不能来因成二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','李家漾南江漫流，幕阜山前春更愁。',32,'全唐诗/poet.song.92000.json','["李家漾南江漫流，幕阜山前春更愁。", "無人肯會西來意，且作小詩盟白鷗。"]'),
('ab7a2e75-941b-4082-a1a0-42b69bd56aad','與諸弟諸李同登塔山愚壁以事不能来因成二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','道人不來花滿山，蹇驢出沒松聲間。',32,'全唐诗/poet.song.92000.json','["道人不來花滿山，蹇驢出沒松聲間。", "待約江頭今夜月，與渠他日報平安。"]'),
('8d8da999-1a73-4af5-915a-a3eef7141beb','春日二首  其一','呂本中','宋','宋诗','song-poetry','','[]','春日紛紛一段奇，無言桃李任春欺。',32,'全唐诗/poet.song.92000.json','["春日紛紛一段奇，無言桃李任春欺。", "要須及熱蘆灣去，莫看風吹雨打時。"]'),
('7b06dd2f-83fb-4e59-8cc4-6c0e8f3a38b9','春日二首  其二','呂本中','宋','宋诗','song-poetry','','[]','誰將舊日狂蜂蝶，誤入春風桃李蹊。',32,'全唐诗/poet.song.92000.json','["誰將舊日狂蜂蝶，誤入春風桃李蹊。", "咫尺風光不相貸，無因乞與上天梯。"]'),
('0c459835-df22-4b34-8ea8-6e686365b974','東園','呂本中','宋','宋诗','song-poetry','','[]','暫開還落不停枝，雨濕東園柳絮稀。',32,'全唐诗/poet.song.92000.json','["暫開還落不停枝，雨濕東園柳絮稀。", "遥想釣船今夜月，暗隨潮信與春歸。"]'),
('f93b7988-6149-4497-880d-87c3988393ac','即事','呂本中','宋','宋诗','song-poetry','','[]','經旬無客事亦少，多病閉門身更輕。',32,'全唐诗/poet.song.92000.json','["經旬無客事亦少，多病閉門身更輕。", "我自不能知許事，暮江斜雨送蛙聲。"]'),
('c8670357-78c6-48fe-8bfa-544ad2b37c02','和李二十七食蛙聽蛙二首  其一','呂本中','宋','宋诗','song-poetry','','[]','膏香未即輸鮭菜，煎和真同食蛤蜊。',32,'全唐诗/poet.song.92000.json','["膏香未即輸鮭菜，煎和真同食蛤蜊。", "北人驚嘆不下箸，乞與韓公南食詩。"]'),
('bc999a3c-6927-4643-a55f-5c6e5a9c5f07','和李二十七食蛙聽蛙二首  其二','呂本中','宋','宋诗','song-poetry','','[]','莫驚朋類多驚爆，曾伴中郎鼓吹來。',32,'全唐诗/poet.song.92000.json','["莫驚朋類多驚爆，曾伴中郎鼓吹來。", "今日屬官本渠分，晚江烟雨閙池臺。"]'),
('46d9c82f-af7c-4e29-9870-34ccf30e4a60','題秦惇秀才園亭','呂本中','宋','宋诗','song-poetry','','[]','秦郎重構水邊亭，仿佛疏林過雨聲。',32,'全唐诗/poet.song.92000.json','["秦郎重構水邊亭，仿佛疏林過雨聲。", "更喚清泉入屏坐，少留他日濯吾纓。"]'),
('fb35406f-9ec4-4d39-9df2-e422adda8fcd','别夜','呂本中','宋','宋诗','song-poetry','','[]','薄酒殘燈欲别情，暗螢依草不能明。',32,'全唐诗/poet.song.92000.json','["薄酒殘燈欲别情，暗螢依草不能明。", "懸知先入他年話，一夜蛙聲連雨聲。"]'),
('2ed16a98-b768-4f68-b0f4-f08991db1a9e','寄題蘇州靈巖','呂本中','宋','宋诗','song-poetry','','[]','水分西子採香徑，山是吴王避暑宫。',32,'全唐诗/poet.song.92000.json','["水分西子採香徑，山是吴王避暑宫。", "可惜同来不同賞，落花飛絮曉濛濛。"]'),
('f9c45a74-f7ce-4add-a66b-b9eeff56c15a','呈甘露印老','呂本中','宋','宋诗','song-poetry','','[]','水滿南河月滿牀，市樓燈火隔秋江。',32,'全唐诗/poet.song.92000.json','["水滿南河月滿牀，市樓燈火隔秋江。", "無人可會庵前事，一夜北風吹破窗。"]'),
('f9f3612f-3ec9-4ee7-9e99-cf163b23b5df','璧上人欲行爲雨止戲成一絕用前韻','呂本中','宋','宋诗','song-poetry','','[]','東風不借南舟便，細雨輕寒鎖暮江。',32,'全唐诗/poet.song.92000.json','["東風不借南舟便，細雨輕寒鎖暮江。", "更想亂山明日路，暮天風雨打船窗。"]'),
('72708720-394b-4fa7-a7e1-9bf4d202e9d9','江口送璧上人二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','小雨浮江霜送秋，曉山晴遶讀書樓。',32,'全唐诗/poet.song.92000.json','["小雨浮江霜送秋，曉山晴遶讀書樓。", "道人不作當時面，萬里一帆隨白鷗。"]'),
('d7743abb-921b-43e1-9799-b681b2f2bfb4','江口送璧上人二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','今日鉢囊南去人，當時雕句作新春。',32,'全唐诗/poet.song.92000.json','["今日鉢囊南去人，當時雕句作新春。", "更知自昔相逢意，定是他生骨肉親。"]'),
('db1b815f-b4ef-4935-811b-c4431a8e9d49','送朱時發','呂本中','宋','宋诗','song-poetry','','[]','眼底家鄉不自歸，癡人争忍劫前灰。',32,'全唐诗/poet.song.92000.json','["眼底家鄉不自歸，癡人争忍劫前灰。", "直饒古廟香爐去，也要披毛戴角来。"]'),
('246da3c6-e60c-4cea-a2ad-9e8d7784eec5','送甯子儀','呂本中','宋','宋诗','song-poetry','','[]','洪波奔放不停塵，萬劫茫茫寄此身。',32,'全唐诗/poet.song.92000.json','["洪波奔放不停塵，萬劫茫茫寄此身。", "畢竟無人會休去，滿堂栝木不能春。"]'),
('4caaac6d-56b3-4f32-a082-d37e4f1219fc','唐張琯書記梁時婦人黄鼎因侯景亂沒北齊爲小校胡兒所虜生二子後附海舶歸聞鼓角得岸乃知是會稽郡鼎先在梁許嫁張固及歸固適爲剡令求與相見不可乃遣令送之宣城鼎在齊時作秋風曲渡海時又作詩三章琯書稱其詞凄怨自琯時已不傳','呂本中','宋','宋诗','song-poetry','','[]','萬里秋風曲，三章渡海詩。',48,'全唐诗/poet.song.92000.json','["萬里秋風曲，三章渡海詩。", "絕勝漢公主，略似蔡文姬。", "故國山河在，荒城鼓角悲。", "何如覓張固，不用憶胡兒。"]'),
('b9388adf-c9ab-4243-8e72-875a88a76ea7','夜坐呈吳迪吉','呂本中','宋','宋诗','song-poetry','','[]','伏暑不能旱，楚天頻復陰。',48,'全唐诗/poet.song.92000.json','["伏暑不能旱，楚天頻復陰。", "疾雷衝雨斷，亂草接江深。", "舊圃可小摘，老盆餘數斟。", "明朝有傾倒，相待沃愁吟。"]'),
('e868c321-6fbb-4c72-b282-4e121c34b1ab','與李夫言諸人分題得之字','呂本中','宋','宋诗','song-poetry','','[]','人生行樂耳，此去復何之。',48,'全唐诗/poet.song.92000.json','["人生行樂耳，此去復何之。", "酒憶侯公聖，月如京兆眉。", "未須誇敏捷，或恐勝肥癡。", "不作別離見，却憂兒輩知。"]'),
('fbc18c15-1330-4a02-b020-9576df8df044','訪秦氏北莊','呂本中','宋','宋诗','song-poetry','','[]','午日城西路，籃輿疑舊尋。',48,'全唐诗/poet.song.92000.json','["午日城西路，籃輿疑舊尋。", "稻田疏野水，草徑接秋陰。", "飯憶分盤玉，書藏遺子金。", "不須千里目，枉費百年心。"]'),
('29c749b3-a128-4680-9650-111fb4692667','喜才仲兄弟至偶成四十字','呂本中','宋','宋诗','song-poetry','','[]','落日下喬木，好風来暮船。',48,'全唐诗/poet.song.92000.json','["落日下喬木，好風来暮船。", "徑思投轄飲，復作對牀眠。", "寂寂驅愁外，紛紛着酒邊。", "平生五經笥，不直一囊錢。"]'),
('370731d8-ef35-4bd4-a1ca-4c647c01a5f4','春日','呂本中','宋','宋诗','song-poetry','','[]','數畝幽畦滿小園，兒童無事亦嘲喧。',64,'全唐诗/poet.song.92000.json','["數畝幽畦滿小園，兒童無事亦嘲喧。", "水搖日影上簷角，風送花香来鼻根。", "病去只留花作伴，客来常欠酒應門。", "城南旱夌塵埃裏，不借春江一尺渾。"]');
